BROKEN_PIPE_EXIT_CODE = 141


def _json_dump(payload: dict[str, Any], exit_code: int = 0) -> NoReturn:
    try:
        print(
            json.dumps(
                payload, ensure_ascii=False, indent=2, sort_keys=True, default=str
            )
        )
    except BrokenPipeError:
        _exit_broken_pipe()
    raise SystemExit(exit_code)


def _exit_broken_pipe() -> NoReturn:
    try:
        stdout_fd = sys.stdout.fileno()
    except (AttributeError, OSError):
        raise SystemExit(BROKEN_PIPE_EXIT_CODE)

    try:
        devnull_fd = os.open(os.devnull, os.O_WRONLY)
    except OSError:
        raise SystemExit(BROKEN_PIPE_EXIT_CODE)

    try:
        os.dup2(devnull_fd, stdout_fd)
    except OSError:
        pass
    finally:
        os.close(devnull_fd)
    raise SystemExit(BROKEN_PIPE_EXIT_CODE)


def _success(command: str, **payload: Any) -> NoReturn:
    data = {"ok": True, "command": command}
    data.update(payload)
    _json_dump(data)


def _failure(
    command: str,
    error: str,
    message: str,
    *,
    exit_code: int = 1,
    **payload: Any,
) -> NoReturn:
    data = {
        "ok": False,
        "command": command,
        "error": _mask_sensitive_text(error),
        "message": _mask_sensitive_text(message),
    }
    data.update(
        {
            key: "***"
            if _is_sensitive_payload_key(key)
            else _sanitize_failure_value(value)
            for key, value in payload.items()
        }
    )
    _json_dump(data, exit_code=exit_code)


def _runtime_failure_fix(command: str, code: str) -> dict[str, Any]:
    commands = [AGENT_DOCTOR_COMMAND]
    guidance = [
        "Read the structured error fields before retrying.",
        "Do not paste secrets or full direct connect URLs into chat.",
    ]
    env = ["LEXMOUNT_API_KEY", "LEXMOUNT_PROJECT_ID"]

    if command.startswith("action."):
        commands = [
            "browser-cli action guide --task interactive_targeting",
            "browser-cli action page-info --session-id <session_id>",
            "browser-cli doctor --smoke-session",
            AGENT_DOCTOR_COMMAND,
        ]
        guidance = [
            "Confirm the browser target is exactly one of --session-id, --connect-url, or --direct-url.",
            "Inspect page-info and action guide before falling back to custom JavaScript.",
            "Run doctor --smoke-session if session creation or browser connectivity is uncertain.",
        ]
    elif command.startswith("session."):
        commands = [
            "browser-cli session list --status active",
            "browser-cli session get --session-id <session_id>",
            "browser-cli session close --session-id <session_id>",
            AGENT_DOCTOR_COMMAND,
        ]
        guidance = [
            "Inspect active sessions before creating replacements.",
            "Close stale sessions when limits or stale state may be involved.",
        ]
    elif command.startswith("context."):
        commands = [
            'browser-cli context list --metadata-json \'{"purpose":"codex-login"}\' --selection newest --include-reuse-state',
            'browser-cli context pick --metadata-json \'{"purpose":"codex-login"}\' --selection newest --dry-run',
            "browser-cli context status --context-id <context_id>",
            AGENT_DOCTOR_COMMAND,
        ]
        guidance = [
            "Use context pick --dry-run to inspect availability before mutating persistent login state.",
            "Treat availability=locked as busy and pick or create a different context.",
        ]

    return {
        "code": code,
        "commands": commands,
        "env": env,
        "guidance": guidance,
    }


def _missing_lexmount_env_from_error(message: Any) -> list[str]:
    text = str(message or "")
    missing = [
        name for name in ("LEXMOUNT_API_KEY", "LEXMOUNT_PROJECT_ID") if name in text
    ]
    if missing:
        return missing
    if "Missing required Lexmount environment variables" in text:
        return ["LEXMOUNT_API_KEY", "LEXMOUNT_PROJECT_ID"]
    return []


def _credential_failure_payload_fix(message: Any) -> dict[str, Any] | None:
    missing_env = _missing_lexmount_env_from_error(message)
    if not missing_env:
        return None
    return _credential_doctor_fix(*missing_env)


def _failure_payload_for_exception(command: str, exc: Exception) -> dict[str, Any]:
    info = getattr(exc, "lexmount_error_info", None)
    if isinstance(info, LexmountErrorInfo):
        payload = info.payload()
        fix = _credential_failure_payload_fix(payload.get("message")) or (
            _runtime_failure_fix(command, "inspect_lexmount_api_error")
        )
        payload["fix"] = fix
        payload.setdefault("next_steps", payload["fix"]["guidance"])
        return payload
    if isinstance(exc, BrowserParallelLimitError):
        fix = _runtime_failure_fix(command, "reduce_browser_parallel_sessions")
        return {
            "error": "browser_parallel_limit_reached",
            "message": str(exc),
            "fix": fix,
            "next_steps": fix["guidance"],
        }
    if isinstance(exc, BrowserConfigError):
        fix = _credential_failure_payload_fix(str(exc)) or _runtime_failure_fix(
            command, "repair_browser_cli_configuration"
        )
        return {
            "error": "configuration_error",
            "message": str(exc),
            "fix": fix,
            "next_steps": fix["guidance"],
        }
    if isinstance(exc, BrowserRuntimeError):
        fix = _runtime_failure_fix(command, "inspect_browser_runtime_failure")
        return {
            "error": exc.__class__.__name__,
            "message": str(exc),
            "fix": fix,
            "next_steps": fix["guidance"],
        }

    fix = _runtime_failure_fix(command, "inspect_unexpected_runtime_failure")
    return {
        "error": exc.__class__.__name__,
        "message": str(exc),
        "fix": fix,
        "next_steps": fix["guidance"],
    }


def _failure_from_exception(command: str, exc: Exception) -> NoReturn:
    _failure(command, **_failure_payload_for_exception(command, exc))


def _command_from_prog(prog: str) -> str:
    parts = prog.split()
    if parts and parts[0] == "browser-cli":
        parts = parts[1:]
    return ".".join(parts) if parts else "browser-cli"


class JsonArgumentParser(argparse.ArgumentParser):
    def add_subparsers(self, *args: Any, **kwargs: Any) -> Any:
        kwargs.setdefault("parser_class", type(self))
        return super().add_subparsers(*args, **kwargs)

    def error(self, message: str) -> NoReturn:
        _failure(
            _command_from_prog(self.prog),
            "argument_error",
            message,
            exit_code=2,
            usage=self.format_usage().strip(),
        )


def _parser_has_option(parser: argparse.ArgumentParser, option: str) -> bool:
    return any(option in action.option_strings for action in parser._actions)


def _add_json_compatibility_flag(parser: argparse.ArgumentParser) -> None:
    if not _parser_has_option(parser, "--json"):
        parser.add_argument(
            "--json",
            action="store_true",
            help=argparse.SUPPRESS,
        )
    for action in parser._actions:
        if isinstance(action, argparse._SubParsersAction):
            for subparser in action.choices.values():
                _add_json_compatibility_flag(subparser)


def _subparser_actions(
    parser: argparse.ArgumentParser,
) -> list[argparse._SubParsersAction[Any]]:
    return [
        action
        for action in parser._actions
        if isinstance(action, argparse._SubParsersAction)
    ]


def _preferred_option(action: argparse.Action) -> str | None:
    if not action.option_strings or action.help is argparse.SUPPRESS:
        return None
    for option in action.option_strings:
        if option.startswith("--"):
            return option
    return action.option_strings[0]


def _catalog_default(value: Any) -> Any:
    if value is argparse.SUPPRESS:
        return None
    if value is None or isinstance(value, str | int | float | bool):
        return value
    return str(value)


def _catalog_option(action: argparse.Action) -> dict[str, Any] | None:
    if not action.option_strings or action.help is argparse.SUPPRESS:
        return None
    if isinstance(action, argparse._HelpAction):
        return None

    takes_value = not isinstance(
        action,
        argparse._StoreTrueAction | argparse._StoreFalseAction,
    )
    option: dict[str, Any] = {
        "flags": list(action.option_strings),
        "dest": action.dest,
        "required": bool(getattr(action, "required", False)),
        "takes_value": takes_value,
    }
    if action.help:
        option["help"] = str(action.help)
    choices = getattr(action, "choices", None)
    if choices is not None:
        option["choices"] = [str(choice) for choice in choices]
    default = _catalog_default(getattr(action, "default", None))
    if default is not None:
        option["default"] = default
    nargs = getattr(action, "nargs", None)
    if nargs not in (None, 0):
        option["nargs"] = nargs
    if isinstance(action, argparse._AppendAction):
        option["repeatable"] = True
    return option


def _catalog_required_one_of(
    parser: argparse.ArgumentParser,
) -> list[list[str]]:
    groups: list[list[str]] = []
    for group in parser._mutually_exclusive_groups:
        if not group.required:
            continue
        options = [
            option
            for action in group._group_actions
            if (option := _preferred_option(action)) is not None
        ]
        if options:
            groups.append(options)
    return groups


def _catalog_leaf_commands(
    parser: argparse.ArgumentParser,
) -> list[dict[str, Any]]:
    subparser_actions = _subparser_actions(parser)
    if subparser_actions:
        commands: list[dict[str, Any]] = []
        for subparser_action in subparser_actions:
            for subparser in subparser_action.choices.values():
                commands.extend(_catalog_leaf_commands(subparser))
        return commands

    name = _command_from_prog(parser.prog)
    path = name.split(".")
    options = [
        option
        for action in parser._actions
        if (option := _catalog_option(action)) is not None
    ]
    required_options = [
        option
        for action in parser._actions
        if getattr(action, "required", False)
        and (option := _preferred_option(action)) is not None
    ]
    target_options = {
        "--session-id",
        "--connect-url",
        "--direct-url",
    }
    option_flags = {
        flag
        for option in options
        for flag in option.get("flags", [])
        if isinstance(flag, str)
    }
    command: dict[str, Any] = {
        "name": name,
        "path": path,
        "group": path[0],
        "usage": parser.format_usage().strip(),
        "options": options,
        "required_options": required_options,
        "required_one_of": _catalog_required_one_of(parser),
    }
    if target_options.intersection(option_flags):
        command["browser_target"] = {
            "required": True,
            "exactly_one_of": sorted(target_options.intersection(option_flags)),
        }
    if name in COMMAND_ALIASES:
        command["alias_of"] = COMMAND_ALIASES[name]
        command["canonical_name"] = COMMAND_ALIASES[name]
    aliases = sorted(
        alias for alias, canonical in COMMAND_ALIASES.items() if canonical == name
    )
    if aliases:
        command["aliases"] = aliases
    return [command]


