def _parse_metadata_json(raw: str | None) -> dict[str, Any] | None:
    if not raw:
        return None
    try:
        value = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise argparse.ArgumentTypeError(f"invalid metadata JSON: {exc}") from exc
    if not isinstance(value, dict):
        raise argparse.ArgumentTypeError("metadata JSON must decode to an object")
    return value


def _parse_filter_metadata_json(raw: str | None) -> dict[str, Any]:
    parsed = _parse_metadata_json(raw)
    return parsed or {}


def _normalize_context_mode(value: str) -> str:
    if value not in {"read_write", "read_only"}:
        raise argparse.ArgumentTypeError("context mode must be read_write or read_only")
    return value


def _normalize_browser_mode(value: str) -> str:
    if value == "chrome-light-docker":
        return "light"
    if value not in {"normal", "light"}:
        raise argparse.ArgumentTypeError("browser mode must be normal or light")
    return value


def _non_negative_int(value: str) -> int:
    try:
        parsed = int(value)
    except ValueError as exc:
        raise argparse.ArgumentTypeError("value must be an integer") from exc
    if parsed < 0:
        raise argparse.ArgumentTypeError("value must be non-negative")
    return parsed


def _model_payload(value: Any) -> dict[str, Any]:
    return value.model_dump(mode="json")


def _package_version(distribution: str) -> str | None:
    try:
        return distribution_version(distribution)
    except PackageNotFoundError:
        return None


def _browser_cli_version() -> tuple[str, str]:
    installed_version = _package_version("browser-cli")
    if installed_version is not None:
        return installed_version, "package_metadata"
    return __version__, "package_fallback"


def _mask_direct_url_secret(connect_url: str) -> str:
    parsed = urlsplit(connect_url)
    query = [
        (key, "***" if key == "api_key" else value)
        for key, value in parse_qsl(parsed.query, keep_blank_values=True)
    ]
    return urlunsplit(
        (
            parsed.scheme,
            parsed.netloc,
            parsed.path,
            urlencode(query, safe="*"),
            parsed.fragment,
        )
    )


def _masked_connect_url_payload(
    connect_url: str,
    *,
    reveal_connect_url: bool,
) -> dict[str, Any]:
    if reveal_connect_url:
        return {"connect_url": connect_url, "connect_url_masked": False}
    masked = _mask_direct_url_secret(connect_url)
    return {
        "connect_url": masked,
        "connect_url_masked": masked != connect_url,
    }


def _mask_sensitive_text(text: str) -> str:
    masked = re.sub(
        r"(?i)((?:api[_-]?key|access[_-]?token|token)=)[^&\s]+",
        r"\1***",
        text,
    )
    api_key = os.environ.get("LEXMOUNT_API_KEY")
    if api_key:
        masked = masked.replace(api_key, "***")
    return masked


def _is_sensitive_payload_key(key: Any) -> bool:
    normalized = str(key).lower().replace("-", "_")
    return normalized in SENSITIVE_PAYLOAD_KEYS


def _sanitize_failure_value(value: Any) -> Any:
    if isinstance(value, str):
        return _mask_sensitive_text(value)
    if isinstance(value, dict):
        return {
            key: "***"
            if _is_sensitive_payload_key(key)
            else _sanitize_failure_value(item)
            for key, item in value.items()
        }
    if isinstance(value, list):
        return [_sanitize_failure_value(item) for item in value]
    if isinstance(value, tuple):
        return tuple(_sanitize_failure_value(item) for item in value)
    return value


def _doctor_check(
    name: str,
    status: str,
    message: str,
    **details: Any,
) -> dict[str, Any]:
    check = {"name": name, "status": status, "message": message}
    check.update(details)
    return check


def _doctor_fix(
    code: str,
    *,
    commands: list[str] | None = None,
    env: list[str] | None = None,
    guidance: list[str] | None = None,
    connect_from_codex: dict[str, Any] | None = None,
) -> dict[str, Any]:
    fix: dict[str, Any] = {"code": code}
    if commands:
        fix["commands"] = commands
    if env:
        fix["env"] = env
    if guidance:
        fix["guidance"] = guidance
    if connect_from_codex:
        fix["connect_from_codex"] = connect_from_codex
    return fix


def _doctor_check_names(
    checks: list[dict[str, Any]],
    *,
    status: str,
) -> list[str]:
    return [str(check["name"]) for check in checks if check.get("status") == status]


def _doctor_repair_plan(checks: list[dict[str, Any]]) -> dict[str, Any]:
    statuses = {"fail", "warn", "skipped"}
    commands: list[str] = []
    env: list[str] = []
    guidance: list[str] = []
    fixes: list[dict[str, Any]] = []
    connect_from_codex: dict[str, Any] | None = None

    for check in checks:
        if check.get("status") not in statuses:
            continue
        fix = check.get("fix")
        if not isinstance(fix, dict):
            continue

        item: dict[str, Any] = {
            "check": check.get("name"),
            "status": check.get("status"),
            "code": fix.get("code"),
        }
        for key in ("commands", "env", "guidance"):
            values = fix.get(key)
            if isinstance(values, list):
                item[key] = values
        fix_connect_from_codex = fix.get("connect_from_codex")
        if isinstance(fix_connect_from_codex, dict):
            item["connect_from_codex"] = fix_connect_from_codex
            if connect_from_codex is None:
                connect_from_codex = fix_connect_from_codex
        fixes.append(item)

        commands.extend(str(value) for value in fix.get("commands", []))
        env.extend(str(value) for value in fix.get("env", []))
        guidance.extend(str(value) for value in fix.get("guidance", []))

    repair_plan: dict[str, Any] = {
        "required": bool(_doctor_check_names(checks, status="fail")),
        "recommended": bool(fixes),
        "commands": _dedupe_preserving_order(commands),
        "env": _dedupe_preserving_order(env),
        "guidance": _dedupe_preserving_order(guidance),
        "fixes": fixes,
    }
    if connect_from_codex:
        repair_plan["connect_from_codex"] = connect_from_codex
    return repair_plan


def _doctor_workflow_step_names(workflow: Any) -> set[str]:
    if not isinstance(workflow, dict):
        return set()
    steps = workflow.get("steps")
    if not isinstance(steps, list):
        return set()
    return {
        str(step.get("id"))
        for step in steps
        if isinstance(step, dict) and step.get("id")
    }


def _doctor_workflow_command_references(
    workflows: Any,
    command_names: set[str],
) -> list[dict[str, Any]]:
    if not isinstance(workflows, dict):
        return []

    invalid: list[dict[str, Any]] = []
    scalar_fields = ("command", "follow_up_command")
    list_fields = ("preferred_commands", "fallback_commands", "alternative_commands")
    for workflow_id, workflow in workflows.items():
        if not isinstance(workflow, dict):
            continue
        steps = workflow.get("steps")
        if not isinstance(steps, list):
            continue
        for step in steps:
            if not isinstance(step, dict):
                continue
            step_id = str(step.get("id") or "")
            for field in scalar_fields:
                command = step.get(field)
                if isinstance(command, str):
                    command_name = _browser_cli_command_reference_name(command)
                    if command_name is not None and command_name not in command_names:
                        invalid.append(
                            {
                                "workflow": str(workflow_id),
                                "step": step_id,
                                "field": field,
                                "command": command,
                                "command_name": command_name,
                            }
                        )
            for field in list_fields:
                commands = step.get(field)
                if not isinstance(commands, list):
                    continue
                for command in commands:
                    if not isinstance(command, str):
                        continue
                    command_name = _browser_cli_command_reference_name(command)
                    if command_name is not None and command_name not in command_names:
                        invalid.append(
                            {
                                "workflow": str(workflow_id),
                                "step": step_id,
                                "field": field,
                                "command": command,
                                "command_name": command_name,
                            }
                        )
    return invalid


def _doctor_agent_entrypoint_command_references(
    entrypoints: Any,
    command_names: set[str],
) -> list[dict[str, Any]]:
    if not isinstance(entrypoints, dict):
        return []

    invalid: list[dict[str, Any]] = []
    for entrypoint_id, commands in entrypoints.items():
        if not isinstance(commands, list):
            continue
        for command in commands:
            if not isinstance(command, str):
                continue
            command_name = _browser_cli_command_reference_name(command)
            if command_name is not None and command_name not in command_names:
                invalid.append(
                    {
                        "entrypoint": str(entrypoint_id),
                        "command": command,
                        "command_name": command_name,
                    }
                )
    return invalid


def _doctor_command_catalog_check() -> dict[str, Any]:
    try:
        catalog = _command_catalog()
    except Exception as exc:
        return _doctor_check(
            "command_catalog",
            "warn",
            "Command catalog could not be built.",
            error=exc.__class__.__name__,
            fix=_doctor_fix(
                "verify_command_catalog",
                commands=[
                    "browser-cli commands --names-only",
                    "uv tool install git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "The Codex Skill relies on command discovery before writing custom JavaScript.",
                    "Upgrade or reinstall browser-cli if command discovery fails.",
                ],
            ),
        )

    command_names = {
        str(command.get("name"))
        for command in catalog.get("commands", [])
        if isinstance(command, dict)
    }
    command_reference_names = set(command_names)
    command_reference_names.update(COMMAND_ALIASES)
    workflows = catalog.get("agent_workflows")
    entrypoints = catalog.get("agent_entrypoints")
    workflow_names = set(workflows) if isinstance(workflows, dict) else set()
    entrypoint_names = set(entrypoints) if isinstance(entrypoints, dict) else set()
    missing_commands = [
        command for command in DOCTOR_REQUIRED_COMMANDS if command not in command_names
    ]
    missing_workflows = [
        workflow
        for workflow in DOCTOR_REQUIRED_WORKFLOWS
        if workflow not in workflow_names
    ]
    missing_agent_entrypoints = [
        entrypoint
        for entrypoint in DOCTOR_REQUIRED_AGENT_ENTRYPOINTS
        if entrypoint not in entrypoint_names
    ]
    required_workflow_steps = {
        workflow: list(steps)
        for workflow, steps in DOCTOR_REQUIRED_WORKFLOW_STEPS.items()
    }
    missing_workflow_steps: dict[str, list[str]] = {}
    if isinstance(workflows, dict):
        for workflow, required_steps in DOCTOR_REQUIRED_WORKFLOW_STEPS.items():
            if workflow not in workflow_names:
                continue
            step_names = _doctor_workflow_step_names(workflows.get(workflow))
            missing_steps = [step for step in required_steps if step not in step_names]
            if missing_steps:
                missing_workflow_steps[workflow] = missing_steps
    invalid_workflow_command_references = _doctor_workflow_command_references(
        workflows,
        command_reference_names,
    )
    invalid_agent_entrypoint_command_references = (
        _doctor_agent_entrypoint_command_references(
            entrypoints,
            command_reference_names,
        )
    )

    if (
        missing_commands
        or missing_workflows
        or missing_agent_entrypoints
        or missing_workflow_steps
        or invalid_workflow_command_references
        or invalid_agent_entrypoint_command_references
    ):
        return _doctor_check(
            "command_catalog",
            "warn",
            "Command catalog is missing commands, workflows, agent entrypoints, workflow steps, or command references expected by the Codex Skill.",
            schema_version=catalog.get("schema_version"),
            command_count=len(command_names),
            workflow_count=len(workflow_names),
            agent_entrypoint_count=len(entrypoint_names),
            required_commands=list(DOCTOR_REQUIRED_COMMANDS),
            missing_required_commands=missing_commands,
            required_workflows=list(DOCTOR_REQUIRED_WORKFLOWS),
            missing_required_workflows=missing_workflows,
            required_agent_entrypoints=list(DOCTOR_REQUIRED_AGENT_ENTRYPOINTS),
            missing_required_agent_entrypoints=missing_agent_entrypoints,
            required_workflow_steps=required_workflow_steps,
            missing_required_workflow_steps=missing_workflow_steps,
            invalid_workflow_command_references=invalid_workflow_command_references,
            invalid_agent_entrypoint_command_references=(
                invalid_agent_entrypoint_command_references
            ),
            fix=_doctor_fix(
                "upgrade_browser_cli_command_surface",
                commands=[
                    "browser-cli commands --names-only",
                    "browser-cli commands",
                    "uv tool install git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Upgrade browser-cli before relying on the full Codex Skill workflow.",
                    "Use `browser-cli commands --group action --names-only` to inspect available actions.",
                    "Use `browser-cli commands` to inspect structured agent_workflows and their steps.",
                ],
            ),
        )

    return _doctor_check(
        "command_catalog",
        "pass",
        "Command catalog includes the commands expected by the Codex Skill.",
        schema_version=catalog.get("schema_version"),
        command_count=len(command_names),
        workflow_count=len(workflow_names),
        agent_entrypoint_count=len(entrypoint_names),
        required_commands=list(DOCTOR_REQUIRED_COMMANDS),
        missing_required_commands=[],
        required_workflows=list(DOCTOR_REQUIRED_WORKFLOWS),
        missing_required_workflows=[],
        required_agent_entrypoints=list(DOCTOR_REQUIRED_AGENT_ENTRYPOINTS),
        missing_required_agent_entrypoints=[],
        required_workflow_steps=required_workflow_steps,
        missing_required_workflow_steps={},
        invalid_workflow_command_references=[],
        invalid_agent_entrypoint_command_references=[],
    )


def _doctor_invalid_action_guides(
    guides: dict[str, Any],
    command_names: set[str],
) -> list[dict[str, Any]]:
    invalid: list[dict[str, Any]] = []
    list_fields = {
        "related_workflows",
        "when_to_use",
        "selection_order",
        "inspect_commands",
        "preferred_commands",
        "fallback_commands",
        "verify_commands",
        "read_fields",
    }
    text_fields = {"purpose", "custom_js_boundary"}
    command_fields = {
        "inspect_commands",
        "preferred_commands",
        "fallback_commands",
        "verify_commands",
    }
    workflow_names = set(DOCTOR_REQUIRED_WORKFLOWS)

    for task in DOCTOR_REQUIRED_ACTION_GUIDE_TASKS:
        guide = guides.get(task)
        if not isinstance(guide, dict):
            if guide is not None:
                invalid.append({"task": task, "problems": ["guide_not_object"]})
            continue

        problems: list[str] = []
        for field in DOCTOR_REQUIRED_ACTION_GUIDE_FIELDS:
            if field not in guide:
                problems.append(f"{field}_missing")
                continue
            value = guide.get(field)
            if field in list_fields and not isinstance(value, list):
                problems.append(f"{field}_not_list")
            elif field in list_fields and not value:
                problems.append(f"{field}_empty")
            elif field in text_fields and not (
                isinstance(value, str) and value.strip()
            ):
                problems.append(f"{field}_empty")

        related_workflows = guide.get("related_workflows")
        if isinstance(related_workflows, list):
            unknown_workflows = [
                str(workflow)
                for workflow in related_workflows
                if str(workflow) not in workflow_names
            ]
            if unknown_workflows:
                problems.append("related_workflows_unknown")

        invalid_command_references: list[dict[str, Any]] = []
        for field in command_fields:
            commands = guide.get(field)
            if not isinstance(commands, list):
                continue
            for command in commands:
                if not isinstance(command, str):
                    continue
                command_name = _browser_cli_command_reference_name(command)
                if command_name is None:
                    continue
                if command_name not in command_names:
                    invalid_command_references.append(
                        {
                            "field": field,
                            "command": command,
                            "command_name": command_name,
                        }
                    )
        if invalid_command_references:
            problems.append("unknown_command_references")

        if problems:
            item: dict[str, Any] = {"task": task, "problems": problems}
            if invalid_command_references:
                item["invalid_command_references"] = invalid_command_references
            invalid.append(item)

    return invalid


def _browser_cli_command_reference_name(command: str) -> str | None:
    text = command.strip()
    if not text.startswith("browser-cli "):
        return None
    try:
        tokens = shlex.split(text)
    except ValueError:
        tokens = text.split()
    if len(tokens) < 2 or tokens[0] != "browser-cli":
        return None
    group = tokens[1]
    if group in {"commands", "doctor", "version"}:
        return group
    if group in {
        "action",
        "auth",
        "case",
        "context",
        "example",
        "reference",
        "session",
        "skill",
    }:
        if len(tokens) < 3:
            return None
        return f"{group}.{tokens[2]}"
    return group


def _doctor_action_guide_command_names() -> set[str]:
    try:
        catalog = _command_catalog()
    except Exception:
        return set(DOCTOR_REQUIRED_COMMANDS)
    command_names = {
        str(command.get("name"))
        for command in catalog.get("commands", [])
        if isinstance(command, dict) and command.get("name")
    }
    command_names.update(COMMAND_ALIASES)
    return command_names


def _doctor_action_guides_check() -> dict[str, Any]:
    try:
        guides = _action_guide_tasks()
    except Exception as exc:
        return _doctor_check(
            "action_guides",
            "warn",
            "Action guide catalog could not be built.",
            error=exc.__class__.__name__,
            required_action_guides=list(DOCTOR_REQUIRED_ACTION_GUIDE_TASKS),
            required_guide_fields=list(DOCTOR_REQUIRED_ACTION_GUIDE_FIELDS),
            fix=_doctor_fix(
                "verify_action_guide_catalog",
                commands=[
                    "browser-cli action guide --names-only",
                    "browser-cli action guide --task interactive_targeting",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "The Codex Skill relies on action guides before choosing browser actions.",
                    "Upgrade or reinstall browser-cli if action guide discovery fails.",
                ],
            ),
        )

    guide_names = set(guides) if isinstance(guides, dict) else set()
    missing_action_guides = [
        task for task in DOCTOR_REQUIRED_ACTION_GUIDE_TASKS if task not in guide_names
    ]
    command_names = _doctor_action_guide_command_names()
    invalid_action_guides = (
        _doctor_invalid_action_guides(guides, command_names)
        if isinstance(guides, dict)
        else [
            {
                "task": task,
                "problems": ["action_guides_not_object"],
            }
            for task in DOCTOR_REQUIRED_ACTION_GUIDE_TASKS
        ]
    )
    invalid_guide_command_references = [
        {
            "task": guide["task"],
            **reference,
        }
        for guide in invalid_action_guides
        for reference in guide.get("invalid_command_references", [])
        if isinstance(reference, dict)
    ]

    if missing_action_guides or invalid_action_guides:
        return _doctor_check(
            "action_guides",
            "warn",
            "Action guide catalog is missing tasks or fields expected by the Codex Skill.",
            schema_version=1,
            guide_count=len(guide_names),
            required_action_guides=list(DOCTOR_REQUIRED_ACTION_GUIDE_TASKS),
            missing_required_action_guides=missing_action_guides,
            required_guide_fields=list(DOCTOR_REQUIRED_ACTION_GUIDE_FIELDS),
            invalid_action_guides=invalid_action_guides,
            invalid_guide_command_references=invalid_guide_command_references,
            fix=_doctor_fix(
                "upgrade_browser_cli_action_guides",
                commands=[
                    "browser-cli action guide --names-only",
                    "browser-cli action guide --task interactive_targeting",
                    "browser-cli action guide --task form_interaction",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Upgrade browser-cli before relying on action guides for the full Codex Skill workflow.",
                    "Use `browser-cli action guide --names-only` to inspect supported guide tasks.",
                    "Use `browser-cli action guide --task <task>` before choosing browser actions or custom JavaScript.",
                ],
            ),
        )

    return _doctor_check(
        "action_guides",
        "pass",
        "Action guide catalog includes the task guides expected by the Codex Skill.",
        schema_version=1,
        guide_count=len(guide_names),
        required_action_guides=list(DOCTOR_REQUIRED_ACTION_GUIDE_TASKS),
        missing_required_action_guides=[],
        required_guide_fields=list(DOCTOR_REQUIRED_ACTION_GUIDE_FIELDS),
        invalid_action_guides=[],
        invalid_guide_command_references=[],
    )


def _doctor_invalid_case_action_schemas(
    actions: dict[str, Any],
) -> list[dict[str, Any]]:
    invalid: list[dict[str, Any]] = []
    for action in DOCTOR_REQUIRED_CASE_ACTIONS:
        schema = actions.get(action)
        if not isinstance(schema, dict):
            continue

        problems: list[str] = []
        for field in (
            "required_fields",
            "required_one_of",
            "optional_fields",
            "result_fields",
        ):
            if not isinstance(schema.get(field), list):
                problems.append(f"{field}_not_list")
        example = schema.get("example_step")
        if not isinstance(example, dict):
            problems.append("example_step_not_object")
        elif example.get("action") != action:
            problems.append("example_step_action_mismatch")

        if problems:
            invalid.append(
                {
                    "action": action,
                    "problems": problems,
                }
            )
    return invalid


def _doctor_case_scaffold_args(template: str) -> argparse.Namespace:
    return argparse.Namespace(
        template=template,
        name=None,
        url=None,
        selector=None,
        title=None,
        text="lexmount browser",
        browser_mode="light",
        max_chars=2000,
        output_format="json",
        output=None,
        overwrite=False,
    )


def _doctor_case_scaffold_checks(
    available_templates: set[str],
) -> list[dict[str, Any]]:
    checked: list[dict[str, Any]] = []
    for template in DOCTOR_REQUIRED_CASE_SCAFFOLD_TEMPLATES:
        if template not in available_templates:
            continue
        try:
            spec = _case_scaffold_spec(_doctor_case_scaffold_args(template))
            if not isinstance(spec, dict):
                raise TypeError("case scaffold spec must be an object")
            errors = _validate_browser_cli_case_spec(spec)
            content = _serialize_case_spec(
                command="doctor.case_schema",
                spec=spec,
                output_format="json",
            )
            decoded = json.loads(content)
            if isinstance(decoded, dict):
                round_trip_errors = _validate_browser_cli_case_spec(decoded)
            else:
                round_trip_errors = ["serialized case must be an object"]
            errors.extend(f"serialized.{error}" for error in round_trip_errors)
            steps = spec.get("steps", [])
            actions = [
                str(step.get("action"))
                for step in steps
                if isinstance(step, dict) and step.get("action") is not None
            ]
            checked.append(
                {
                    "template": template,
                    "valid": not errors,
                    "errors": errors,
                    "step_count": len(steps) if isinstance(steps, list) else 0,
                    "actions": actions,
                    "output_format": "json",
                    "content_length": len(content),
                }
            )
        except Exception as exc:
            checked.append(
                {
                    "template": template,
                    "valid": False,
                    "errors": [f"{exc.__class__.__name__}: {exc}"],
                    "step_count": 0,
                    "actions": [],
                    "output_format": "json",
                    "content_length": 0,
                }
            )
    return checked


def _doctor_case_schema_check() -> dict[str, Any]:
    try:
        actions = _case_action_schema()
        supported_actions = set(BROWSER_CLI_SUPPORTED_CASE_ACTIONS)
    except Exception as exc:
        return _doctor_check(
            "case_schema",
            "warn",
            "Case schema could not be built.",
            error=exc.__class__.__name__,
            required_case_actions=list(DOCTOR_REQUIRED_CASE_ACTIONS),
            required_case_scaffold_templates=list(
                DOCTOR_REQUIRED_CASE_SCAFFOLD_TEMPLATES
            ),
            checked_case_scaffold_templates=[],
            invalid_case_scaffold_templates=[],
            fix=_doctor_fix(
                "verify_case_schema",
                commands=[
                    "browser-cli case schema --names-only",
                    "browser-cli case schema --action act",
                    "browser-cli case schema --action observe",
                    "browser-cli case schema --action extract",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "The Codex Skill relies on case schema before writing repeatable browser tasks.",
                    "Upgrade or reinstall browser-cli if case schema discovery fails.",
                ],
            ),
        )

    action_names = set(actions) if isinstance(actions, dict) else set()
    missing_supported_actions = [
        action
        for action in DOCTOR_REQUIRED_CASE_ACTIONS
        if action not in supported_actions
    ]
    missing_action_schemas = [
        action for action in DOCTOR_REQUIRED_CASE_ACTIONS if action not in action_names
    ]
    missing_required_case_actions = [
        action
        for action in DOCTOR_REQUIRED_CASE_ACTIONS
        if action in set(missing_supported_actions) | set(missing_action_schemas)
    ]
    scaffold_templates = set(CASE_SCAFFOLD_TEMPLATES)
    missing_case_scaffold_templates = [
        template
        for template in DOCTOR_REQUIRED_CASE_SCAFFOLD_TEMPLATES
        if template not in scaffold_templates
    ]
    checked_case_scaffold_templates = _doctor_case_scaffold_checks(scaffold_templates)
    invalid_case_scaffold_templates = [
        result for result in checked_case_scaffold_templates if not result["valid"]
    ]
    invalid_action_schemas = (
        _doctor_invalid_case_action_schemas(actions)
        if isinstance(actions, dict)
        else [
            {
                "action": action,
                "problems": ["case_schema_not_object"],
            }
            for action in DOCTOR_REQUIRED_CASE_ACTIONS
        ]
    )

    if (
        missing_supported_actions
        or missing_action_schemas
        or missing_case_scaffold_templates
        or invalid_case_scaffold_templates
        or invalid_action_schemas
    ):
        return _doctor_check(
            "case_schema",
            "warn",
            "Case schema is missing actions, scaffold templates, valid starter cases, or schema fields expected by the Codex Skill.",
            schema_version=1,
            action_count=len(action_names),
            supported_action_count=len(supported_actions),
            required_case_actions=list(DOCTOR_REQUIRED_CASE_ACTIONS),
            required_case_scaffold_templates=list(
                DOCTOR_REQUIRED_CASE_SCAFFOLD_TEMPLATES
            ),
            missing_required_case_actions=missing_required_case_actions,
            missing_supported_actions=missing_supported_actions,
            missing_action_schemas=missing_action_schemas,
            missing_case_scaffold_templates=missing_case_scaffold_templates,
            checked_case_scaffold_templates=checked_case_scaffold_templates,
            invalid_case_scaffold_templates=invalid_case_scaffold_templates,
            invalid_action_schemas=invalid_action_schemas,
            fix=_doctor_fix(
                "upgrade_browser_cli_case_schema",
                commands=[
                    "browser-cli case schema --names-only",
                    "browser-cli case schema --action act",
                    "browser-cli case schema --action observe",
                    "browser-cli case schema --action extract",
                    "browser-cli case schema --action fill-label",
                    "browser-cli case scaffold --template agent-primitives --format json",
                    "browser-cli case scaffold --template content-extraction --format json",
                    "browser-cli case scaffold --template browser-state --format json",
                    "browser-cli case scaffold --template navigation-flow --format json",
                    "browser-cli case scaffold --template file-upload --format json",
                    "browser-cli case scaffold --template checkout-flow --format json",
                    "browser-cli case schema --action network-snapshot",
                    "browser-cli case scaffold --template interactive-targeting --format json",
                    "browser-cli case scaffold --template page-diagnostics --format json",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Upgrade browser-cli before relying on case files for the full Codex Skill workflow.",
                    "Use `browser-cli case schema --names-only` to inspect repeatable case actions.",
                    "Use `browser-cli case schema --action <action>` to inspect required fields, result fields, and example steps.",
                    "Use `browser-cli case scaffold --template <template> --format json` to verify packaged starter cases are valid.",
                ],
            ),
        )

    return _doctor_check(
        "case_schema",
        "pass",
        "Case schema includes the repeatable actions and valid scaffold templates expected by the Codex Skill.",
        schema_version=1,
        action_count=len(action_names),
        supported_action_count=len(supported_actions),
        required_case_actions=list(DOCTOR_REQUIRED_CASE_ACTIONS),
        required_case_scaffold_templates=list(DOCTOR_REQUIRED_CASE_SCAFFOLD_TEMPLATES),
        missing_required_case_actions=[],
        missing_supported_actions=[],
        missing_action_schemas=[],
        missing_case_scaffold_templates=[],
        checked_case_scaffold_templates=checked_case_scaffold_templates,
        invalid_case_scaffold_templates=[],
        invalid_action_schemas=[],
    )


def _doctor_auth_export_env_contract_check() -> dict[str, Any]:
    try:
        payload = _auth_export_env_payload(
            argparse.Namespace(
                shell="posix",
                from_current=False,
                reveal_secrets=False,
                include_base_url=False,
                include_region=False,
            )
        )
    except Exception as exc:
        return _doctor_check(
            "auth_export_env_contract",
            "warn",
            "auth export-env contract could not be built.",
            error=exc.__class__.__name__,
            required_fields=list(DOCTOR_REQUIRED_AUTH_EXPORT_ENV_FIELDS),
            fix=_doctor_fix(
                "repair_auth_export_env_contract",
                commands=[
                    "browser-cli auth export-env",
                    "browser-cli doctor --json",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Agents rely on auth export-env safety metadata before copying shell commands.",
                    "Upgrade or reinstall browser-cli if auth export-env cannot produce JSON.",
                ],
            ),
        )

    missing_fields = [
        field
        for field in DOCTOR_REQUIRED_AUTH_EXPORT_ENV_FIELDS
        if field not in payload
    ]
    invalid_fields: list[str] = []

    safety = payload.get("safety")
    setup_block = payload.get("setup_block")
    verification = payload.get("verification")
    if not isinstance(safety, dict):
        invalid_fields.append("safety")
        safety = {}
    if not isinstance(setup_block, dict):
        invalid_fields.append("setup_block")
        setup_block = {}
    if not isinstance(verification, dict):
        invalid_fields.append("verification")
        verification = {}

    expected_values = {
        "usable": False,
        "contains_secret_values": False,
        "contains_secret_placeholders": True,
        "safe_to_paste_in_chat": False,
        "local_shell_only": True,
    }
    for field, expected in expected_values.items():
        if payload.get(field) is not expected:
            invalid_fields.append(field)
        if safety.get(field) is not expected and field in {
            "contains_secret_values",
            "contains_secret_placeholders",
            "safe_to_paste_in_chat",
            "local_shell_only",
        }:
            invalid_fields.append(f"safety.{field}")

    if "LEXMOUNT_API_KEY" not in payload.get("secret_env", []):
        invalid_fields.append("secret_env")
    if safety.get("secret_env") != payload.get("secret_env"):
        invalid_fields.append("safety.secret_env")
    if setup_block.get("id") != "local_env":
        invalid_fields.append("setup_block.id")
    if setup_block.get("commands") != payload.get("commands"):
        invalid_fields.append("setup_block.commands")
    if verification.get("doctor_command") != AGENT_DOCTOR_COMMAND:
        invalid_fields.append("verification.doctor_command")
    if verification.get("status_command") != "browser-cli auth status":
        invalid_fields.append("verification.status_command")

    invalid_fields = _dedupe_preserving_order(invalid_fields)
    common_details: dict[str, Any] = {
        "schema_version": 1,
        "required_fields": list(DOCTOR_REQUIRED_AUTH_EXPORT_ENV_FIELDS),
        "missing_fields": missing_fields,
        "invalid_fields": invalid_fields,
        "safe_to_paste_in_chat": payload.get("safe_to_paste_in_chat"),
        "local_shell_only": payload.get("local_shell_only"),
        "contains_secret_values": payload.get("contains_secret_values"),
        "contains_secret_placeholders": payload.get("contains_secret_placeholders"),
        "secret_env": payload.get("secret_env"),
        "verification": verification,
    }

    if missing_fields or invalid_fields:
        return _doctor_check(
            "auth_export_env_contract",
            "warn",
            "auth export-env safety metadata is missing or invalid.",
            fix=_doctor_fix(
                "repair_auth_export_env_contract",
                commands=[
                    "browser-cli auth export-env",
                    "browser-cli auth export-env --from-current",
                    "browser-cli doctor --json",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Agents should read safe_to_paste_in_chat, local_shell_only, safety, setup_block, and verification before using export commands.",
                    "Keep auth export-env output, README, and docs/json-contract.md in sync.",
                ],
            ),
            **common_details,
        )

    return _doctor_check(
        "auth_export_env_contract",
        "pass",
        "auth export-env exposes safe local-shell metadata for agents.",
        **common_details,
    )


def _doctor_auth_login_contract_check() -> dict[str, Any]:
    try:
        project_id = None
        project_id_source = "unset"
        scopes = list(DEFAULT_CODEX_CONNECT_SCOPES)
        expires_in = DEFAULT_CODEX_CONNECT_EXPIRES_IN
        connect_url = _connect_from_codex_url(
            project_id=project_id,
            scopes=scopes,
            expires_in=expires_in,
        )
        handoff = _auth_login_handoff(
            connect_url=connect_url,
            project_id=project_id,
            project_id_source=project_id_source,
            scopes=scopes,
            expires_in=expires_in,
        )
        site_capability_status = _connect_from_codex_site_capability_status(
            _connect_from_codex_site_capabilities()
        )
        runtime_auth = _connect_from_codex_required_runtime_auth()
    except Exception as exc:
        return _doctor_check(
            "auth_login_contract",
            "warn",
            "auth login handoff contract could not be built.",
            error=exc.__class__.__name__,
            required_handoff_fields=list(DOCTOR_REQUIRED_AUTH_LOGIN_HANDOFF_FIELDS),
            fix=_doctor_fix(
                "repair_auth_login_contract",
                commands=[
                    "browser-cli auth login",
                    "browser-cli auth connect-requirements",
                    "browser-cli commands --workflow connect_from_codex_auth",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Agents rely on auth login handoff fields before guiding users through local credential setup.",
                    "Upgrade or reinstall browser-cli if auth login cannot produce JSON.",
                ],
            ),
        )

    missing_handoff_fields = [
        field
        for field in DOCTOR_REQUIRED_AUTH_LOGIN_HANDOFF_FIELDS
        if field not in handoff
    ]
    invalid_fields: list[str] = []
    if handoff.get("recommended_flow") != "manual_env":
        invalid_fields.append("recommended_flow")
    if handoff.get("login_url") != LEXMOUNT_CONSOLE_URL:
        invalid_fields.append("login_url")
    if handoff.get("connect_from_codex_available") is not False:
        invalid_fields.append("connect_from_codex_available")
    if handoff.get("open_command") != "browser-cli auth login --open":
        invalid_fields.append("open_command")
    if handoff.get("open_url") != handoff.get("connect_from_codex_url"):
        invalid_fields.append("open_url")
    if handoff.get("connect_from_codex_url") != connect_url:
        invalid_fields.append("connect_from_codex_url")

    split_url = urlsplit(str(handoff.get("connect_from_codex_url", "")))
    query_pairs = parse_qsl(split_url.query)
    query_values = {key: value for key, value in query_pairs if key != "scope"}
    scope_values = [value for key, value in query_pairs if key == "scope"]
    if f"{split_url.scheme}://{split_url.netloc}{split_url.path}" != (
        LEXMOUNT_CODEX_CONNECT_URL
    ):
        invalid_fields.append("connect_from_codex_url.base")
    expected_query = {
        "source": "browser-cli",
        "intent": "agent-browser-control",
        "response": "code",
        "expires_in": DEFAULT_CODEX_CONNECT_EXPIRES_IN,
    }
    for key, expected in expected_query.items():
        if query_values.get(key) != expected:
            invalid_fields.append(f"connect_from_codex_url.{key}")
    if scope_values != [" ".join(DEFAULT_CODEX_CONNECT_SCOPES)]:
        invalid_fields.append("connect_from_codex_url.scope")

    setup_blocks = handoff.get("setup_blocks")
    setup_block_ids: list[str] = []
    missing_setup_blocks = list(DOCTOR_REQUIRED_AUTH_LOGIN_SETUP_BLOCKS)
    setup_by_id: dict[str, dict[str, Any]] = {}
    if isinstance(setup_blocks, list):
        setup_by_id = {
            str(block.get("id")): block
            for block in setup_blocks
            if isinstance(block, dict) and block.get("id") is not None
        }
        setup_block_ids = list(setup_by_id)
        missing_setup_blocks = [
            block_id
            for block_id in DOCTOR_REQUIRED_AUTH_LOGIN_SETUP_BLOCKS
            if block_id not in setup_by_id
        ]
    else:
        invalid_fields.append("setup_blocks")

    install_block = setup_by_id.get("install", {})
    if "uv tool install git+https://github.com/lexmount/browser-cli.git" not in (
        install_block.get("commands") or []
    ):
        invalid_fields.append("setup_blocks.install.commands")
    local_env_block = setup_by_id.get("local_env", {})
    if local_env_block.get("safe_to_paste_in_chat") is not False:
        invalid_fields.append("setup_blocks.local_env.safe_to_paste_in_chat")
    if local_env_block.get("local_shell_only") is not True:
        invalid_fields.append("setup_blocks.local_env.local_shell_only")
    if local_env_block.get("contains_secret_values") is not False:
        invalid_fields.append("setup_blocks.local_env.contains_secret_values")
    if "LEXMOUNT_API_KEY" not in local_env_block.get("secret_env", []):
        invalid_fields.append("setup_blocks.local_env.secret_env")
    verify_block = setup_by_id.get("verify", {})
    if AGENT_DOCTOR_COMMAND not in (verify_block.get("commands") or []):
        invalid_fields.append("setup_blocks.verify.commands")

    copyable_commands = handoff.get("copyable_commands")
    if not isinstance(copyable_commands, list):
        invalid_fields.append("copyable_commands")
    else:
        for command in (
            AGENT_USABLE_STATUS_METADATA_COMMAND,
            AGENT_USABLE_STATUS_COMMAND,
            "browser-cli auth status",
            "browser-cli auth login",
            "browser-cli auth export-env",
            AGENT_DOCTOR_COMMAND,
        ):
            if command not in copyable_commands:
                invalid_fields.append(f"copyable_commands.{command}")

    local_env = handoff.get("local_env")
    if not isinstance(local_env, list):
        invalid_fields.append("local_env")
        local_env_names: list[str] = []
    else:
        env_by_name = {
            str(item.get("name")): item
            for item in local_env
            if isinstance(item, dict) and item.get("name") is not None
        }
        local_env_names = list(env_by_name)
        if env_by_name.get("LEXMOUNT_API_KEY", {}).get("secret") is not True:
            invalid_fields.append("local_env.LEXMOUNT_API_KEY.secret")
        if env_by_name.get("LEXMOUNT_PROJECT_ID", {}).get("required") is not True:
            invalid_fields.append("local_env.LEXMOUNT_PROJECT_ID.required")

    verification = handoff.get("verification")
    if not isinstance(verification, dict):
        invalid_fields.append("verification")
        verification = {}
    if verification.get("doctor_command") != AGENT_DOCTOR_COMMAND:
        invalid_fields.append("verification.doctor_command")
    if verification.get("status_command") != "browser-cli auth status":
        invalid_fields.append("verification.status_command")

    secret_policy = handoff.get("secret_policy")
    if not isinstance(secret_policy, dict):
        invalid_fields.append("secret_policy")
        secret_policy = {}
    if "LEXMOUNT_API_KEY" not in secret_policy.get("do_not_paste_in_chat", []):
        invalid_fields.append("secret_policy.do_not_paste_in_chat")
    if "browser-cli doctor output with default masking" not in secret_policy.get(
        "safe_to_share", []
    ):
        invalid_fields.append("secret_policy.safe_to_share")

    runtime_auth_ids = [
        str(item.get("id")) for item in runtime_auth if isinstance(item, dict)
    ]
    missing_runtime_auth = [
        item
        for item in DOCTOR_REQUIRED_CONNECT_RUNTIME_AUTH
        if item not in runtime_auth_ids
    ]
    if missing_runtime_auth:
        invalid_fields.append("required_runtime_auth")

    invalid_fields = _dedupe_preserving_order(invalid_fields)
    common_details: dict[str, Any] = {
        "schema_version": 1,
        "required_handoff_fields": list(DOCTOR_REQUIRED_AUTH_LOGIN_HANDOFF_FIELDS),
        "missing_handoff_fields": missing_handoff_fields,
        "required_setup_blocks": list(DOCTOR_REQUIRED_AUTH_LOGIN_SETUP_BLOCKS),
        "setup_block_ids": setup_block_ids,
        "missing_setup_blocks": missing_setup_blocks,
        "invalid_fields": invalid_fields,
        "copyable_commands": copyable_commands,
        "local_env_names": local_env_names,
        "recommended_flow": handoff.get("recommended_flow"),
        "manual_env_available": True,
        "connect_from_codex_available": handoff.get("connect_from_codex_available"),
        "connect_from_codex_url": handoff.get("connect_from_codex_url"),
        "connect_from_codex_url_masked": False,
        "requested_scopes": handoff.get("requested_scopes"),
        "requested_expires_in": handoff.get("requested_expires_in"),
        "site_capability_status": site_capability_status,
        "runtime_auth_ids": runtime_auth_ids,
        "missing_runtime_auth": missing_runtime_auth,
        "secret_policy": secret_policy,
        "verification": verification,
    }

    if missing_handoff_fields or missing_setup_blocks or invalid_fields:
        return _doctor_check(
            "auth_login_contract",
            "warn",
            "auth login handoff metadata is missing or invalid.",
            fix=_doctor_fix(
                "repair_auth_login_contract",
                commands=[
                    "browser-cli auth login",
                    "browser-cli auth login --device-code",
                    "browser-cli commands --workflow connect_from_codex_auth",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Keep auth login, auth connect-requirements, README, and docs/json-contract.md in sync.",
                    "Agents should not guide users through browser credentials unless auth login exposes setup_blocks, local_env safety, verification, and secret_policy.",
                ],
            ),
            **common_details,
        )

    return _doctor_check(
        "auth_login_contract",
        "pass",
        "auth login exposes the handoff metadata agents need for safe setup.",
        **common_details,
    )


def _doctor_device_code_contract_check() -> dict[str, Any]:
    try:
        project_id = None
        project_id_source = "unset"
        scopes = list(DEFAULT_CODEX_CONNECT_SCOPES)
        scope_details = _scope_details(scopes)
        expires_in = DEFAULT_CODEX_CONNECT_EXPIRES_IN
        connect_url = _connect_from_codex_url(
            project_id=project_id,
            scopes=scopes,
            expires_in=expires_in,
            response="device_code",
        )
        fallback_connect_url = _connect_from_codex_url(
            project_id=project_id,
            scopes=scopes,
            expires_in=expires_in,
        )
        fallback_handoff = _auth_login_handoff(
            connect_url=fallback_connect_url,
            project_id=project_id,
            project_id_source=project_id_source,
            scopes=scopes,
            expires_in=expires_in,
        )
        required_endpoints = _device_code_required_endpoints()
        required_browser_site_support = _device_code_required_browser_site_support()
        device_code = {
            "available": False,
            "reason": "browser_site_endpoint_missing",
            "verification_uri": LEXMOUNT_CODEX_CONNECT_URL,
            "connect_from_codex_url": connect_url,
            "project_id": project_id,
            "project_id_source": project_id_source,
            "requested_scopes": scopes,
            "requested_scope_details": scope_details,
            "requested_expires_in": expires_in,
            "required_endpoints": required_endpoints,
            "required_browser_site_support": required_browser_site_support,
        }
        site_capabilities = _connect_from_codex_site_capabilities()
        site_capability_status = _connect_from_codex_site_capability_status(
            site_capabilities
        )
        runtime_auth = _connect_from_codex_required_runtime_auth()
    except Exception as exc:
        return _doctor_check(
            "device_code_contract",
            "warn",
            "auth login --device-code contract could not be built.",
            error=exc.__class__.__name__,
            required_device_code_fields=list(DOCTOR_REQUIRED_DEVICE_CODE_FIELDS),
            fix=_doctor_fix(
                "repair_device_code_contract",
                commands=[
                    "browser-cli auth login --device-code",
                    "browser-cli auth connect-requirements",
                    "browser-cli commands --workflow device_code_auth",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Agents rely on auth login --device-code metadata to decide between approval and manual-env fallback.",
                    "Upgrade or reinstall browser-cli if device-code login cannot produce JSON.",
                ],
                connect_from_codex=_doctor_connect_from_codex_fix(),
            ),
        )

    missing_device_code_fields = [
        field for field in DOCTOR_REQUIRED_DEVICE_CODE_FIELDS if field not in device_code
    ]
    invalid_fields: list[str] = []
    if device_code.get("available") is not False:
        invalid_fields.append("available")
    if device_code.get("reason") != "browser_site_endpoint_missing":
        invalid_fields.append("reason")
    if device_code.get("verification_uri") != LEXMOUNT_CODEX_CONNECT_URL:
        invalid_fields.append("verification_uri")
    if device_code.get("project_id") is not None:
        invalid_fields.append("project_id")
    if device_code.get("project_id_source") != "unset":
        invalid_fields.append("project_id_source")
    if device_code.get("requested_scopes") != list(DEFAULT_CODEX_CONNECT_SCOPES):
        invalid_fields.append("requested_scopes")
    if device_code.get("requested_expires_in") != DEFAULT_CODEX_CONNECT_EXPIRES_IN:
        invalid_fields.append("requested_expires_in")

    split_url = urlsplit(str(device_code.get("connect_from_codex_url", "")))
    query_pairs = parse_qsl(split_url.query)
    query_values = {key: value for key, value in query_pairs if key != "scope"}
    scope_values = [value for key, value in query_pairs if key == "scope"]
    if f"{split_url.scheme}://{split_url.netloc}{split_url.path}" != (
        LEXMOUNT_CODEX_CONNECT_URL
    ):
        invalid_fields.append("connect_from_codex_url.base")
    expected_query = {
        "source": "browser-cli",
        "intent": "agent-browser-control",
        "response": "device_code",
        "expires_in": DEFAULT_CODEX_CONNECT_EXPIRES_IN,
    }
    for key, expected in expected_query.items():
        if query_values.get(key) != expected:
            invalid_fields.append(f"connect_from_codex_url.{key}")
    if scope_values != [" ".join(DEFAULT_CODEX_CONNECT_SCOPES)]:
        invalid_fields.append("connect_from_codex_url.scope")

    device_code_endpoints = device_code.get("required_endpoints")
    if not isinstance(device_code_endpoints, list):
        invalid_fields.append("required_endpoints")
        device_code_endpoints = []
    missing_required_device_code_endpoints = [
        endpoint
        for endpoint in DOCTOR_REQUIRED_DEVICE_CODE_ENDPOINTS
        if endpoint not in device_code_endpoints
    ]
    if missing_required_device_code_endpoints:
        invalid_fields.append("required_endpoints")

    browser_site_support = device_code.get("required_browser_site_support")
    if not isinstance(browser_site_support, list):
        invalid_fields.append("required_browser_site_support")
        browser_site_support = []
    missing_required_browser_site_support = [
        support
        for support in DOCTOR_REQUIRED_DEVICE_CODE_BROWSER_SITE_SUPPORT
        if support not in browser_site_support
    ]
    if missing_required_browser_site_support:
        invalid_fields.append("required_browser_site_support")

    fallback_setup_blocks = fallback_handoff.get("setup_blocks")
    fallback_setup_block_ids: list[str] = []
    missing_fallback_setup_blocks = list(DOCTOR_REQUIRED_AUTH_LOGIN_SETUP_BLOCKS)
    fallback_setup_by_id: dict[str, dict[str, Any]] = {}
    if isinstance(fallback_setup_blocks, list):
        fallback_setup_by_id = {
            str(block.get("id")): block
            for block in fallback_setup_blocks
            if isinstance(block, dict) and block.get("id") is not None
        }
        fallback_setup_block_ids = list(fallback_setup_by_id)
        missing_fallback_setup_blocks = [
            block_id
            for block_id in DOCTOR_REQUIRED_AUTH_LOGIN_SETUP_BLOCKS
            if block_id not in fallback_setup_by_id
        ]
    else:
        invalid_fields.append("fallback_handoff.setup_blocks")

    local_env_block = fallback_setup_by_id.get("local_env", {})
    if local_env_block.get("safe_to_paste_in_chat") is not False:
        invalid_fields.append(
            "fallback_handoff.setup_blocks.local_env.safe_to_paste_in_chat"
        )
    if local_env_block.get("local_shell_only") is not True:
        invalid_fields.append(
            "fallback_handoff.setup_blocks.local_env.local_shell_only"
        )
    if local_env_block.get("contains_secret_values") is not False:
        invalid_fields.append(
            "fallback_handoff.setup_blocks.local_env.contains_secret_values"
        )
    verify_block = fallback_setup_by_id.get("verify", {})
    if AGENT_DOCTOR_COMMAND not in (verify_block.get("commands") or []):
        invalid_fields.append("fallback_handoff.setup_blocks.verify.commands")

    capability_ids = [
        str(item.get("id")) for item in site_capabilities if isinstance(item, dict)
    ]
    missing_required_site_capabilities = [
        capability
        for capability in DOCTOR_REQUIRED_DEVICE_CODE_SITE_CAPABILITIES
        if capability not in capability_ids
    ]
    if missing_required_site_capabilities:
        invalid_fields.append("site_capabilities")

    runtime_auth_ids = [
        str(item.get("id")) for item in runtime_auth if isinstance(item, dict)
    ]
    missing_runtime_auth = [
        item
        for item in DOCTOR_REQUIRED_CONNECT_RUNTIME_AUTH
        if item not in runtime_auth_ids
    ]
    if missing_runtime_auth:
        invalid_fields.append("required_runtime_auth")

    secret_policy = {
        "contains_secret_values": False,
        "do_not_paste_in_chat": [
            "access_token",
            "refresh_token",
            "raw device_code",
        ],
        "safe_to_share": [
            "browser-cli auth login --device-code output with unavailable pending contract",
            "browser-cli doctor output with default masking",
        ],
    }
    verification = {
        "login_command": "browser-cli auth login --device-code",
        "workflow_command": "browser-cli commands --workflow device_code_auth",
        "doctor_command": AGENT_DOCTOR_COMMAND,
        "success_condition": (
            "available=false falls back to manual_env until device-code endpoints "
            "and bearer-token runtime auth are implemented"
        ),
    }

    invalid_fields = _dedupe_preserving_order(invalid_fields)
    common_details: dict[str, Any] = {
        "schema_version": 1,
        "required_device_code_fields": list(DOCTOR_REQUIRED_DEVICE_CODE_FIELDS),
        "missing_device_code_fields": missing_device_code_fields,
        "available": device_code.get("available"),
        "selected_flow": "device_code",
        "device_code_available": device_code.get("available"),
        "reason": device_code.get("reason"),
        "verification_uri": device_code.get("verification_uri"),
        "connect_from_codex_url": device_code.get("connect_from_codex_url"),
        "connect_from_codex_url_masked": False,
        "requested_scopes": device_code.get("requested_scopes"),
        "requested_expires_in": device_code.get("requested_expires_in"),
        "required_device_code_endpoints": device_code_endpoints,
        "missing_required_device_code_endpoints": (
            missing_required_device_code_endpoints
        ),
        "required_browser_site_support": browser_site_support,
        "missing_required_browser_site_support": (
            missing_required_browser_site_support
        ),
        "required_site_capabilities": list(
            DOCTOR_REQUIRED_DEVICE_CODE_SITE_CAPABILITIES
        ),
        "site_capability_ids": capability_ids,
        "missing_required_site_capabilities": missing_required_site_capabilities,
        "site_capability_status": site_capability_status,
        "fallback_handoff_setup_block_ids": fallback_setup_block_ids,
        "missing_fallback_setup_blocks": missing_fallback_setup_blocks,
        "runtime_auth_ids": runtime_auth_ids,
        "missing_runtime_auth": missing_runtime_auth,
        "invalid_fields": invalid_fields,
        "secret_policy": secret_policy,
        "verification": verification,
    }

    if (
        missing_device_code_fields
        or missing_required_device_code_endpoints
        or missing_required_browser_site_support
        or missing_required_site_capabilities
        or missing_fallback_setup_blocks
        or missing_runtime_auth
        or invalid_fields
    ):
        return _doctor_check(
            "device_code_contract",
            "warn",
            "auth login --device-code metadata is missing or invalid.",
            fix=_doctor_fix(
                "repair_device_code_contract",
                commands=[
                    "browser-cli auth login --device-code",
                    "browser-cli auth connect-requirements",
                    "browser-cli commands --workflow device_code_auth",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Keep auth login --device-code, auth connect-requirements, README, and docs/json-contract.md in sync.",
                    "browser.lexmount.cn needs device-code endpoints plus bearer-token runtime support before agents can prefer approval over manual_env fallback.",
                ],
                connect_from_codex=_doctor_connect_from_codex_fix(),
            ),
            **common_details,
        )

    return _doctor_check(
        "device_code_contract",
        "pass",
        "auth login --device-code exposes a safe pending/fallback contract for agents.",
        **common_details,
    )


def _doctor_connect_from_codex_contract_check() -> dict[str, Any]:
    try:
        capabilities = _connect_from_codex_site_capabilities()
        capability_status = _connect_from_codex_site_capability_status(capabilities)
        acceptance_tests = _connect_from_codex_browser_site_acceptance_tests()
        token_lifecycle = _connect_from_codex_required_token_lifecycle()
        runtime_auth = _connect_from_codex_required_runtime_auth()
        api_contract = _connect_from_codex_required_api_contract()
    except Exception as exc:
        return _doctor_check(
            "connect_from_codex_contract",
            "warn",
            "Connect from Codex contract could not be built.",
            error=exc.__class__.__name__,
            required_capabilities=list(DOCTOR_REQUIRED_CONNECT_CAPABILITIES),
            required_acceptance_tests=list(DOCTOR_REQUIRED_CONNECT_ACCEPTANCE_TESTS),
            fix=_doctor_fix(
                "repair_connect_from_codex_contract",
                commands=[
                    "browser-cli auth connect-requirements",
                    "browser-cli auth scopes --include-site-contract",
                    "browser-cli commands --workflow connect_from_codex_site_requirements",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "The Connect from Codex browser-site handoff must be machine-readable for agents and browser.lexmount.cn implementers.",
                    "Upgrade or reinstall browser-cli if connect-requirements cannot produce JSON.",
                ],
            ),
        )

    capability_ids = [
        str(item.get("id")) for item in capabilities if isinstance(item, dict)
    ]
    acceptance_ids = [
        str(item.get("id")) for item in acceptance_tests if isinstance(item, dict)
    ]
    acceptance_capabilities = [
        str(item.get("capability"))
        for item in acceptance_tests
        if isinstance(item, dict) and item.get("capability")
    ]
    token_lifecycle_ids = [
        str(item.get("id")) for item in token_lifecycle if isinstance(item, dict)
    ]
    runtime_auth_ids = [
        str(item.get("id")) for item in runtime_auth if isinstance(item, dict)
    ]

    missing_capabilities = [
        item
        for item in DOCTOR_REQUIRED_CONNECT_CAPABILITIES
        if item not in capability_ids
    ]
    missing_acceptance_tests = [
        item
        for item in DOCTOR_REQUIRED_CONNECT_ACCEPTANCE_TESTS
        if item not in acceptance_ids
    ]
    missing_acceptance_capabilities = [
        item
        for item in DOCTOR_REQUIRED_CONNECT_CAPABILITIES
        if item not in acceptance_capabilities
    ]
    missing_token_lifecycle = [
        item
        for item in DOCTOR_REQUIRED_CONNECT_TOKEN_LIFECYCLE
        if item not in token_lifecycle_ids
    ]
    missing_runtime_auth = [
        item
        for item in DOCTOR_REQUIRED_CONNECT_RUNTIME_AUTH
        if item not in runtime_auth_ids
    ]
    invalid_acceptance_tests: list[dict[str, Any]] = []
    for item in acceptance_tests:
        if not isinstance(item, dict):
            invalid_acceptance_tests.append(
                {"id": None, "problems": ["acceptance_test_not_object"]}
            )
            continue
        problems: list[str] = []
        if item.get("id") not in DOCTOR_REQUIRED_CONNECT_ACCEPTANCE_TESTS:
            problems.append("unknown_id")
        if item.get("capability") not in DOCTOR_REQUIRED_CONNECT_CAPABILITIES:
            problems.append("unknown_capability")
        if not isinstance(item.get("source_fields"), list) or not item.get(
            "source_fields"
        ):
            problems.append("missing_source_fields")
        if not isinstance(item.get("expected"), str) or not item.get("expected"):
            problems.append("missing_expected")
        if problems:
            invalid_acceptance_tests.append(
                {
                    "id": item.get("id"),
                    "capability": item.get("capability"),
                    "problems": problems,
                }
            )

    api_device_code = api_contract.get("device_code")
    api_token_lifecycle = api_contract.get("token_lifecycle")
    invalid_api_contract: list[str] = []
    if not isinstance(api_device_code, list) or not api_device_code:
        invalid_api_contract.append("device_code")
    if not isinstance(api_token_lifecycle, list) or not api_token_lifecycle:
        invalid_api_contract.append("token_lifecycle")

    common_details: dict[str, Any] = {
        "schema_version": 1,
        "capability_ids": capability_ids,
        "required_capabilities": list(DOCTOR_REQUIRED_CONNECT_CAPABILITIES),
        "missing_capabilities": missing_capabilities,
        "site_capability_status": capability_status,
        "acceptance_test_ids": acceptance_ids,
        "required_acceptance_tests": list(DOCTOR_REQUIRED_CONNECT_ACCEPTANCE_TESTS),
        "missing_acceptance_tests": missing_acceptance_tests,
        "missing_acceptance_capabilities": missing_acceptance_capabilities,
        "invalid_acceptance_tests": invalid_acceptance_tests,
        "token_lifecycle_ids": token_lifecycle_ids,
        "missing_token_lifecycle": missing_token_lifecycle,
        "runtime_auth_ids": runtime_auth_ids,
        "missing_runtime_auth": missing_runtime_auth,
        "invalid_api_contract": invalid_api_contract,
    }

    if (
        missing_capabilities
        or missing_acceptance_tests
        or missing_acceptance_capabilities
        or invalid_acceptance_tests
        or missing_token_lifecycle
        or missing_runtime_auth
        or invalid_api_contract
    ):
        return _doctor_check(
            "connect_from_codex_contract",
            "warn",
            "Connect from Codex browser-site contract is missing required fields.",
            fix=_doctor_fix(
                "repair_connect_from_codex_contract",
                commands=[
                    "browser-cli auth connect-requirements",
                    "browser-cli auth scopes --include-site-contract",
                    "browser-cli commands --workflow connect_from_codex_site_requirements",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Keep auth connect-requirements, auth scopes --include-site-contract, docs/connect-from-codex.md, and docs/json-contract.md in sync.",
                    "browser.lexmount.cn should implement every browser_site_acceptance_tests item before marking Connect from Codex available.",
                ],
                connect_from_codex=_doctor_connect_from_codex_fix(),
            ),
            **common_details,
        )

    return _doctor_check(
        "connect_from_codex_contract",
        "pass",
        "Connect from Codex browser-site contract includes the expected capabilities and acceptance tests.",
        **common_details,
    )


def _nearest_existing_parent(path: Path) -> Path | None:
    current = path.parent
    while not current.exists() and current != current.parent:
        current = current.parent
    return current if current.exists() else None


def _doctor_context_registry_fix() -> dict[str, Any]:
    return _doctor_fix(
        "repair_context_registry",
        env=[CONTEXT_REGISTRY_FILE_ENV],
        commands=[
            "browser-cli doctor --json",
            "browser-cli commands --workflow persistent_login_state",
            'browser-cli context pick --metadata-json \'{"purpose":"codex-login"}\' --selection newest --create-if-missing --dry-run',
        ],
        guidance=[
            "Set LEXMOUNT_BROWSER_CONTEXT_REGISTRY_FILE to a writable JSON file for isolated agent workspaces.",
            "Delete or repair the local context registry if it contains invalid JSON.",
            "Use context pick --dry-run before creating a session that relies on persistent login state.",
        ],
    )


def _doctor_context_registry_check() -> dict[str, Any]:
    path, path_source = _context_registry_path()
    nearest_parent = _nearest_existing_parent(path)
    parent = path.parent
    parent_exists = parent.exists()
    parent_creatable = bool(
        nearest_parent and os.access(nearest_parent, os.W_OK | os.X_OK)
    )
    path_exists = path.exists()
    path_is_file = path.is_file() if path_exists else None
    file_readable = os.access(path, os.R_OK) if path_exists else None
    file_writable = os.access(path, os.W_OK) if path_exists else None
    writable = bool(file_writable if path_exists else parent_creatable)
    scope = _context_registry_scope()
    common_details: dict[str, Any] = {
        "path": str(path),
        "path_source": path_source,
        "env_var": CONTEXT_REGISTRY_FILE_ENV,
        "exists": path_exists,
        "parent": str(parent),
        "parent_exists": parent_exists,
        "nearest_existing_parent": str(nearest_parent) if nearest_parent else None,
        "parent_creatable": parent_creatable,
        "readable": file_readable,
        "writable": writable,
        "project_id_present": bool(scope["project_id"]),
        "base_url": scope["base_url"],
        "stores_metadata_values": True,
        "metadata_values_redacted": True,
    }

    if not path_exists:
        if writable:
            return _doctor_check(
                "context_registry",
                "pass",
                "Context registry does not exist yet and can be created when persistent context metadata is recorded.",
                schema_version=1,
                context_count=0,
                scoped_context_count=0,
                metadata_context_count=0,
                **common_details,
            )
        return _doctor_check(
            "context_registry",
            "warn",
            "Context registry does not exist and its parent path is not writable.",
            error="registry_parent_not_writable",
            schema_version=1,
            context_count=0,
            scoped_context_count=0,
            metadata_context_count=0,
            fix=_doctor_context_registry_fix(),
            **common_details,
        )

    if not path_is_file:
        return _doctor_check(
            "context_registry",
            "warn",
            "Context registry path exists but is not a file.",
            error="registry_path_not_file",
            fix=_doctor_context_registry_fix(),
            **common_details,
        )

    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except json.JSONDecodeError as exc:
        return _doctor_check(
            "context_registry",
            "warn",
            "Context registry contains invalid JSON.",
            error="registry_invalid_json",
            line=exc.lineno,
            column=exc.colno,
            fix=_doctor_context_registry_fix(),
            **common_details,
        )
    except OSError as exc:
        return _doctor_check(
            "context_registry",
            "warn",
            "Context registry could not be read.",
            error=exc.__class__.__name__,
            fix=_doctor_context_registry_fix(),
            **common_details,
        )

    if not isinstance(data, dict):
        return _doctor_check(
            "context_registry",
            "warn",
            "Context registry JSON must be an object.",
            error="registry_not_object",
            fix=_doctor_context_registry_fix(),
            **common_details,
        )

    contexts = data.get("contexts")
    if contexts is None:
        contexts = {}
    if not isinstance(contexts, dict):
        return _doctor_check(
            "context_registry",
            "warn",
            "Context registry contexts field must be an object.",
            error="registry_contexts_not_object",
            schema_version=data.get("version"),
            fix=_doctor_context_registry_fix(),
            **common_details,
        )

    scoped_context_count = 0
    metadata_context_count = 0
    for entry in contexts.values():
        if not isinstance(entry, dict):
            continue
        metadata = entry.get("metadata")
        if isinstance(metadata, dict) and metadata:
            metadata_context_count += 1
        if (
            entry.get("project_id") == scope["project_id"]
            and entry.get("base_url") == scope["base_url"]
        ):
            scoped_context_count += 1

    if not writable:
        return _doctor_check(
            "context_registry",
            "warn",
            "Context registry is readable but not writable.",
            error="registry_not_writable",
            schema_version=data.get("version"),
            context_count=len(contexts),
            scoped_context_count=scoped_context_count,
            metadata_context_count=metadata_context_count,
            fix=_doctor_context_registry_fix(),
            **common_details,
        )

    return _doctor_check(
        "context_registry",
        "pass",
        "Context registry is readable and writable for persistent context metadata.",
        schema_version=data.get("version"),
        context_count=len(contexts),
        scoped_context_count=scoped_context_count,
        metadata_context_count=metadata_context_count,
        **common_details,
    )


def _doctor_agent_prompt_check() -> dict[str, Any]:
    metadata = _agent_prompt_metadata().get("openai", {})
    package_resource = metadata.get("package_resource")
    try:
        content = _read_agent_prompt_metadata_content("openai")
    except Exception as exc:
        return _doctor_check(
            "agent_prompt",
            "warn",
            "Packaged agent prompt metadata could not be read.",
            error=exc.__class__.__name__,
            package_resource=package_resource,
            fix=_doctor_fix(
                "repair_packaged_agent_prompt",
                commands=[
                    "browser-cli doctor --json",
                    "browser-cli commands --workflows-only",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "The Codex Skill relies on packaged agent prompt metadata for install-time defaults.",
                    "Reinstall browser-cli if packaged agent metadata is unavailable.",
                ],
            ),
        )

    display_name = _quoted_yaml_field(content, "display_name")
    short_description = _quoted_yaml_field(content, "short_description")
    default_prompt = _quoted_yaml_field(content, "default_prompt")
    missing_fields = [
        field
        for field, value in (
            ("display_name", display_name),
            ("short_description", short_description),
            ("default_prompt", default_prompt),
        )
        if not value
    ]
    missing_patterns = [
        str(pattern)
        for pattern in metadata.get("grep_patterns", [])
        if not default_prompt or str(pattern) not in default_prompt
    ]
    mismatched_fields = []
    if display_name != metadata.get("expected_display_name"):
        mismatched_fields.append("display_name")
    if short_description != metadata.get("expected_short_description"):
        mismatched_fields.append("short_description")

    common_details: dict[str, Any] = {
        "metadata_id": "openai",
        "path": metadata.get("path"),
        "package_resource": package_resource,
        "format": metadata.get("format"),
        "content_length": len(content),
        "display_name": display_name,
        "short_description": short_description,
        "default_prompt_present": bool(default_prompt),
        "required_pattern_count": len(metadata.get("grep_patterns", [])),
        "missing_fields": missing_fields,
        "missing_patterns": missing_patterns,
        "mismatched_fields": mismatched_fields,
    }

    if missing_fields or missing_patterns or mismatched_fields:
        return _doctor_check(
            "agent_prompt",
            "warn",
            "Packaged agent prompt metadata is missing required fields or prompt guidance.",
            fix=_doctor_fix(
                "repair_packaged_agent_prompt",
                commands=[
                    "browser-cli doctor --json",
                    "browser-cli commands --workflows-only",
                    "browser-cli commands --workflow setup_and_verify",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Agent prompt metadata should point Codex to doctor, workflow discovery, packaged examples, and safe credential handling.",
                    "Keep agents/openai.yaml and the packaged browser_cli.agent_metadata copy in sync.",
                ],
            ),
            **common_details,
        )

    return _doctor_check(
        "agent_prompt",
        "pass",
        "Packaged agent prompt metadata includes the expected Codex setup guidance.",
        **common_details,
    )


def _doctor_agent_skill_resources_check() -> dict[str, Any]:
    resource_items, package_errors = _packaged_skill_resource_items()
    checked_resources: list[dict[str, Any]] = []
    missing_patterns: list[str] = []
    skill_content = ""
    for item in resource_items:
        resource_payload = {
            "path": item["path"],
            "package_resource": item["package_resource"],
            "content_length": len(str(item["content"])),
            "sha256": item["sha256"],
        }
        if item["path"] == "SKILL.md":
            skill_content = str(item["content"])
        checked_resources.append(resource_payload)

    if skill_content:
        missing_patterns = [
            pattern
            for pattern in DOCTOR_REQUIRED_SKILL_PATTERNS
            if pattern not in skill_content
        ]
    elif not package_errors:
        missing_patterns = list(DOCTOR_REQUIRED_SKILL_PATTERNS)

    common_details = {
        "resource_count": len(resource_items),
        "expected_resource_count": len(_packaged_skill_resources()),
        "checked_resources": checked_resources,
        "package_errors": package_errors,
        "required_patterns": list(DOCTOR_REQUIRED_SKILL_PATTERNS),
        "missing_patterns": missing_patterns,
        "status_command": "browser-cli skill status",
        "install_command": "browser-cli skill install",
        "force_install_command": "browser-cli skill install --force",
    }

    if package_errors or missing_patterns:
        return _doctor_check(
            "agent_skill_resources",
            "warn",
            "Packaged Codex Skill resources are missing or stale.",
            fix=_doctor_fix(
                "repair_packaged_agent_skill_resources",
                commands=[
                    "browser-cli skill status",
                    "browser-cli skill install --force",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Packaged Skill resources should include SKILL.md, agents/openai.yaml, and references.",
                    "Keep root SKILL.md and browser_cli.agent_skill:SKILL.md in sync.",
                    "Run skill install to refresh a local Codex Skill directory.",
                ],
            ),
            **common_details,
        )

    return _doctor_check(
        "agent_skill_resources",
        "pass",
        "Packaged Codex Skill resources are installable.",
        **common_details,
    )


def _doctor_agent_references_check() -> dict[str, Any]:
    try:
        references = _agent_references()
    except Exception as exc:
        return _doctor_check(
            "agent_references",
            "warn",
            "Agent reference metadata could not be built.",
            error=exc.__class__.__name__,
            required_references=list(DOCTOR_REQUIRED_REFERENCES),
            fix=_doctor_fix(
                "verify_agent_reference_metadata",
                commands=[
                    "browser-cli reference list",
                    "browser-cli commands --workflows-only",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "The Codex Skill relies on packaged references before choosing custom JavaScript.",
                    "Upgrade or reinstall browser-cli if agent reference metadata is unavailable.",
                ],
            ),
        )

    missing_references = [
        reference_id
        for reference_id in DOCTOR_REQUIRED_REFERENCES
        if reference_id not in references
    ]
    checked_references: list[dict[str, Any]] = []
    invalid_references: list[dict[str, Any]] = []

    for reference_id in DOCTOR_REQUIRED_REFERENCES:
        reference = references.get(reference_id)
        if not isinstance(reference, dict):
            continue
        item: dict[str, Any] = {
            "id": reference_id,
            "path": reference.get("path"),
            "package_resource": reference.get("package_resource"),
            "content_command": reference.get("content_command"),
        }
        try:
            content = _read_agent_reference_content(reference_id)
        except Exception as exc:
            item.update(
                {
                    "status": "unavailable",
                    "error": exc.__class__.__name__,
                }
            )
            invalid_references.append(item)
            checked_references.append(item)
            continue

        missing_patterns = [
            str(pattern)
            for pattern in reference.get("grep_patterns", [])
            if str(pattern) not in content
        ]
        item.update(
            {
                "status": "pass"
                if content.strip() and not missing_patterns
                else "invalid",
                "content_length": len(content),
                "missing_patterns": missing_patterns,
            }
        )
        if item["status"] != "pass":
            invalid_references.append(item)
        checked_references.append(item)

    if missing_references or invalid_references:
        return _doctor_check(
            "agent_references",
            "warn",
            "Packaged agent references are missing or invalid.",
            required_references=list(DOCTOR_REQUIRED_REFERENCES),
            reference_count=len(references),
            missing_required_references=missing_references,
            invalid_references=invalid_references,
            checked_references=checked_references,
            fix=_doctor_fix(
                "repair_packaged_agent_references",
                commands=[
                    "browser-cli reference list",
                    *[
                        command
                        for reference_id in DOCTOR_REQUIRED_REFERENCES
                        for command in (
                            f"browser-cli reference get --id {reference_id} --metadata-only",
                            f"browser-cli reference get --id {reference_id}",
                        )
                    ],
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Packaged references should be readable from an installed CLI.",
                    "Reinstall browser-cli if reference get cannot load required references.",
                ],
            ),
        )

    return _doctor_check(
        "agent_references",
        "pass",
        "Packaged agent references are readable.",
        required_references=list(DOCTOR_REQUIRED_REFERENCES),
        reference_count=len(references),
        missing_required_references=[],
        invalid_references=[],
        checked_references=checked_references,
    )


def _validate_case_example_content(content: str) -> list[str]:
    try:
        import yaml
    except Exception as exc:
        return [f"PyYAML unavailable: {exc.__class__.__name__}"]

    try:
        spec = yaml.safe_load(content)
    except Exception as exc:
        return [f"Invalid YAML: {exc}"]
    if not isinstance(spec, dict):
        return ["Case example root must be an object."]
    return _validate_browser_cli_case_spec(spec)


def _doctor_agent_examples_check() -> dict[str, Any]:
    try:
        examples = _agent_examples()
    except Exception as exc:
        return _doctor_check(
            "agent_examples",
            "warn",
            "Agent example metadata could not be built.",
            error=exc.__class__.__name__,
            required_examples=list(DOCTOR_REQUIRED_EXAMPLES),
            fix=_doctor_fix(
                "verify_agent_example_metadata",
                commands=[
                    "browser-cli example list",
                    "browser-cli commands --workflows-only",
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "The Codex Skill relies on packaged examples for repeatable browser tasks.",
                    "Upgrade or reinstall browser-cli if agent example metadata is unavailable.",
                ],
            ),
        )

    missing_examples = [
        example_id
        for example_id in DOCTOR_REQUIRED_EXAMPLES
        if example_id not in examples
    ]
    checked_examples: list[dict[str, Any]] = []
    invalid_examples: list[dict[str, Any]] = []

    for example_id in DOCTOR_REQUIRED_EXAMPLES:
        example = examples.get(example_id)
        if not isinstance(example, dict):
            continue
        item: dict[str, Any] = {
            "id": example_id,
            "path": example.get("path"),
            "package_resource": example.get("package_resource"),
            "content_command": example.get("content_command"),
            "format": example.get("format"),
        }
        try:
            content = _read_agent_example_content(example_id)
        except Exception as exc:
            item.update(
                {
                    "status": "unavailable",
                    "error": exc.__class__.__name__,
                }
            )
            invalid_examples.append(item)
            checked_examples.append(item)
            continue

        missing_patterns = [
            str(pattern)
            for pattern in example.get("grep_patterns", [])
            if str(pattern) not in content
        ]
        case_errors: list[str] = []
        if example.get("case_file"):
            case_errors = _validate_case_example_content(content)
        item.update(
            {
                "status": "pass"
                if content.strip() and not missing_patterns and not case_errors
                else "invalid",
                "content_length": len(content),
                "missing_patterns": missing_patterns,
            }
        )
        if example.get("case_file"):
            item.update(
                {
                    "case_valid": not case_errors,
                    "case_errors": case_errors,
                }
            )
        if item["status"] != "pass":
            invalid_examples.append(item)
        checked_examples.append(item)

    if missing_examples or invalid_examples:
        return _doctor_check(
            "agent_examples",
            "warn",
            "Packaged agent examples are missing, unreadable, or invalid.",
            required_examples=list(DOCTOR_REQUIRED_EXAMPLES),
            example_count=len(examples),
            missing_required_examples=missing_examples,
            invalid_examples=invalid_examples,
            checked_examples=checked_examples,
            fix=_doctor_fix(
                "repair_packaged_agent_examples",
                commands=[
                    "browser-cli example list",
                    "browser-cli example get --id agent_playbook --metadata-only",
                    *[
                        f"browser-cli example get --id {example_id}"
                        for example_id in DOCTOR_REQUIRED_EXAMPLES
                        if example_id != "agent_playbook"
                    ],
                    "uv tool install --force git+https://github.com/lexmount/browser-cli.git",
                ],
                guidance=[
                    "Packaged examples should be readable from an installed CLI.",
                    "Reinstall browser-cli if example get cannot load playbooks or case files.",
                    "Run `browser-cli case validate --file <case.yaml>` on copied case examples before running them.",
                ],
            ),
        )

    return _doctor_check(
        "agent_examples",
        "pass",
        "Packaged agent examples are readable and case examples validate.",
        required_examples=list(DOCTOR_REQUIRED_EXAMPLES),
        example_count=len(examples),
        missing_required_examples=[],
        invalid_examples=[],
        checked_examples=checked_examples,
    )


def _doctor_error_name(exc: Exception) -> str:
    info = getattr(exc, "lexmount_error_info", None)
    if isinstance(info, LexmountErrorInfo):
        error = info.payload().get("error")
        if error:
            return str(error)
    return exc.__class__.__name__


def _doctor_session_id(payload: dict[str, Any]) -> str | None:
    session_id = payload.get("session_id")
    if session_id:
        return str(session_id)
    session = payload.get("session")
    if isinstance(session, dict) and session.get("session_id"):
        return str(session["session_id"])
    return None


def _doctor_smoke_session_check(admin: Any) -> dict[str, Any]:
    session_id: str | None = None
    try:
        result = admin.create_session(
            context_id=None,
            create_context=False,
            context_mode="read_write",
            browser_mode="normal",
            metadata={"purpose": "browser-cli-doctor-smoke"},
        )
    except Exception as exc:
        return _doctor_check(
            "browser_smoke_session",
            "fail",
            _mask_sensitive_text(str(exc)),
            stage="create",
            created=False,
            closed=False,
            error=_doctor_error_name(exc),
            fix=_doctor_fix(
                "verify_browser_session_creation",
                commands=[
                    "browser-cli auth status",
                    "browser-cli doctor --smoke-session",
                ],
                guidance=[
                    "Confirm the API key can create browser sessions for this project.",
                    "Check project session quotas and key scopes in browser.lexmount.cn.",
                ],
            ),
        )

    payload = _model_payload(result)
    session_id = _doctor_session_id(payload)
    if not session_id:
        return _doctor_check(
            "browser_smoke_session",
            "fail",
            "Smoke session was created, but the response did not include a session_id to close.",
            stage="response",
            created=True,
            closed=False,
            session=_sanitize_failure_value(payload.get("session")),
            fix=_doctor_fix(
                "verify_browser_session_response",
                commands=[
                    "browser-cli doctor --smoke-session",
                ],
                guidance=[
                    "Confirm the browser session API response includes session.session_id.",
                ],
            ),
        )

    try:
        admin.close_session(session_id)
    except Exception as exc:
        return _doctor_check(
            "browser_smoke_session",
            "fail",
            f"Smoke session was created but could not be closed automatically: {_mask_sensitive_text(str(exc))}",
            stage="close",
            created=True,
            closed=False,
            session_id=session_id,
            error=_doctor_error_name(exc),
            fix=_doctor_fix(
                "close_smoke_session",
                commands=[
                    f"browser-cli session close --session-id {session_id}",
                    "browser-cli doctor --smoke-session",
                ],
                guidance=[
                    "Close the temporary smoke-test session manually, then rerun doctor.",
                ],
            ),
        )

    return _doctor_check(
        "browser_smoke_session",
        "pass",
        "Temporary browser session can be created and closed",
        stage="closed",
        created=True,
        closed=True,
        session_id=session_id,
    )


def _normalize_status(value: Any) -> str | None:
    if value is None:
        return None
    normalized = re.sub(r"[\s\-]+", "_", str(value).strip().lower())
    normalized = re.sub(r"_+", "_", normalized).strip("_")
    return normalized or None


def _context_reuse_state(context: dict[str, Any]) -> dict[str, Any]:
    status = _normalize_status(context.get("status"))
    if status in CONTEXT_REUSABLE_STATUSES:
        return {
            "status": context.get("status"),
            "normalized_status": status,
            "availability": "available",
            "reusable": True,
            "locked": False,
            "reason": "status_reusable",
        }
    if status in CONTEXT_LOCKED_STATUSES:
        return {
            "status": context.get("status"),
            "normalized_status": status,
            "availability": "locked",
            "reusable": False,
            "locked": True,
            "reason": "status_locked",
        }
    if status in CONTEXT_UNAVAILABLE_STATUSES:
        return {
            "status": context.get("status"),
            "normalized_status": status,
            "availability": "unavailable",
            "reusable": False,
            "locked": False,
            "reason": "status_unavailable",
        }
    if status is None:
        return {
            "status": None,
            "normalized_status": None,
            "availability": "unknown",
            "reusable": False,
            "locked": False,
            "reason": "status_missing",
        }
    return {
        "status": context.get("status"),
        "normalized_status": status,
        "availability": "unknown",
        "reusable": False,
        "locked": False,
        "reason": "status_not_reusable",
    }


def _metadata_matches(
    metadata: dict[str, Any] | None,
    expected: dict[str, Any],
) -> bool:
    if not expected:
        return True
    if not isinstance(metadata, dict):
        return False
    return all(metadata.get(key) == value for key, value in expected.items())


def _context_registry_path(raw_path: str | None = None) -> tuple[Path, str]:
    if raw_path:
        return Path(raw_path).expanduser(), "argument"
    env_path = os.environ.get(CONTEXT_REGISTRY_FILE_ENV)
    if env_path:
        return Path(env_path).expanduser(), "env"
    return (
        Path.home() / ".config" / "lexmount" / "browser-cli" / "context-registry.json",
        "default",
    )


def _context_registry_scope() -> dict[str, str | None]:
    return {
        "project_id": os.environ.get("LEXMOUNT_PROJECT_ID"),
        "base_url": os.environ.get("LEXMOUNT_BASE_URL") or DEFAULT_LEXMOUNT_BASE_URL,
    }


def _read_context_registry() -> dict[str, Any]:
    path, _path_source = _context_registry_path()
    if not path.exists():
        return {"version": 1, "contexts": {}}
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return {"version": 1, "contexts": {}}
    if not isinstance(data, dict):
        return {"version": 1, "contexts": {}}
    contexts = data.get("contexts")
    if not isinstance(contexts, dict):
        contexts = {}
    return {"version": 1, "contexts": contexts}


def _write_context_registry(registry: dict[str, Any]) -> None:
    path, _path_source = _context_registry_path()
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(
        json.dumps(registry, ensure_ascii=False, indent=2, sort_keys=True),
        encoding="utf-8",
    )
    if os.name == "posix":
        path.chmod(0o600)


def _record_context_metadata(context: dict[str, Any]) -> None:
    context_id = context.get("context_id") or context.get("id")
    metadata = context.get("metadata")
    if not context_id or not isinstance(metadata, dict) or not metadata:
        return
    registry = _read_context_registry()
    contexts = registry.setdefault("contexts", {})
    contexts[str(context_id)] = {
        "context_id": str(context_id),
        "metadata": metadata,
        **_context_registry_scope(),
        "updated_at": datetime.now(timezone.utc).isoformat(),
    }
    _write_context_registry(registry)


def _forget_context_metadata(context_id: str) -> None:
    registry = _read_context_registry()
    contexts = registry.get("contexts")
    if not isinstance(contexts, dict) or context_id not in contexts:
        return
    del contexts[context_id]
    _write_context_registry(registry)


def _registry_metadata_for_context(
    context: dict[str, Any],
    registry: dict[str, Any],
) -> dict[str, Any] | None:
    context_id = context.get("context_id") or context.get("id")
    if not context_id:
        return None
    contexts = registry.get("contexts")
    if not isinstance(contexts, dict):
        return None
    entry = contexts.get(str(context_id))
    if not isinstance(entry, dict):
        return None
    scope = _context_registry_scope()
    if entry.get("project_id") != scope["project_id"]:
        return None
    if entry.get("base_url") != scope["base_url"]:
        return None
    metadata = entry.get("metadata")
    if not isinstance(metadata, dict) or not metadata:
        return None
    return metadata


def _effective_context_metadata(
    context: dict[str, Any],
    registry: dict[str, Any],
) -> tuple[Any, str]:
    metadata = context.get("metadata")
    if isinstance(metadata, dict) and metadata:
        return metadata, "api"
    registry_metadata = _registry_metadata_for_context(context, registry)
    if registry_metadata is not None:
        return registry_metadata, "local_registry"
    if isinstance(metadata, dict):
        return metadata, "api_empty"
    return metadata, "missing"


def _metadata_match_diagnostics(
    metadata: Any,
    expected: dict[str, Any],
    *,
    metadata_source: str,
) -> dict[str, Any]:
    if isinstance(metadata, dict):
        metadata_keys = sorted(str(key) for key in metadata)
    else:
        metadata_keys = []

    expected_keys = sorted(expected, key=str)
    filter_keys = [str(key) for key in expected_keys]
    matched_keys: list[str] = []
    missing_keys: list[str] = []
    different_keys: list[str] = []

    for key in expected_keys:
        key_name = str(key)
        if not isinstance(metadata, dict) or key not in metadata:
            missing_keys.append(key_name)
        elif metadata.get(key) == expected.get(key):
            matched_keys.append(key_name)
        else:
            different_keys.append(key_name)

    return {
        "metadata_present": isinstance(metadata, dict),
        "metadata_source": metadata_source,
        "metadata_keys": metadata_keys,
        "filter_keys": filter_keys,
        "matched_keys": matched_keys,
        "missing_keys": missing_keys,
        "different_keys": different_keys,
        "value_redacted": True,
    }


def _context_pick_candidate(
    context: dict[str, Any],
    metadata_filter: dict[str, Any],
    registry: dict[str, Any],
) -> dict[str, Any]:
    reuse = _context_reuse_state(context)
    metadata, metadata_source = _effective_context_metadata(context, registry)
    metadata_match = _metadata_matches(metadata, metadata_filter)
    metadata_diagnostics = _metadata_match_diagnostics(
        metadata,
        metadata_filter,
        metadata_source=metadata_source,
    )
    return {
        "context_id": context.get("context_id"),
        "status": context.get("status"),
        "normalized_status": reuse["normalized_status"],
        "availability": reuse["availability"],
        "metadata_match": metadata_match,
        "metadata_diagnostics": metadata_diagnostics,
        "reusable": reuse["reusable"],
        "locked": reuse["locked"],
        "reason": reuse["reason"] if metadata_match else "metadata_mismatch",
    }


def _parse_context_timestamp(value: Any) -> float | None:
    if value is None:
        return None
    if isinstance(value, bool):
        return None
    if isinstance(value, (int, float)):
        return float(value)
    text = str(value).strip()
    if not text:
        return None
    if text.isdigit():
        try:
            return float(text)
        except ValueError:
            return None
    normalized = text[:-1] + "+00:00" if text.endswith("Z") else text
    try:
        parsed = datetime.fromisoformat(normalized)
    except ValueError:
        return None
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
    return parsed.timestamp()


def _context_selection_timestamp(context: dict[str, Any]) -> float | None:
    for field in CONTEXT_SELECTION_TIMESTAMP_FIELDS:
        parsed = _parse_context_timestamp(context.get(field))
        if parsed is not None:
            return parsed
    return None


def _select_reusable_context(
    contexts: list[dict[str, Any]],
    candidates: list[dict[str, Any]],
    *,
    selection_strategy: str,
) -> dict[str, Any] | None:
    reusable_pairs = [
        (index, context)
        for index, (context, candidate) in enumerate(zip(contexts, candidates))
        if candidate.get("metadata_match") and candidate.get("reusable")
    ]
    if not reusable_pairs:
        return None
    if selection_strategy == "last":
        return reusable_pairs[-1][1]
    if selection_strategy in {"newest", "oldest"}:
        timestamped = [
            (index, context, timestamp)
            for index, context in reusable_pairs
            if (timestamp := _context_selection_timestamp(context)) is not None
        ]
        if not timestamped:
            return (
                reusable_pairs[-1][1]
                if selection_strategy == "newest"
                else reusable_pairs[0][1]
            )
        return sorted(
            timestamped,
            key=lambda pair: (pair[2], pair[0]),
            reverse=selection_strategy == "newest",
        )[0][1]
    return reusable_pairs[0][1]


def _context_selection_decision(
    candidates: list[dict[str, Any]],
    *,
    selected_context_id: Any = None,
    created: bool = False,
    create_if_missing: bool = False,
    dry_run: bool = False,
) -> tuple[str, str]:
    if selected_context_id is not None:
        if created:
            return "use_created_context", "created_context_selected"
        return "use_selected_context", "reusable_context_selected"

    metadata_matches = [
        candidate for candidate in candidates if candidate.get("metadata_match") is True
    ]
    locked_matches = [
        candidate for candidate in metadata_matches if candidate.get("locked") is True
    ]
    if dry_run and create_if_missing:
        return "rerun_without_dry_run_to_create", "dry_run_create_if_missing"
    if locked_matches:
        return "wait_or_choose_different_context", "locked_context_matches"
    if candidates and not metadata_matches:
        return "adjust_metadata_filter", "no_metadata_matches"
    if create_if_missing:
        return "create_context", "create_if_missing"
    return "rerun_with_create_if_missing", "no_reusable_context"


def _context_selection_summary(
    candidates: list[dict[str, Any]],
    *,
    selected_context_id: Any = None,
    created: bool = False,
    create_if_missing: bool = False,
    dry_run: bool = False,
) -> dict[str, Any]:
    availability_counts = Counter(
        str(candidate.get("availability", "unknown")) for candidate in candidates
    )
    reason_counts = Counter(
        str(candidate.get("reason", "unknown")) for candidate in candidates
    )
    metadata_matches = [
        candidate for candidate in candidates if candidate.get("metadata_match") is True
    ]
    reusable_matches = [
        candidate for candidate in metadata_matches if candidate.get("reusable") is True
    ]
    locked_matches = [
        candidate for candidate in metadata_matches if candidate.get("locked") is True
    ]
    unavailable_matches = [
        candidate
        for candidate in metadata_matches
        if candidate.get("availability") == "unavailable"
    ]
    unknown_matches = [
        candidate
        for candidate in metadata_matches
        if candidate.get("availability") == "unknown"
    ]
    recommended_next_action, decision_reason = _context_selection_decision(
        candidates,
        selected_context_id=selected_context_id,
        created=created,
        create_if_missing=create_if_missing,
        dry_run=dry_run,
    )
    return {
        "checked": len(candidates),
        "selected_context_id": selected_context_id,
        "recommended_next_action": recommended_next_action,
        "decision_reason": decision_reason,
        "metadata_matches": len(metadata_matches),
        "metadata_mismatches": len(candidates) - len(metadata_matches),
        "reusable_matches": len(reusable_matches),
        "locked_matches": len(locked_matches),
        "unavailable_matches": len(unavailable_matches),
        "unknown_matches": len(unknown_matches),
        "availability_counts": dict(sorted(availability_counts.items())),
        "reason_counts": dict(sorted(reason_counts.items())),
        "create_if_missing": bool(create_if_missing),
        "dry_run": bool(dry_run),
        "would_create": bool(
            dry_run and selected_context_id is None and create_if_missing
        ),
    }


def _select_or_create_context_for_session(
    admin: Any,
    *,
    command: str,
    metadata_filter: dict[str, Any],
    status: str | None,
    limit: int,
    selection_strategy: str,
    create_if_missing: bool,
) -> dict[str, Any]:
    try:
        result = admin.list_contexts(status=status, limit=limit)
    except Exception as exc:
        _failure_from_exception(command, exc)

    payload = _model_payload(result)
    contexts = payload.get("contexts", [])
    if not isinstance(contexts, list):
        contexts = []
    registry = _read_context_registry()
    candidates = [
        _context_pick_candidate(context, metadata_filter, registry)
        for context in contexts
    ]
    selected_context = _select_reusable_context(
        contexts,
        candidates,
        selection_strategy=selection_strategy,
    )

    if selected_context is not None:
        context_id = selected_context.get("context_id")
        reuse = _context_reuse_state(selected_context)
        return {
            "selected": True,
            "created": False,
            "context_id": context_id,
            "context": selected_context,
            "normalized_status": reuse["normalized_status"],
            "availability": reuse["availability"],
            "reusable": reuse["reusable"],
            "locked": reuse["locked"],
            "reuse_reason": reuse["reason"],
            "reuse": reuse,
            "checked": len(contexts),
            "candidates": candidates,
            "selection_strategy": selection_strategy,
            "selection_summary": _context_selection_summary(
                candidates,
                selected_context_id=context_id,
                create_if_missing=create_if_missing,
            ),
            "metadata_filter": metadata_filter,
            "status_filter": status,
            "limit": limit,
        }

    if create_if_missing:
        try:
            context = admin.create_context(metadata=metadata_filter or None)
        except Exception as exc:
            _failure_from_exception(command, exc)
        created_context = _model_payload(context)
        _record_context_metadata(created_context)
        reuse = _context_reuse_state(created_context)
        return {
            "selected": True,
            "created": True,
            "context_id": created_context.get("context_id"),
            "context": created_context,
            "normalized_status": reuse["normalized_status"],
            "availability": reuse["availability"],
            "reusable": reuse["reusable"],
            "locked": reuse["locked"],
            "reuse_reason": reuse["reason"],
            "reuse": reuse,
            "checked": len(contexts),
            "candidates": candidates,
            "selection_strategy": selection_strategy,
            "selection_summary": _context_selection_summary(
                candidates,
                selected_context_id=created_context.get("context_id"),
                created=True,
                create_if_missing=create_if_missing,
            ),
            "metadata_filter": metadata_filter,
            "status_filter": status,
            "limit": limit,
        }

    _failure(
        command,
        "no_available_context",
        "No reusable context matched the requested session context filters.",
        selected=False,
        created=False,
        checked=len(contexts),
        candidates=candidates,
        selection_strategy=selection_strategy,
        selection_summary=_context_selection_summary(
            candidates,
            create_if_missing=create_if_missing,
        ),
        metadata_filter=metadata_filter,
        status_filter=status,
        limit=limit,
    )


def _env_value_status(
    name: str,
    *,
    secret: bool = False,
    default: str | None = None,
) -> dict[str, Any]:
    value = os.environ.get(name)
    present = bool(value)
    payload: dict[str, Any] = {"present": present}
    if secret:
        payload.update(
            {
                "masked_value": "***" if present else None,
                "length": len(value) if value else 0,
            }
        )
    else:
        payload["value"] = value
    if default is not None:
        payload["default"] = default
        payload["effective_value"] = value or default
        payload["using_default"] = not present
    return payload


def _now_utc() -> datetime:
    return datetime.now(timezone.utc)


def _device_token_credentials_path(raw_path: str | None = None) -> tuple[Path, str]:
    if raw_path:
        return Path(raw_path).expanduser(), "argument"
    env_path = os.environ.get(DEVICE_TOKEN_CREDENTIALS_FILE_ENV)
    if env_path:
        return Path(env_path).expanduser(), "env"
    return (
        Path.home() / ".config" / "lexmount" / "browser-cli" / "credentials.json",
        "default",
    )


def _parse_datetime_utc(value: Any) -> datetime | None:
    if not isinstance(value, str) or not value:
        return None
    normalized = value.replace("Z", "+00:00")
    try:
        parsed = datetime.fromisoformat(normalized)
    except ValueError:
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _device_code_base_url(raw_url: str | None = None) -> tuple[str | None, str]:
    if raw_url:
        return raw_url.rstrip("/"), "argument"
    env_url = os.environ.get(DEVICE_CODE_BASE_URL_ENV)
    if env_url:
        return env_url.rstrip("/"), "env"
    return None, "unset"


def _device_code_endpoint(base_url: str, path: str) -> str:
    return urljoin(f"{base_url.rstrip('/')}/", path.lstrip("/"))


def _codex_connect_base_url(raw_url: str | None = None) -> tuple[str, str]:
    if raw_url:
        return raw_url.rstrip("/"), "argument"
    env_url = os.environ.get(CODEX_CONNECT_BASE_URL_ENV)
    if env_url:
        return env_url.rstrip("/"), "env"
    return LEXMOUNT_CONSOLE_URL, "default"


def _codex_connect_endpoint(base_url: str, path: str) -> str:
    return urljoin(f"{base_url.rstrip('/')}/", path.lstrip("/"))


def _token_lifecycle_base_url(raw_url: str | None = None) -> tuple[str | None, str]:
    if raw_url:
        return raw_url.rstrip("/"), "argument"
    env_url = os.environ.get(TOKEN_LIFECYCLE_BASE_URL_ENV)
    if env_url:
        return env_url.rstrip("/"), "env"
    device_code_env_url = os.environ.get(DEVICE_CODE_BASE_URL_ENV)
    if device_code_env_url:
        return device_code_env_url.rstrip("/"), "device_code_env"
    return None, "unset"


def _token_lifecycle_endpoint(base_url: str, path: str) -> str:
    return urljoin(f"{base_url.rstrip('/')}/", path.lstrip("/"))


def _json_http_post(
    url: str,
    payload: dict[str, Any],
    *,
    timeout_seconds: float,
) -> dict[str, Any]:
    body = json.dumps(payload).encode("utf-8")
    request = Request(
        url,
        data=body,
        headers={
            "Content-Type": "application/json",
            "Accept": "application/json",
        },
        method="POST",
    )
    try:
        with urlopen(request, timeout=timeout_seconds) as response:
            raw_body = response.read()
            status_code = int(getattr(response, "status", 200))
    except HTTPError as exc:
        raw_body = exc.read()
        status_code = int(exc.code)
    except URLError as exc:
        return {
            "ok": False,
            "status_code": None,
            "error": "network_error",
            "message": _mask_sensitive_text(str(exc.reason)),
            "json": {},
        }
    except OSError as exc:
        return {
            "ok": False,
            "status_code": None,
            "error": "network_error",
            "message": _mask_sensitive_text(str(exc)),
            "json": {},
        }

    text = raw_body.decode("utf-8", errors="replace") if raw_body else ""
    try:
        parsed = json.loads(text) if text else {}
    except json.JSONDecodeError as exc:
        return {
            "ok": False,
            "status_code": status_code,
            "error": "invalid_json_response",
            "message": f"Response JSON could not be parsed: {exc}",
            "json": {},
        }
    if not isinstance(parsed, dict):
        return {
            "ok": False,
            "status_code": status_code,
            "error": "invalid_json_response",
            "message": "Response JSON must contain an object.",
            "json": {},
        }
    error = parsed.get("error")
    return {
        "ok": 200 <= status_code < 300 and not error,
        "status_code": status_code,
        "error": str(error) if error else None,
        "message": _mask_sensitive_text(str(parsed.get("message") or "")) or None,
        "json": parsed,
    }


_TOKEN_PAYLOAD_CONTAINER_KEYS = ("token", "device_token", "credential", "credentials")
_TOKEN_PAYLOAD_KEY_ALIASES = {
    "accessToken": "access_token",
    "refreshToken": "refresh_token",
    "expiresAt": "expires_at",
    "expiresIn": "expires_in",
    "projectId": "project_id",
    "apiBaseUrl": "api_base_url",
    "tokenId": "token_id",
    "tokenType": "token_type",
}


def _scope_list(value: Any) -> list[str] | None:
    if isinstance(value, list):
        return [str(scope) for scope in value]
    if isinstance(value, str):
        return [scope for scope in re.split(r"[\s,]+", value.strip()) if scope]
    return None


def _normalize_device_token_payload(token_payload: dict[str, Any]) -> dict[str, Any]:
    normalized = dict(token_payload)
    for source_key, target_key in _TOKEN_PAYLOAD_KEY_ALIASES.items():
        if normalized.get(target_key) in (None, "", []) and source_key in normalized:
            normalized[target_key] = normalized.get(source_key)

    scopes = _scope_list(normalized.get("scopes"))
    if scopes is None:
        scopes = _scope_list(normalized.get("scope"))
    if scopes is not None:
        normalized["scopes"] = scopes
    return normalized


def _extract_token_response_payload(
    response_payload: dict[str, Any],
) -> tuple[dict[str, Any], str, list[str]]:
    inspected_sources = ["json"]
    if isinstance(response_payload.get("access_token"), str) or isinstance(
        response_payload.get("accessToken"), str
    ):
        return (
            _normalize_device_token_payload(response_payload),
            "json",
            inspected_sources,
        )

    for key in _TOKEN_PAYLOAD_CONTAINER_KEYS:
        nested = response_payload.get(key)
        inspected_sources.append(f"json.{key}")
        if not isinstance(nested, dict):
            continue
        if isinstance(nested.get("access_token"), str) or isinstance(
            nested.get("accessToken"), str
        ):
            return (
                _normalize_device_token_payload(nested),
                f"json.{key}",
                inspected_sources,
            )
    return {}, "missing", inspected_sources


def _token_response_summary(token_payload: dict[str, Any]) -> dict[str, Any]:
    scopes = _scope_list(token_payload.get("scopes")) or []
    return {
        "has_access_token": isinstance(token_payload.get("access_token"), str)
        and bool(token_payload.get("access_token")),
        "has_refresh_token": isinstance(token_payload.get("refresh_token"), str)
        and bool(token_payload.get("refresh_token")),
        "has_expires_at": isinstance(token_payload.get("expires_at"), str)
        and bool(token_payload.get("expires_at")),
        "has_expires_in": token_payload.get("expires_in") not in (None, ""),
        "has_project_id": isinstance(token_payload.get("project_id"), str)
        and bool(token_payload.get("project_id")),
        "has_api_base_url": isinstance(token_payload.get("api_base_url"), str)
        and bool(token_payload.get("api_base_url")),
        "has_token_id": token_payload.get("token_id") not in (None, ""),
        "scope_count": len(scopes),
    }


def _device_token_expires_at(token_payload: dict[str, Any]) -> str | None:
    expires_at = token_payload.get("expires_at")
    if isinstance(expires_at, str) and expires_at:
        return expires_at
    expires_in = token_payload.get("expires_in")
    if isinstance(expires_in, str) and expires_in.isdigit():
        expires_in = int(expires_in)
    if isinstance(expires_in, int | float):
        return datetime.fromtimestamp(
            _now_utc().timestamp() + float(expires_in),
            tz=timezone.utc,
        ).isoformat()
    return None


def _write_device_token_credentials(
    token_payload: dict[str, Any],
    *,
    credentials_file: str | None,
    requested_scopes: list[str],
) -> dict[str, Any]:
    path, path_source = _device_token_credentials_path(credentials_file)
    access_token = token_payload.get("access_token")
    if not isinstance(access_token, str) or not access_token:
        return {
            "saved": False,
            "credentials_file": str(path),
            "path_source": path_source,
            "error": "missing_access_token",
        }
    scopes = token_payload.get("scopes")
    if not isinstance(scopes, list):
        scopes = requested_scopes
    data = {
        "kind": "device_token",
        "project_id": token_payload.get("project_id"),
        "api_base_url": token_payload.get("api_base_url") or DEFAULT_LEXMOUNT_BASE_URL,
        "access_token": access_token,
        "refresh_token": token_payload.get("refresh_token"),
        "expires_at": _device_token_expires_at(token_payload),
        "scopes": scopes,
        "token_id": token_payload.get("token_id"),
        "token_type": token_payload.get("token_type") or "Bearer",
        "created_at": _now_utc().isoformat(),
    }
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(
        json.dumps(data, ensure_ascii=False, indent=2, sort_keys=True),
        encoding="utf-8",
    )
    if os.name == "posix":
        path.chmod(0o600)
    return {
        "saved": True,
        "credentials_file": str(path),
        "path_source": path_source,
        "device_token": _local_device_token_status(str(path)),
    }


def _read_device_token_credentials_data(
    raw_path: str | None = None,
) -> tuple[dict[str, Any] | None, dict[str, Any]]:
    path, path_source = _device_token_credentials_path(raw_path)
    meta = {"credentials_file": str(path), "path_source": path_source}
    try:
        raw_data = path.read_text(encoding="utf-8")
    except OSError as exc:
        return None, {
            **meta,
            "error": "read_error",
            "message": _mask_sensitive_text(str(exc)),
        }
    try:
        data = json.loads(raw_data)
    except json.JSONDecodeError as exc:
        return None, {
            **meta,
            "error": "invalid_json",
            "message": f"Invalid credentials JSON: {exc}",
        }
    if not isinstance(data, dict):
        return None, {
            **meta,
            "error": "invalid_credentials",
            "message": "Credentials JSON must contain an object.",
        }
    return data, meta


def _posix_file_mode(path: Path) -> tuple[str | None, bool | None]:
    if os.name != "posix":
        return None, None
    try:
        mode = path.stat().st_mode & 0o777
    except OSError:
        return None, None
    return oct(mode), mode == 0o600


def _local_device_token_status(raw_path: str | None = None) -> dict[str, Any]:
    path, path_source = _device_token_credentials_path(raw_path)
    status: dict[str, Any] = {
        "present": False,
        "path": str(path),
        "path_source": path_source,
        "kind": None,
        "valid": False,
        "expired": None,
        "refresh_needed": None,
        "usable_for_runtime": False,
        "warnings": [],
    }
    if not path.exists():
        return status

    status["present"] = True
    file_mode, file_mode_ok = _posix_file_mode(path)
    if file_mode is not None:
        status["file_mode"] = file_mode
        status["file_mode_ok"] = file_mode_ok
        if file_mode_ok is False:
            status["warnings"].append(
                "Credential file permissions should be 0600 on POSIX systems."
            )

    try:
        raw_data = path.read_text(encoding="utf-8")
    except OSError as exc:
        status.update({"readable": False, "error": "read_error", "message": str(exc)})
        return status

    status["readable"] = True
    try:
        data = json.loads(raw_data)
    except json.JSONDecodeError as exc:
        status.update(
            {
                "error": "invalid_json",
                "message": f"Invalid credentials JSON: {exc}",
            }
        )
        return status
    if not isinstance(data, dict):
        status.update(
            {
                "error": "invalid_credentials",
                "message": "Credentials JSON must contain an object.",
            }
        )
        return status

    kind = data.get("kind")
    access_token = data.get("access_token")
    refresh_token = data.get("refresh_token")
    expires_at = data.get("expires_at")
    expires_at_dt = _parse_datetime_utc(expires_at)
    expires_in_seconds: int | None = None
    expired: bool | None = None
    refresh_needed: bool | None = None
    if expires_at_dt is not None:
        expires_in_seconds = int((expires_at_dt - _now_utc()).total_seconds())
        expired = expires_in_seconds <= 0
        refresh_needed = (
            expired or expires_in_seconds <= DEVICE_TOKEN_REFRESH_WINDOW_SECONDS
        )
    scopes = data.get("scopes")
    if not isinstance(scopes, list):
        scopes = []
    scopes = [str(scope) for scope in scopes]

    status.update(
        {
            "kind": kind,
            "valid": (
                kind == "device_token"
                and isinstance(access_token, str)
                and bool(access_token)
                and isinstance(data.get("project_id"), str)
                and bool(data.get("project_id"))
                and expires_at_dt is not None
                and expired is False
            ),
            "expired": expired,
            "refresh_needed": refresh_needed,
            "expires_at": expires_at,
            "expires_in_seconds": expires_in_seconds,
            "project_id": data.get("project_id"),
            "api_base_url": data.get("api_base_url") or DEFAULT_LEXMOUNT_BASE_URL,
            "scopes": scopes,
            "scope_count": len(scopes),
            "token_id": data.get("token_id"),
            "has_access_token": isinstance(access_token, str) and bool(access_token),
            "has_refresh_token": isinstance(refresh_token, str) and bool(refresh_token),
        }
    )
    if kind != "device_token":
        status["warnings"].append(
            "Credential file does not contain device-token credentials; see api_key_credentials when kind is api_key."
        )
        status["usable_for_runtime"] = False
        status["runtime_note"] = (
            "Device-token bearer auth is not enabled in browser-cli runtime yet; "
            "api_key credentials are reported separately."
        )
        return status
    if not status["has_access_token"]:
        status["warnings"].append("Device token is missing access_token.")
    if not status.get("project_id"):
        status["warnings"].append("Device token is missing project_id.")
    if expires_at_dt is None:
        status["warnings"].append("Device token expires_at is missing or invalid.")
    elif expired:
        status["warnings"].append("Device token is expired.")
    status["usable_for_runtime"] = False
    status["runtime_note"] = (
        "Device-token bearer auth is not enabled in browser-cli runtime yet; "
        "use LEXMOUNT_API_KEY and LEXMOUNT_PROJECT_ID for browser actions."
    )
    return status


def _extract_api_key_response_payload(
    response_payload: dict[str, Any],
) -> tuple[dict[str, Any], str, list[str]]:
    inspected_sources = ["json"]
    candidates: list[tuple[str, dict[str, Any]]] = [("json", response_payload)]
    for key in ("credential", "credentials", "token"):
        inspected_sources.append(f"json.{key}")
        nested = response_payload.get(key)
        if isinstance(nested, dict):
            candidates.append((f"json.{key}", nested))
    env = response_payload.get("env")
    if isinstance(env, dict):
        inspected_sources.append("json.env")
        candidates.append(("json.env", env))

    top_level_scope = response_payload.get("scope") or response_payload.get("scopes")
    for source, candidate in candidates:
        project_id = (
            candidate.get("project_id")
            or candidate.get("projectId")
            or candidate.get("LEXMOUNT_PROJECT_ID")
            or response_payload.get("project_id")
            or response_payload.get("projectId")
        )
        api_key = (
            candidate.get("api_key")
            or candidate.get("apiKey")
            or candidate.get("LEXMOUNT_API_KEY")
            or response_payload.get("api_key")
            or response_payload.get("apiKey")
        )
        if isinstance(project_id, str) and project_id and isinstance(api_key, str) and api_key:
            scopes = _scope_list(candidate.get("scopes"))
            if scopes is None:
                scopes = _scope_list(candidate.get("scope"))
            if scopes is None:
                scopes = _scope_list(top_level_scope)
            return (
                {
                    "project_id": project_id,
                    "api_key": api_key,
                    "api_base_url": candidate.get("api_base_url")
                    or candidate.get("apiBaseUrl")
                    or response_payload.get("api_base_url")
                    or response_payload.get("apiBaseUrl"),
                    "scopes": scopes or [],
                    "expires_at": candidate.get("expires_at")
                    or candidate.get("expiresAt")
                    or response_payload.get("expires_at")
                    or response_payload.get("expiresAt"),
                },
                source,
                inspected_sources,
            )
    return {}, "missing", inspected_sources


def _default_api_base_url_allowed_for_connect_base(connect_base_url: str) -> bool:
    return connect_base_url.rstrip("/") == LEXMOUNT_CONSOLE_URL


def _local_api_key_credentials_status(raw_path: str | None = None) -> dict[str, Any]:
    path, path_source = _device_token_credentials_path(raw_path)
    status: dict[str, Any] = {
        "present": False,
        "path": str(path),
        "path_source": path_source,
        "kind": None,
        "valid": False,
        "usable_for_runtime": False,
        "warnings": [],
    }
    if not path.exists():
        return status

    status["present"] = True
    file_mode, file_mode_ok = _posix_file_mode(path)
    if file_mode is not None:
        status["file_mode"] = file_mode
        status["file_mode_ok"] = file_mode_ok
        if file_mode_ok is False:
            status["warnings"].append(
                "Credential file permissions should be 0600 on POSIX systems."
            )

    try:
        raw_data = path.read_text(encoding="utf-8")
    except OSError as exc:
        status.update(
            {"readable": False, "error": "read_error", "message": str(exc)}
        )
        return status

    status["readable"] = True
    try:
        data = json.loads(raw_data)
    except json.JSONDecodeError as exc:
        status.update(
            {
                "error": "invalid_json",
                "message": f"Invalid credentials JSON: {exc}",
            }
        )
        return status
    if not isinstance(data, dict):
        status.update(
            {
                "error": "invalid_credentials",
                "message": "Credentials JSON must contain an object.",
            }
        )
        return status

    kind = data.get("kind")
    api_key = data.get("api_key")
    project_id = data.get("project_id")
    api_base_url = data.get("api_base_url") or DEFAULT_LEXMOUNT_BASE_URL
    connect_base_url = data.get("connect_base_url")
    scopes = data.get("scopes")
    if not isinstance(scopes, list):
        scopes = _scope_list(data.get("scope")) or []
    scopes = [str(scope) for scope in scopes]
    valid = (
        kind == "api_key"
        and isinstance(api_key, str)
        and bool(api_key)
        and isinstance(project_id, str)
        and bool(project_id)
    )
    status.update(
        {
            "kind": kind,
            "valid": valid,
            "usable_for_runtime": valid,
            "project_id": project_id,
            "api_base_url": api_base_url,
            "connect_base_url": connect_base_url,
            "scopes": scopes,
            "scope_count": len(scopes),
            "has_api_key": isinstance(api_key, str) and bool(api_key),
            "api_key_length": len(api_key) if isinstance(api_key, str) else 0,
            "api_key_redacted": bool(api_key),
            "source": data.get("source"),
            "created_at": data.get("created_at"),
        }
    )
    if kind != "api_key":
        status["warnings"].append("Credential file does not contain api_key credentials.")
    if not status["has_api_key"]:
        status["warnings"].append("API-key credentials are missing api_key.")
    if not project_id:
        status["warnings"].append("API-key credentials are missing project_id.")
    if (
        kind == "api_key"
        and isinstance(connect_base_url, str)
        and not _default_api_base_url_allowed_for_connect_base(connect_base_url)
        and api_base_url == DEFAULT_LEXMOUNT_BASE_URL
    ):
        status["warnings"].append(
            "Credential file was created from a non-default Connect base URL "
            "but points at the default production API base URL; rerun "
            "browser-cli auth login --open after the Connect exchange returns api_base_url."
        )
    return status


def _write_api_key_credentials(
    api_key_payload: dict[str, Any],
    *,
    credentials_file: str | None,
    requested_scopes: list[str],
    connect_base_url: str,
) -> dict[str, Any]:
    path, path_source = _device_token_credentials_path(credentials_file)
    api_key = api_key_payload.get("api_key")
    project_id = api_key_payload.get("project_id")
    if not isinstance(api_key, str) or not api_key:
        return {
            "saved": False,
            "credentials_file": str(path),
            "path_source": path_source,
            "error": "missing_api_key",
        }
    if not isinstance(project_id, str) or not project_id:
        return {
            "saved": False,
            "credentials_file": str(path),
            "path_source": path_source,
            "error": "missing_project_id",
        }
    api_base_url = api_key_payload.get("api_base_url")
    if isinstance(api_base_url, str):
        api_base_url = api_base_url.rstrip("/")
    if not api_base_url:
        if _default_api_base_url_allowed_for_connect_base(connect_base_url):
            api_base_url = DEFAULT_LEXMOUNT_BASE_URL
        else:
            return {
                "saved": False,
                "credentials_file": str(path),
                "path_source": path_source,
                "error": "missing_api_base_url",
                "message": (
                    "Connect exchange response must include api_base_url when "
                    "using a non-default connect_base_url."
                ),
            }
    scopes = api_key_payload.get("scopes")
    if not isinstance(scopes, list):
        scopes = requested_scopes
    data = {
        "kind": "api_key",
        "project_id": project_id,
        "api_base_url": api_base_url,
        "api_key": api_key,
        "scopes": [str(scope) for scope in scopes],
        "expires_at": api_key_payload.get("expires_at"),
        "source": "connect_from_codex",
        "connect_base_url": connect_base_url,
        "created_at": _now_utc().isoformat(),
    }
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(
        json.dumps(data, ensure_ascii=False, indent=2, sort_keys=True),
        encoding="utf-8",
    )
    if os.name == "posix":
        path.chmod(0o600)
    return {
        "saved": True,
        "credentials_file": str(path),
        "path_source": path_source,
        "project_id": project_id,
        "scopes": data["scopes"],
        "scope_count": len(data["scopes"]),
        "has_api_key": True,
        "api_key_length": len(api_key),
        "api_key_redacted": True,
        "api_base_url": api_base_url,
        "api_key_credentials": _local_api_key_credentials_status(str(path)),
    }


def _apply_local_api_key_credentials(
    raw_path: str | None = None,
) -> dict[str, Any]:
    status = _local_api_key_credentials_status(raw_path)
    result: dict[str, Any] = {
        "attempted": True,
        "applied": False,
        "path": status.get("path"),
        "path_source": status.get("path_source"),
        "reason": None,
        "applied_env": [],
    }
    if not status.get("present"):
        result["reason"] = "missing_credentials_file"
        return result
    if not status.get("valid"):
        result["reason"] = status.get("error") or "invalid_api_key_credentials"
        return result

    data, read_meta = _read_device_token_credentials_data(raw_path)
    if data is None:
        result.update(
            {
                "reason": read_meta.get("error") or "read_error",
                "message": read_meta.get("message"),
            }
        )
        return result

    applied_env: list[str] = []
    if not os.environ.get("LEXMOUNT_API_KEY") and isinstance(data.get("api_key"), str):
        os.environ["LEXMOUNT_API_KEY"] = data["api_key"]
        applied_env.append("LEXMOUNT_API_KEY")
    if not os.environ.get("LEXMOUNT_PROJECT_ID") and isinstance(
        data.get("project_id"), str
    ):
        os.environ["LEXMOUNT_PROJECT_ID"] = data["project_id"]
        applied_env.append("LEXMOUNT_PROJECT_ID")
    api_base_url = data.get("api_base_url")
    if not os.environ.get("LEXMOUNT_BASE_URL") and isinstance(api_base_url, str):
        os.environ["LEXMOUNT_BASE_URL"] = api_base_url
        applied_env.append("LEXMOUNT_BASE_URL")

    result["applied"] = bool(applied_env)
    result["reason"] = "applied" if applied_env else "env_already_set"
    result["applied_env"] = applied_env
    return result


def _auth_source(
    *,
    env_configured: bool,
    device_token_status: dict[str, Any],
) -> str:
    if env_configured:
        return "env"
    if device_token_status.get("present"):
        return "device_token"
    return "missing"


def _bearer_runtime_required_support() -> list[dict[str, Any]]:
    return [
        {
            "id": "sdk_accepts_bearer_token",
            "owner": "lexmount-python-sdk",
            "required_change": (
                "Lexmount client accepts scoped bearer/access tokens and sends "
                "Authorization: Bearer without requiring LEXMOUNT_API_KEY."
            ),
        },
        {
            "id": "api_accepts_bearer_token",
            "owner": "Lexmount API",
            "required_change": (
                "Session, context, and action-related APIs accept project-bound "
                "scoped bearer tokens with browser.* permissions."
            ),
        },
        {
            "id": "browser_gateway_accepts_bearer_token",
            "owner": "Lexmount browser gateway",
            "required_change": (
                "Browser CDP websocket connection can be authorized with a "
                "short-lived bearer token instead of an api_key query parameter."
            ),
        },
    ]


def _runtime_auth_status(
    *,
    env_configured: bool,
    missing_env: list[str],
    device_token_status: dict[str, Any],
) -> dict[str, Any]:
    device_token_present = bool(device_token_status.get("present"))
    device_token_valid = bool(device_token_status.get("valid"))
    bearer_runtime_required = _bearer_runtime_required_support()
    if env_configured:
        return {
            "usable": True,
            "source": "env_api_key",
            "browser_actions_auth": "env_api_key",
            "fallback_missing_env": [],
            "device_token_runtime_usable": False,
            "bearer_runtime": {
                "available": False,
                "reason": "bearer_token_runtime_not_enabled",
                "device_token_present": device_token_present,
                "device_token_valid": device_token_valid,
                "required_support": bearer_runtime_required,
            },
            "next_steps": [
                f"Run `{AGENT_DOCTOR_COMMAND}` to verify live API connectivity.",
                "Continue using env API-key credentials for browser actions until bearer-token runtime support lands.",
            ],
        }
    if device_token_present:
        return {
            "usable": False,
            "source": "device_token_pending_runtime",
            "browser_actions_auth": "unavailable",
            "fallback_missing_env": missing_env,
            "device_token_runtime_usable": False,
            "bearer_runtime": {
                "available": False,
                "reason": "bearer_token_runtime_not_enabled",
                "device_token_present": device_token_present,
                "device_token_valid": device_token_valid,
                "required_support": bearer_runtime_required,
            },
            "next_steps": [
                "Use LEXMOUNT_API_KEY and LEXMOUNT_PROJECT_ID for browser actions today.",
                "Track runtime_auth.bearer_runtime.required_support before treating device tokens as browser-action credentials.",
                "Run `browser-cli commands --workflow scoped_token_lifecycle` for refresh, scope, and logout checks.",
            ],
        }
    return {
        "usable": False,
        "source": "missing",
        "browser_actions_auth": "missing_env_api_key",
        "fallback_missing_env": missing_env,
        "device_token_runtime_usable": False,
        "bearer_runtime": {
            "available": False,
            "reason": "no_device_token_metadata",
            "device_token_present": False,
            "device_token_valid": False,
            "required_support": bearer_runtime_required,
        },
        "next_steps": [
            "Run `browser-cli auth login` for Connect from Codex setup guidance.",
            "Set LEXMOUNT_API_KEY and LEXMOUNT_PROJECT_ID in the local shell.",
            f"Run `{AGENT_DOCTOR_COMMAND}` after setting credentials.",
        ],
    }


def _device_token_scope_check(
    device_token_status: dict[str, Any],
    required_scopes: list[str] | None,
) -> dict[str, Any]:
    required = _dedupe_preserving_order(required_scopes or [])
    available = [
        str(scope)
        for scope in device_token_status.get("scopes", [])
        if isinstance(scope, str)
    ]
    missing = [scope for scope in required if scope not in available]
    return {
        "required_scopes": required,
        "available_scopes": available,
        "missing_scopes": missing,
        "satisfied": not missing,
    }


def _auth_next_steps(
    *,
    configured: bool,
    device_token_status: dict[str, Any] | None = None,
) -> list[str]:
    if configured:
        return [
            f"Run `{AGENT_DOCTOR_COMMAND}` to verify live API connectivity.",
            "Create a session with `browser-cli session create`.",
        ]
    if device_token_status and device_token_status.get("present"):
        if device_token_status.get("valid"):
            return [
                "Device token metadata is present, but browser actions still require env API-key credentials until bearer-token support lands.",
                "Set LEXMOUNT_API_KEY and LEXMOUNT_PROJECT_ID in the local shell.",
                f"Run `{AGENT_DOCTOR_COMMAND}` after setting credentials.",
            ]
        return [
            "Local device-token metadata is present but not currently valid.",
            "Run `browser-cli auth login` for browser.lexmount.cn setup guidance.",
            "Set LEXMOUNT_API_KEY and LEXMOUNT_PROJECT_ID in the local shell.",
        ]
    return [
        "Run `browser-cli auth login` for browser.lexmount.cn setup guidance.",
        "Set LEXMOUNT_API_KEY and LEXMOUNT_PROJECT_ID in the local shell.",
        f"Run `{AGENT_DOCTOR_COMMAND}` after setting credentials.",
    ]


def _auth_token_info_next_steps(
    *,
    device_token_status: dict[str, Any],
    scope_check: dict[str, Any],
) -> list[str]:
    if not device_token_status.get("present"):
        return [
            "No local device-token metadata was found.",
            "Run `browser-cli auth login` for browser.lexmount.cn setup guidance.",
            "Use LEXMOUNT_API_KEY and LEXMOUNT_PROJECT_ID for browser actions until bearer-token runtime support lands.",
        ]
    if not device_token_status.get("valid"):
        return [
            "Local device-token metadata is present but not currently valid.",
            "Run `browser-cli auth login` to request fresh credentials when device-code login is available.",
            "Use env API-key credentials for browser actions today.",
        ]
    if not scope_check.get("satisfied"):
        return [
            "Local device-token metadata is valid but missing one or more requested scopes.",
            "Request a scoped credential that includes the missing scopes.",
            "Use env API-key credentials for browser actions today.",
        ]
    return [
        "Local device-token metadata is valid for the requested scope check.",
        "Bearer-token runtime auth is not enabled yet, so browser actions still require env API-key credentials.",
    ]


def _auth_refresh_reason(
    device_token_status: dict[str, Any],
    *,
    force: bool,
) -> str:
    if not device_token_status.get("present"):
        return "missing_credentials_file"
    if device_token_status.get("error"):
        return "invalid_credentials_file"
    if device_token_status.get("kind") != "device_token":
        return "unsupported_credentials_kind"
    if not device_token_status.get("has_refresh_token"):
        return "missing_refresh_token"
    if not force and device_token_status.get("refresh_needed") is False:
        return "refresh_not_needed"
    return "remote_refresh_unavailable"


def _auth_refresh_next_steps(
    *,
    reason: str,
    device_token_status: dict[str, Any],
) -> list[str]:
    if reason == "missing_credentials_file":
        return [
            "No local device-token metadata was found.",
            "Run `browser-cli auth login` for browser.lexmount.cn setup guidance.",
            "Use LEXMOUNT_API_KEY and LEXMOUNT_PROJECT_ID for browser actions until bearer-token runtime support lands.",
        ]
    if reason in {"invalid_credentials_file", "unsupported_credentials_kind"}:
        return [
            "Local token metadata cannot be refreshed in its current form.",
            "Run `browser-cli auth logout` to remove local metadata if it is stale.",
            "Run `browser-cli auth login` for browser.lexmount.cn setup guidance.",
        ]
    if reason == "missing_refresh_token":
        return [
            "Local device-token metadata does not include a refresh token.",
            "Run `browser-cli auth login` to request fresh credentials when device-code login is available.",
            "Use env API-key credentials for browser actions today.",
        ]
    if reason == "refresh_not_needed":
        return [
            "Local device-token metadata does not currently need refresh.",
            "Bearer-token runtime auth is not enabled yet, so browser actions still require env API-key credentials.",
        ]
    if reason == "refreshed":
        return [
            "Local device-token metadata was refreshed and saved.",
            "Run `browser-cli auth status` to inspect the refreshed metadata.",
            "Bearer-token runtime auth is not enabled yet, so browser actions still require env API-key credentials.",
        ]
    if reason in {"refresh_endpoint_error", "refresh_response_invalid"}:
        return [
            "Remote token refresh was attempted but did not complete.",
            "Inspect `remote_refresh.status_code`, `remote_refresh.error`, and `remote_refresh.message`.",
            "Use env API-key credentials for browser actions today.",
        ]
    steps = [
        "Token lifecycle refresh endpoint is not configured for this CLI run.",
        "Pass `--token-base-url` or set LEXMOUNT_BROWSER_TOKEN_BASE_URL when browser.lexmount.cn exposes token lifecycle endpoints.",
        "Use env API-key credentials for browser actions today.",
    ]
    if device_token_status.get("expired"):
        steps.insert(0, "Local device-token metadata is expired.")
    return steps


def _auth_logout_next_steps(
    *,
    deleted: bool,
    revoke_requested: bool,
    revoke_available: bool = False,
    revoked: bool = False,
) -> list[str]:
    steps = [
        "Run `browser-cli auth status` to verify local credential state.",
        "Use LEXMOUNT_API_KEY and LEXMOUNT_PROJECT_ID for browser actions until bearer-token runtime support lands.",
    ]
    if deleted:
        steps.insert(0, "Local device-token metadata was removed.")
    else:
        steps.insert(0, "No local device-token metadata file was removed.")
    if revoke_requested:
        if revoked:
            steps.append("Remote token revoke completed.")
        elif revoke_available:
            steps.append(
                "Remote token revoke was attempted but did not complete; inspect `remote_revoke`."
            )
        else:
            steps.append(
                "Token lifecycle revoke endpoint is not configured; revoke the token from browser.lexmount.cn if needed."
            )
    return steps


def _merge_refreshed_token_payload(
    response_payload: dict[str, Any],
    current_credentials: dict[str, Any],
) -> dict[str, Any]:
    merged = dict(response_payload)
    for key in (
        "refresh_token",
        "project_id",
        "api_base_url",
        "scopes",
        "token_id",
        "token_type",
    ):
        if merged.get(key) in (None, "", []):
            merged[key] = current_credentials.get(key)
    return merged


def _request_remote_token_refresh(
    *,
    endpoint: str,
    credentials_file: str | None,
    requested_scopes: list[str],
    timeout_seconds: float,
) -> dict[str, Any]:
    current_credentials, read_meta = _read_device_token_credentials_data(
        credentials_file
    )
    if current_credentials is None:
        return {
            "attempted": False,
            "ok": False,
            "error": read_meta.get("error"),
            "message": read_meta.get("message"),
            **read_meta,
        }
    refresh_token = current_credentials.get("refresh_token")
    if not isinstance(refresh_token, str) or not refresh_token:
        return {
            "attempted": False,
            "ok": False,
            "error": "missing_refresh_token",
            "message": "Local credentials do not contain a refresh token.",
            **read_meta,
        }
    response = _json_http_post(
        endpoint,
        {
            "client_name": "browser-cli",
            "grant_type": "refresh_token",
            "credential_kind": current_credentials.get("kind") or "device_token",
            "refresh_token": refresh_token,
            "token_id": current_credentials.get("token_id"),
            "project_id": current_credentials.get("project_id"),
            "requested_scopes": requested_scopes,
        },
        timeout_seconds=timeout_seconds,
    )
    response_payload = response.get("json", {})
    result: dict[str, Any] = {
        "attempted": True,
        "ok": bool(response.get("ok")),
        "endpoint": endpoint,
        "status_code": response.get("status_code"),
        "error": response.get("error"),
        "message": response.get("message"),
    }
    if not response.get("ok") or not isinstance(response_payload, dict):
        return result
    token_payload, payload_source, inspected_sources = _extract_token_response_payload(
        response_payload
    )
    result.update(
        {
            "response_payload_source": payload_source,
            "inspected_response_sources": inspected_sources,
            "response_summary": _token_response_summary(token_payload),
        }
    )
    if not token_payload.get("access_token"):
        return {
            **result,
            "ok": False,
            "error": "refresh_response_invalid",
            "message": "Refresh response did not contain a usable access token payload.",
            "saved": False,
        }
    token_payload = _merge_refreshed_token_payload(
        token_payload,
        current_credentials,
    )
    credentials = _write_device_token_credentials(
        token_payload,
        credentials_file=credentials_file,
        requested_scopes=requested_scopes,
    )
    return {
        **result,
        "credentials": credentials,
        "saved": bool(credentials.get("saved")),
    }


def _request_remote_token_revoke(
    *,
    endpoint: str,
    credentials_file: str | None,
    timeout_seconds: float,
) -> dict[str, Any]:
    current_credentials, read_meta = _read_device_token_credentials_data(
        credentials_file
    )
    if current_credentials is None:
        return {
            "attempted": False,
            "ok": False,
            "error": read_meta.get("error"),
            "message": read_meta.get("message"),
            **read_meta,
        }
    scopes = _scope_list(current_credentials.get("scopes")) or []
    token_type_hint = (
        "refresh_token"
        if isinstance(current_credentials.get("refresh_token"), str)
        and bool(current_credentials.get("refresh_token"))
        else "access_token"
    )
    response = _json_http_post(
        endpoint,
        {
            "client_name": "browser-cli",
            "credential_kind": current_credentials.get("kind") or "device_token",
            "token_type_hint": token_type_hint,
            "access_token": current_credentials.get("access_token"),
            "refresh_token": current_credentials.get("refresh_token"),
            "token_id": current_credentials.get("token_id"),
            "project_id": current_credentials.get("project_id"),
            "scopes": scopes,
        },
        timeout_seconds=timeout_seconds,
    )
    response_payload = response.get("json", {})
    revoked_field = (
        response_payload.get("revoked") if isinstance(response_payload, dict) else None
    )
    revoked_confirmed = bool(revoked_field) if revoked_field is not None else None
    ok = bool(response.get("ok")) and revoked_confirmed is not False
    return {
        "attempted": True,
        "ok": ok,
        "endpoint": endpoint,
        "status_code": response.get("status_code"),
        "error": response.get("error") or ("revoke_not_confirmed" if not ok else None),
        "message": response.get("message")
        or (
            "Revoke response explicitly reported revoked=false."
            if revoked_confirmed is False
            else None
        ),
        "token_type_hint": token_type_hint,
        "revoked": revoked_confirmed,
    }


def _dedupe_preserving_order(values: list[str] | tuple[str, ...]) -> list[str]:
    deduped: list[str] = []
    for value in values:
        if value not in deduped:
            deduped.append(value)
    return deduped


def _auth_login_project_id(args: argparse.Namespace) -> tuple[str | None, str]:
    if args.project_id:
        return args.project_id, "argument"
    env_project_id = os.environ.get("LEXMOUNT_PROJECT_ID")
    if env_project_id:
        return env_project_id, "env"
    return None, "unset"


def _auth_login_scopes(args: argparse.Namespace) -> list[str]:
    raw_scopes = args.scope or list(DEFAULT_CODEX_CONNECT_SCOPES)
    return _dedupe_preserving_order(raw_scopes)


def _known_scope_details() -> dict[str, dict[str, Any]]:
    return {
        "browser:sessions": {
            "label": "Browser sessions",
            "description": "Create, list, inspect, keep alive, and close browser sessions.",
            "permissions": [
                "browser.sessions:create",
                "browser.sessions:list",
                "browser.sessions:read",
                "browser.sessions:close",
            ],
            "risk": "medium",
            "destructive": False,
        },
        "browser:contexts": {
            "label": "Persistent browser contexts",
            "description": "Create, list, inspect, reuse, and delete persistent browser contexts.",
            "permissions": [
                "browser.contexts:create",
                "browser.contexts:list",
                "browser.contexts:read",
                "browser.contexts:delete",
            ],
            "risk": "medium",
            "destructive": True,
        },
        "browser:actions": {
            "label": "Browser actions",
            "description": "Open pages and operate browser pages with clicks, typing, snapshots, screenshots, and DOM-backed actions.",
            "permissions": [
                "browser.actions:run",
            ],
            "risk": "high",
            "destructive": False,
        },
    }


def _scope_detail(scope: str) -> dict[str, Any]:
    detail = _known_scope_details().get(scope)
    if detail is None:
        return {
            "scope": scope,
            "known": False,
            "label": scope,
            "description": "Custom or future scope requested by the caller.",
            "permissions": [scope],
            "risk": "unknown",
            "destructive": None,
        }
    return {
        "scope": scope,
        "known": True,
        **detail,
    }


def _scope_details(scopes: list[str]) -> list[dict[str, Any]]:
    return [_scope_detail(scope) for scope in scopes]


def _scope_catalog_entry(scope: str) -> dict[str, Any]:
    detail = _scope_detail(scope)
    permissions = list(detail["permissions"])
    entry = {
        **detail,
        "default_requested": scope in DEFAULT_CODEX_CONNECT_SCOPES,
        "permission_count": len(permissions),
        "query_parameter": f"scope={scope}",
        "browser_site_ui": {
            "label_field": "label",
            "description_field": "description",
            "permissions_field": "permissions",
            "risk_field": "risk",
            "destructive_field": "destructive",
            "default_checked_field": "default_requested",
        },
    }
    if not detail["known"]:
        entry["browser_site_ui"]["custom_scope"] = True
    return entry


def _scope_catalog_entries(scopes: list[str]) -> list[dict[str, Any]]:
    return [_scope_catalog_entry(scope) for scope in scopes]


def _base64url_no_padding(raw: bytes) -> str:
    return base64.urlsafe_b64encode(raw).decode("ascii").rstrip("=")


def _new_pkce_code_verifier() -> str:
    return _base64url_no_padding(os.urandom(32))


def _pkce_code_challenge(code_verifier: str) -> str:
    return _base64url_no_padding(hashlib.sha256(code_verifier.encode("ascii")).digest())


def _new_oauth_state() -> str:
    return _base64url_no_padding(os.urandom(24))


def _connect_from_codex_url(
    *,
    project_id: str | None,
    scopes: list[str],
    expires_in: str,
    response: str = "code",
    connect_base_url: str | None = None,
    redirect_uri: str | None = None,
    state: str | None = None,
    code_challenge: str | None = None,
    code_challenge_method: str = "S256",
    client_name: str = "Codex",
) -> str:
    base_url = connect_base_url or LEXMOUNT_CONSOLE_URL
    query: list[tuple[str, str]] = [
        ("source", "browser-cli"),
        ("intent", "agent-browser-control"),
        ("response", response),
        ("expires_in", expires_in),
    ]
    if project_id:
        query.append(("project_id", project_id))
    if scopes:
        query.append(("scope", " ".join(scopes)))
    if redirect_uri:
        query.append(("redirect_uri", redirect_uri))
    if state:
        query.append(("state", state))
    if code_challenge:
        query.append(("code_challenge", code_challenge))
        query.append(("code_challenge_method", code_challenge_method))
    if client_name:
        query.append(("client_name", client_name))
    connect_url = _codex_connect_endpoint(base_url, "/connect/codex")
    return f"{connect_url}?{urlencode(query)}"


class _CodexConnectCallbackHandler(BaseHTTPRequestHandler):
    server_version = "browser-cli-connect"

    def do_GET(self) -> None:
        parsed = urlsplit(self.path)
        params = dict(parse_qsl(parsed.query, keep_blank_values=True))
        result = {
            "received": True,
            "path": parsed.path,
            "query": params,
        }
        self.server.callback_result = result  # type: ignore[attr-defined]
        self.server.callback_event.set()  # type: ignore[attr-defined]

        is_callback = parsed.path == "/callback"
        status = 200 if is_callback else 404
        title = "Lexmount connection received" if is_callback else "Not found"
        body = (
            "<!doctype html><meta charset='utf-8'>"
            f"<title>{title}</title>"
            "<body style='font-family: system-ui, sans-serif; padding: 32px;'>"
            f"<h1>{title}</h1>"
            "<p>You can return to the terminal.</p>"
            "</body>"
        ).encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.send_header("Cache-Control", "no-store")
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def log_message(self, format: str, *args: Any) -> None:
        return


def _safe_callback_result(result: dict[str, Any] | None, expected_state: str) -> dict[str, Any]:
    if not result:
        return {"received": False, "state_valid": False, "code_present": False}
    query = result.get("query") if isinstance(result.get("query"), dict) else {}
    state = query.get("state")
    code = query.get("code")
    error = query.get("error")
    return {
        "received": True,
        "path": result.get("path"),
        "state_present": bool(state),
        "state_valid": state == expected_state,
        "code_present": bool(code),
        "error": _mask_sensitive_text(str(error)) if error else None,
        "error_description": _mask_sensitive_text(str(query.get("error_description")))
        if query.get("error_description")
        else None,
    }


def _exchange_codex_connect_code(
    *,
    exchange_endpoint: str,
    code: str,
    code_verifier: str,
    redirect_uri: str,
    credentials_file: str | None,
    requested_scopes: list[str],
    connect_base_url: str,
    timeout_seconds: float,
) -> dict[str, Any]:
    response = _json_http_post(
        exchange_endpoint,
        {
            "code": code,
            "code_verifier": code_verifier,
            "redirect_uri": redirect_uri,
        },
        timeout_seconds=timeout_seconds,
    )
    response_payload = response.get("json", {})
    api_key_payload: dict[str, Any] = {}
    payload_source = "missing"
    inspected_sources: list[str] = []
    if isinstance(response_payload, dict):
        api_key_payload, payload_source, inspected_sources = (
            _extract_api_key_response_payload(response_payload)
        )
    credentials: dict[str, Any] = {
        "saved": False,
        "credentials_file": str(
            _device_token_credentials_path(credentials_file)[0]
        ),
    }
    if response.get("ok") and api_key_payload:
        credentials = _write_api_key_credentials(
            api_key_payload,
            credentials_file=credentials_file,
            requested_scopes=requested_scopes,
            connect_base_url=connect_base_url,
        )
        if credentials.get("saved"):
            _apply_local_api_key_credentials(credentials_file)

    ok = bool(response.get("ok")) and bool(credentials.get("saved"))
    error = response.get("error")
    if response.get("ok") and not api_key_payload:
        error = "exchange_response_missing_api_key"
    elif response.get("ok") and not credentials.get("saved"):
        error = credentials.get("error") or "credentials_not_saved"

    return {
        "attempted": True,
        "ok": ok,
        "endpoint": exchange_endpoint,
        "status_code": response.get("status_code"),
        "error": error,
        "message": response.get("message"),
        "response_payload_source": payload_source,
        "inspected_payload_sources": inspected_sources,
        "project_id": api_key_payload.get("project_id"),
        "api_base_url": api_key_payload.get("api_base_url"),
        "has_api_base_url": isinstance(api_key_payload.get("api_base_url"), str)
        and bool(api_key_payload.get("api_base_url")),
        "scopes": api_key_payload.get("scopes") or [],
        "scope_count": len(api_key_payload.get("scopes") or []),
        "has_api_key": isinstance(api_key_payload.get("api_key"), str)
        and bool(api_key_payload.get("api_key")),
        "api_key_length": len(api_key_payload.get("api_key"))
        if isinstance(api_key_payload.get("api_key"), str)
        else 0,
        "api_key_redacted": bool(api_key_payload.get("api_key")),
        "credentials": credentials,
    }


def _run_codex_connect_loopback_login(
    *,
    args: argparse.Namespace,
    project_id: str | None,
    project_id_source: str,
    scopes: list[str],
    expires_in: str,
    connect_base_url: str,
    connect_base_url_source: str,
) -> dict[str, Any]:
    code_verifier = _new_pkce_code_verifier()
    code_challenge = _pkce_code_challenge(code_verifier)
    state = _new_oauth_state()
    server = ThreadingHTTPServer(("127.0.0.1", 0), _CodexConnectCallbackHandler)
    server.callback_event = threading.Event()  # type: ignore[attr-defined]
    server.callback_result = None  # type: ignore[attr-defined]
    redirect_uri = f"http://127.0.0.1:{server.server_port}/callback"
    connect_url = _connect_from_codex_url(
        project_id=project_id,
        scopes=scopes,
        expires_in=expires_in,
        response="code",
        connect_base_url=connect_base_url,
        redirect_uri=redirect_uri,
        state=state,
        code_challenge=code_challenge,
        code_challenge_method="S256",
        client_name="Codex",
    )
    exchange_endpoint = _codex_connect_endpoint(
        connect_base_url, "/api/connect/codex/exchange"
    )
    callback_timeout_seconds = float(args.callback_timeout_seconds)
    thread = threading.Thread(target=server.serve_forever, daemon=True)
    thread.start()
    open_result: dict[str, Any] = {
        "requested": True,
        "url": connect_url,
        "opened": False,
    }
    warnings: list[str] = []
    try:
        try:
            open_result["opened"] = bool(webbrowser.open(connect_url))
        except Exception as exc:
            open_result["error"] = _mask_sensitive_text(str(exc))
            warnings.append(
                "Failed to open the Connect from Codex URL automatically; rerun auth login --open or copy the URL locally."
            )
            return {
                "attempted": True,
                "available": True,
                "authenticated": False,
                "credentials_saved": False,
                "reason": "browser_open_failed",
                "connect_url": connect_url,
                "connect_base_url": connect_base_url,
                "connect_base_url_source": connect_base_url_source,
                "exchange_endpoint": exchange_endpoint,
                "redirect_uri": redirect_uri,
                "open_result": open_result,
                "loopback_callback": {
                    "redirect_uri": redirect_uri,
                    "timeout_seconds": callback_timeout_seconds,
                    "received": False,
                },
                "exchange": {"attempted": False, "endpoint": exchange_endpoint},
                "warnings": warnings,
            }
        if not open_result["opened"]:
            warnings.append(
                "The system browser did not confirm opening the Connect from Codex URL; rerun auth login --open or copy the URL locally."
            )
            return {
                "attempted": True,
                "available": True,
                "authenticated": False,
                "credentials_saved": False,
                "reason": "browser_open_unconfirmed",
                "connect_url": connect_url,
                "connect_base_url": connect_base_url,
                "connect_base_url_source": connect_base_url_source,
                "exchange_endpoint": exchange_endpoint,
                "redirect_uri": redirect_uri,
                "open_result": open_result,
                "loopback_callback": {
                    "redirect_uri": redirect_uri,
                    "timeout_seconds": callback_timeout_seconds,
                    "received": False,
                },
                "exchange": {"attempted": False, "endpoint": exchange_endpoint},
                "warnings": warnings,
            }

        callback_event = server.callback_event  # type: ignore[attr-defined]
        received = callback_event.wait(callback_timeout_seconds)
        raw_callback = server.callback_result if received else None  # type: ignore[attr-defined]
        callback = _safe_callback_result(raw_callback, state)
        callback["redirect_uri"] = redirect_uri
        callback["timeout_seconds"] = callback_timeout_seconds
        if not received:
            warnings.append(
                "Timed out waiting for the local Connect from Codex callback."
            )
            return {
                "attempted": True,
                "available": True,
                "authenticated": False,
                "credentials_saved": False,
                "reason": "callback_timeout",
                "connect_url": connect_url,
                "connect_base_url": connect_base_url,
                "connect_base_url_source": connect_base_url_source,
                "exchange_endpoint": exchange_endpoint,
                "redirect_uri": redirect_uri,
                "open_result": open_result,
                "loopback_callback": callback,
                "exchange": {"attempted": False, "endpoint": exchange_endpoint},
                "warnings": warnings,
            }
        query = raw_callback.get("query", {}) if isinstance(raw_callback, dict) else {}
        if callback.get("error"):
            warnings.append("Connect from Codex returned an authorization error.")
            return {
                "attempted": True,
                "available": True,
                "authenticated": False,
                "credentials_saved": False,
                "reason": "authorization_error",
                "connect_url": connect_url,
                "connect_base_url": connect_base_url,
                "connect_base_url_source": connect_base_url_source,
                "exchange_endpoint": exchange_endpoint,
                "redirect_uri": redirect_uri,
                "open_result": open_result,
                "loopback_callback": callback,
                "exchange": {"attempted": False, "endpoint": exchange_endpoint},
                "warnings": warnings,
            }
        if not callback.get("state_valid"):
            warnings.append("Connect from Codex callback state did not match.")
            return {
                "attempted": True,
                "available": True,
                "authenticated": False,
                "credentials_saved": False,
                "reason": "state_mismatch",
                "connect_url": connect_url,
                "connect_base_url": connect_base_url,
                "connect_base_url_source": connect_base_url_source,
                "exchange_endpoint": exchange_endpoint,
                "redirect_uri": redirect_uri,
                "open_result": open_result,
                "loopback_callback": callback,
                "exchange": {"attempted": False, "endpoint": exchange_endpoint},
                "warnings": warnings,
            }
        code = query.get("code")
        if not isinstance(code, str) or not code:
            warnings.append("Connect from Codex callback did not include a code.")
            return {
                "attempted": True,
                "available": True,
                "authenticated": False,
                "credentials_saved": False,
                "reason": "missing_code",
                "connect_url": connect_url,
                "connect_base_url": connect_base_url,
                "connect_base_url_source": connect_base_url_source,
                "exchange_endpoint": exchange_endpoint,
                "redirect_uri": redirect_uri,
                "open_result": open_result,
                "loopback_callback": callback,
                "exchange": {"attempted": False, "endpoint": exchange_endpoint},
                "warnings": warnings,
            }

        exchange = _exchange_codex_connect_code(
            exchange_endpoint=exchange_endpoint,
            code=code,
            code_verifier=code_verifier,
            redirect_uri=redirect_uri,
            credentials_file=args.credentials_file,
            requested_scopes=scopes,
            connect_base_url=connect_base_url,
            timeout_seconds=float(args.connect_http_timeout_seconds),
        )
        authenticated = bool(exchange.get("ok"))
        if not authenticated:
            warnings.append(
                "Connect from Codex exchange did not return usable credentials."
            )
        return {
            "attempted": True,
            "available": True,
            "authenticated": authenticated,
            "credentials_saved": bool(
                exchange.get("credentials", {}).get("saved")
            ),
            "reason": "authenticated" if authenticated else "exchange_failed",
            "connect_url": connect_url,
            "connect_base_url": connect_base_url,
            "connect_base_url_source": connect_base_url_source,
            "exchange_endpoint": exchange_endpoint,
            "redirect_uri": redirect_uri,
            "project_id": exchange.get("project_id") or project_id,
            "project_id_source": "exchange" if exchange.get("project_id") else project_id_source,
            "requested_scopes": scopes,
            "requested_expires_in": expires_in,
            "open_result": open_result,
            "loopback_callback": callback,
            "exchange": exchange,
            "credentials": exchange.get("credentials"),
            "warnings": warnings,
        }
    finally:
        server.shutdown()
        server.server_close()
        thread.join(timeout=1)


