def _target_from_args(args: argparse.Namespace) -> BrowserActionTarget:
    target_count = sum(
        bool(value)
        for value in (
            getattr(args, "connect_url", None),
            getattr(args, "session_id", None),
            getattr(args, "direct_url", False),
        )
    )
    if target_count != 1:
        raise BrowserRuntimeError(
            "Pass exactly one action target: --connect-url, --session-id, or --direct-url."
        )
    return BrowserActionTarget(
        connect_url=getattr(args, "connect_url", None),
        session_id=getattr(args, "session_id", None),
        direct_url=bool(getattr(args, "direct_url", False)),
    )


def _run_action_command(
    args: argparse.Namespace,
    command: str,
    request: Any,
) -> None:
    try:
        target = _target_from_args(args)
        connect_url = resolve_browser_action_connect_url(target)
        action_name = command.removeprefix("action.")
        result = run_browser_action(
            connect_url=connect_url,
            action=action_name,  # type: ignore[arg-type]
            request=request,
        )
    except Exception as exc:
        _failure_from_exception(command, exc)
    _success(
        command,
        session_id=getattr(args, "session_id", None),
        **_masked_connect_url_payload(
            connect_url,
            reveal_connect_url=bool(getattr(args, "reveal_connect_url", False)),
        ),
        result=result.result,
    )


def _run_with_playwright_page(
    *,
    connect_url: str,
    operation: Callable[[Any], dict[str, Any]],
) -> dict[str, Any]:
    try:
        from playwright.sync_api import sync_playwright  # type: ignore[import-not-found]
    except Exception as exc:
        raise BrowserConfigError(
            "Failed to import Playwright. Install lex-browser-runtime[browser] "
            "or provide an environment that already includes playwright."
        ) from exc

    with sync_playwright() as playwright:
        browser = playwright.chromium.connect_over_cdp(connect_url)
        try:
            context = browser.contexts[0] if browser.contexts else browser.new_context()
            page = context.pages[0] if context.pages else context.new_page()
            return operation(page)
        finally:
            browser.close()


def _set_page_viewport(
    *,
    connect_url: str,
    width: int,
    height: int,
) -> dict[str, Any]:
    def apply(page: Any) -> dict[str, Any]:
        previous_viewport = page.viewport_size
        page.set_viewport_size({"width": width, "height": height})
        viewport = page.viewport_size
        window_viewport = page.evaluate(
            """
() => ({
  width: window.innerWidth,
  height: window.innerHeight,
  device_pixel_ratio: window.devicePixelRatio
})
""".strip()
        )
        return {
            "url": page.url,
            "title": page.title(),
            "requested_viewport": {"width": width, "height": height},
            "previous_viewport": previous_viewport,
            "viewport": viewport,
            "window_viewport": window_viewport,
            "changed": previous_viewport != viewport,
        }

    return _run_with_playwright_page(connect_url=connect_url, operation=apply)


def _screenshot_selector(
    *,
    connect_url: str,
    selector: str,
    output: str | None,
    index: int,
    timeout_ms: float,
) -> dict[str, Any]:
    output_path = output or str(
        Path("/tmp")
        / f"browser-cli-selector-screenshot-{int(datetime.now(timezone.utc).timestamp())}.png"
    )

    def apply(page: Any) -> dict[str, Any]:
        try:
            page.wait_for_selector(selector, state="attached", timeout=timeout_ms)
        except Exception:
            return {
                "url": page.url,
                "selector": selector,
                "index": index,
                "found": False,
                "screenshot": False,
                "path": output_path,
                "match_count": 0,
                "error": "selector_not_found",
            }

        matches = page.locator(selector)
        match_count = matches.count()
        if index >= match_count:
            return {
                "url": page.url,
                "selector": selector,
                "index": index,
                "found": False,
                "screenshot": False,
                "path": output_path,
                "match_count": match_count,
                "error": "index_out_of_range",
            }

        target = matches.nth(index)
        try:
            target.wait_for(state="visible", timeout=timeout_ms)
        except Exception:
            return {
                "url": page.url,
                "selector": selector,
                "index": index,
                "found": True,
                "visible": False,
                "screenshot": False,
                "path": output_path,
                "match_count": match_count,
                "bounding_box": target.bounding_box(),
                "error": "element_not_visible",
            }

        bounding_box = target.bounding_box()
        if bounding_box is None:
            return {
                "url": page.url,
                "selector": selector,
                "index": index,
                "found": True,
                "visible": False,
                "screenshot": False,
                "path": output_path,
                "match_count": match_count,
                "bounding_box": None,
                "error": "missing_bounding_box",
            }

        target.screenshot(path=output_path, timeout=timeout_ms)
        return {
            "url": page.url,
            "selector": selector,
            "index": index,
            "found": True,
            "visible": True,
            "screenshot": True,
            "path": output_path,
            "match_count": match_count,
            "bounding_box": bounding_box,
        }

    return _run_with_playwright_page(connect_url=connect_url, operation=apply)


def _screenshot_role(
    *,
    connect_url: str,
    role: str,
    name: str | None,
    output: str | None,
    index: int,
    timeout_ms: float,
    exact: bool,
    include_hidden: bool,
) -> dict[str, Any]:
    output_path = output or str(
        Path("/tmp")
        / f"browser-cli-role-screenshot-{int(datetime.now(timezone.utc).timestamp())}.png"
    )

    def apply(page: Any) -> dict[str, Any]:
        matches = page.get_by_role(
            role,
            name=name,
            exact=exact,
            include_hidden=include_hidden,
        )
        target = matches.nth(index)
        try:
            target.wait_for(state="attached", timeout=timeout_ms)
        except Exception:
            match_count = matches.count()
            return {
                "url": page.url,
                "role": role,
                "name": name,
                "exact": exact,
                "include_hidden": include_hidden,
                "index": index,
                "found": False,
                "role_found": False,
                "screenshot": False,
                "path": output_path,
                "match_count": match_count,
                "error": "role_not_found",
            }

        match_count = matches.count()
        if index >= match_count:
            return {
                "url": page.url,
                "role": role,
                "name": name,
                "exact": exact,
                "include_hidden": include_hidden,
                "index": index,
                "found": False,
                "role_found": match_count > 0,
                "screenshot": False,
                "path": output_path,
                "match_count": match_count,
                "error": "index_out_of_range",
            }

        try:
            target.wait_for(state="visible", timeout=timeout_ms)
        except Exception:
            return {
                "url": page.url,
                "role": role,
                "name": name,
                "exact": exact,
                "include_hidden": include_hidden,
                "index": index,
                "found": True,
                "role_found": True,
                "visible": False,
                "screenshot": False,
                "path": output_path,
                "match_count": match_count,
                "bounding_box": target.bounding_box(),
                "error": "element_not_visible",
            }

        bounding_box = target.bounding_box()
        if bounding_box is None:
            return {
                "url": page.url,
                "role": role,
                "name": name,
                "exact": exact,
                "include_hidden": include_hidden,
                "index": index,
                "found": True,
                "role_found": True,
                "visible": False,
                "screenshot": False,
                "path": output_path,
                "match_count": match_count,
                "bounding_box": None,
                "error": "missing_bounding_box",
            }

        target.screenshot(path=output_path, timeout=timeout_ms)
        return {
            "url": page.url,
            "role": role,
            "name": name,
            "exact": exact,
            "include_hidden": include_hidden,
            "index": index,
            "found": True,
            "role_found": True,
            "visible": True,
            "screenshot": True,
            "path": output_path,
            "match_count": match_count,
            "bounding_box": bounding_box,
        }

    return _run_with_playwright_page(connect_url=connect_url, operation=apply)


