def _js_literal(value: Any) -> str:
    return json.dumps(value)


def _read_file_input_payloads(
    *,
    command: str,
    files: list[str],
    max_bytes: int,
) -> list[dict[str, Any]]:
    if max_bytes < 0:
        _failure(
            command,
            "argument_error",
            "--max-bytes must be zero or greater.",
            exit_code=2,
            max_bytes=max_bytes,
        )

    payloads: list[dict[str, Any]] = []
    total_bytes = 0
    for raw_file in files:
        path = Path(raw_file).expanduser()
        if not path.is_file():
            _failure(
                command,
                "file_not_found",
                "File input path does not exist or is not a file.",
                exit_code=2,
                file=raw_file,
            )
        try:
            data = path.read_bytes()
            stat = path.stat()
        except OSError as exc:
            _failure(
                command,
                "file_read_error",
                str(exc),
                exit_code=2,
                file=raw_file,
            )
        total_bytes += len(data)
        if total_bytes > max_bytes:
            _failure(
                command,
                "file_payload_too_large",
                "Total file input payload exceeds --max-bytes.",
                exit_code=2,
                max_bytes=max_bytes,
                total_bytes=total_bytes,
            )
        mime_type = mimetypes.guess_type(path.name)[0] or "application/octet-stream"
        payloads.append(
            {
                "name": path.name,
                "type": mime_type,
                "size": len(data),
                "last_modified": int(stat.st_mtime * 1000),
                "data_base64": base64.b64encode(data).decode("ascii"),
            }
        )
    return payloads


def _inline_file_input_payloads(
    *,
    command: str,
    inline_files: list[Any],
    max_bytes: int,
) -> list[dict[str, Any]]:
    if max_bytes < 0:
        _failure(
            command,
            "argument_error",
            "max_bytes must be zero or greater.",
            exit_code=2,
            max_bytes=max_bytes,
        )

    payloads: list[dict[str, Any]] = []
    total_bytes = 0
    for index, inline_file in enumerate(inline_files):
        if not isinstance(inline_file, dict):
            _failure(
                command,
                "argument_error",
                "inline_files entries must be objects.",
                exit_code=2,
                index=index,
            )
        name = inline_file.get("name")
        if not isinstance(name, str) or not name:
            _failure(
                command,
                "argument_error",
                "inline_files entries require a non-empty name.",
                exit_code=2,
                index=index,
            )
        if "data_base64" in inline_file:
            data_base64 = inline_file["data_base64"]
            if not isinstance(data_base64, str):
                _failure(
                    command,
                    "argument_error",
                    "inline_files data_base64 must be a string.",
                    exit_code=2,
                    index=index,
                )
            try:
                data = base64.b64decode(data_base64, validate=True)
            except Exception as exc:
                _failure(
                    command,
                    "argument_error",
                    "inline_files data_base64 must be valid base64.",
                    exit_code=2,
                    index=index,
                    error_class=exc.__class__.__name__,
                )
        else:
            content = inline_file.get("content")
            if not isinstance(content, str):
                _failure(
                    command,
                    "argument_error",
                    "inline_files entries require string content or data_base64.",
                    exit_code=2,
                    index=index,
                )
            data = content.encode("utf-8")
            data_base64 = base64.b64encode(data).decode("ascii")

        total_bytes += len(data)
        if total_bytes > max_bytes:
            _failure(
                command,
                "file_payload_too_large",
                "Total inline file input payload exceeds max_bytes.",
                exit_code=2,
                max_bytes=max_bytes,
                total_bytes=total_bytes,
            )
        mime_type = inline_file.get("type")
        if not isinstance(mime_type, str) or not mime_type:
            mime_type = mimetypes.guess_type(name)[0] or "application/octet-stream"
        raw_last_modified = inline_file.get("last_modified", 0) or 0
        try:
            last_modified = int(raw_last_modified)
        except (TypeError, ValueError):
            _failure(
                command,
                "argument_error",
                "inline_files last_modified must be an integer.",
                exit_code=2,
                index=index,
            )
        payloads.append(
            {
                "name": name,
                "type": mime_type,
                "size": len(data),
                "last_modified": last_modified,
                "data_base64": data_base64,
            }
        )
    return payloads


def _eval_backed_result_payload(result: Any) -> dict[str, Any]:
    if not isinstance(result, dict):
        return {"value": result}

    value = result.get("value")
    payload = dict(value) if isinstance(value, dict) else {"value": value}
    for key in ("url", "fallback"):
        if key in result and key not in payload:
            payload[key] = result[key]
    return payload


def _run_eval_backed_action_command(
    args: argparse.Namespace,
    command: str,
    expression: str,
) -> None:
    try:
        target = _target_from_args(args)
        connect_url = resolve_browser_action_connect_url(target)
        result = run_browser_action(
            connect_url=connect_url,
            action="eval",
            request=EvalRequest(expression=expression),
        )
    except Exception as exc:
        _failure_from_exception(command, exc)
    _success(
        command,
        session_id=getattr(args, "session_id", None),
        **_masked_connect_url_payload(
            connect_url,
            reveal_connect_url=bool(getattr(args, "reveal_connect_url", False)),
        ),
        result=_eval_backed_result_payload(result.result),
    )


def _run_eval_expression_result(*, connect_url: str, expression: str) -> dict[str, Any]:
    result = run_browser_action(
        connect_url=connect_url,
        action="eval",
        request=EvalRequest(expression=expression),
    )
    return _eval_backed_result_payload(result.result)


def _normalize_observe_surfaces(values: list[str]) -> list[str]:
    requested = values or ["interactive", "text"]
    if "all" in requested:
        requested = list(OBSERVE_SURFACE_CHOICES)
    return _dedupe_preserving_order(requested)


def _observe_surface_expression(
    surface: str,
    args: argparse.Namespace,
) -> str:
    if surface == "interactive":
        return _interactive_snapshot_expression(
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
        )
    if surface == "accessibility":
        return _accessibility_snapshot_expression(
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
        )
    if surface == "text":
        return _text_snapshot_expression(
            selector=args.selector,
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
            max_chars=args.max_chars,
        )
    if surface == "links":
        return _link_snapshot_expression(
            selector=args.selector,
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
            include_empty=False,
            same_origin_only=False,
        )
    if surface == "forms":
        return _form_snapshot_expression(
            selector=args.selector,
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
            reveal_sensitive_values=False,
        )
    if surface == "outline":
        return _outline_snapshot_expression(
            selector=args.selector,
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
        )
    raise BrowserRuntimeError(f"Unsupported observe surface: {surface}")


def _normalize_extract_surfaces(values: list[str]) -> list[str]:
    requested = values or ["text", "links"]
    if "all" in requested:
        requested = list(EXTRACT_SURFACE_CHOICES)
    return _dedupe_preserving_order(requested)


def _extract_surface_expression(
    surface: str,
    args: argparse.Namespace,
) -> str:
    if surface == "outline":
        return _outline_snapshot_expression(
            selector=args.selector,
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
        )
    if surface == "text":
        return _text_snapshot_expression(
            selector=args.selector,
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
            max_chars=args.max_chars,
        )
    if surface == "links":
        return _link_snapshot_expression(
            selector=args.selector,
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
            include_empty=args.include_empty_links,
            same_origin_only=args.same_origin_only,
        )
    if surface == "tables":
        return _table_snapshot_expression(
            selector=args.selector,
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
            max_rows=args.max_rows,
            max_cells=args.max_cells,
        )
    if surface == "lists":
        return _list_snapshot_expression(
            selector=args.selector,
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
            max_items=args.max_items,
        )
    if surface == "accessibility":
        return _accessibility_snapshot_expression(
            include_hidden=args.include_hidden,
            max_nodes=args.max_nodes,
        )
    raise BrowserRuntimeError(f"Unsupported extract surface: {surface}")


def _extract_truncated_surfaces(extractions: dict[str, dict[str, Any]]) -> list[str]:
    return [
        surface
        for surface, payload in extractions.items()
        if bool(payload.get("truncated"))
    ]


def cmd_action_observe(args: argparse.Namespace) -> None:
    command = "action.observe"
    try:
        target = _target_from_args(args)
        connect_url = resolve_browser_action_connect_url(target)
        page_info = _run_eval_expression_result(
            connect_url=connect_url,
            expression=_page_info_expression(),
        )
        surfaces = _normalize_observe_surfaces(args.surface)
        snapshots = {
            surface: _run_eval_expression_result(
                connect_url=connect_url,
                expression=_observe_surface_expression(surface, args),
            )
            for surface in surfaces
        }
    except Exception as exc:
        _failure_from_exception(command, exc)

    result = {
        "kind": "observe",
        "url": page_info.get("url"),
        "title": page_info.get("title"),
        "ready_state": page_info.get("ready_state"),
        "surface_count": len(surfaces),
        "surfaces": surfaces,
        "page_info": page_info,
        "snapshots": snapshots,
    }
    _success(
        command,
        session_id=getattr(args, "session_id", None),
        **_masked_connect_url_payload(
            connect_url,
            reveal_connect_url=bool(getattr(args, "reveal_connect_url", False)),
        ),
        result=result,
    )


def cmd_action_extract(args: argparse.Namespace) -> None:
    command = "action.extract"
    try:
        target = _target_from_args(args)
        connect_url = resolve_browser_action_connect_url(target)
        page_info = _run_eval_expression_result(
            connect_url=connect_url,
            expression=_page_info_expression(),
        )
        surfaces = _normalize_extract_surfaces(args.surface)
        extractions = {
            surface: _run_eval_expression_result(
                connect_url=connect_url,
                expression=_extract_surface_expression(surface, args),
            )
            for surface in surfaces
        }
    except Exception as exc:
        _failure_from_exception(command, exc)

    truncated_surfaces = _extract_truncated_surfaces(extractions)
    result = {
        "kind": "extract",
        "url": page_info.get("url"),
        "title": page_info.get("title"),
        "ready_state": page_info.get("ready_state"),
        "surface_count": len(surfaces),
        "surfaces": surfaces,
        "selector": args.selector,
        "truncated": bool(truncated_surfaces),
        "truncated_surfaces": truncated_surfaces,
        "page_info": page_info,
        "extractions": extractions,
    }
    _success(
        command,
        session_id=getattr(args, "session_id", None),
        **_masked_connect_url_payload(
            connect_url,
            reveal_connect_url=bool(getattr(args, "reveal_connect_url", False)),
        ),
        result=result,
    )


def _act_argument_error(
    command: str,
    message: str,
    **payload: Any,
) -> NoReturn:
    if command == "case.run":
        detail = {
            key: _sanitize_failure_value(value)
            for key, value in payload.items()
            if value is not None
        }
        suffix = (
            " " + json.dumps(detail, ensure_ascii=False, sort_keys=True, default=str)
            if detail
            else ""
        )
        raise BrowserConfigError(f"{message}{suffix}")
    _failure(command, "argument_error", message, exit_code=2, **payload)


def _act_present(value: Any) -> bool:
    return value is not None and value != ""


def _act_target_modes(args: argparse.Namespace, allowed: Iterable[str]) -> list[str]:
    allowed_set = set(allowed)
    modes: list[str] = []
    for mode in ("role", "label", "text", "selector"):
        if mode not in allowed_set:
            continue
        if _act_present(getattr(args, mode, None)):
            modes.append(mode)
    return modes


def _act_validate_unused_targets(
    command: str,
    args: argparse.Namespace,
    allowed: Iterable[str],
) -> None:
    allowed_set = set(allowed)
    provided = [
        mode
        for mode in ("role", "label", "text", "selector")
        if mode not in allowed_set
        and not (args.kind == "fill" and mode == "text")
        and _act_present(getattr(args, mode, None))
    ]
    if provided:
        _act_argument_error(
            command,
            f"--kind {args.kind} does not support target option(s): "
            + ", ".join(f"--{mode}" for mode in provided),
            kind=args.kind,
            unsupported_targets=provided,
        )
    if _act_present(getattr(args, "name", None)) and not _act_present(args.role):
        _act_argument_error(
            command,
            "--name requires --role.",
            kind=args.kind,
            name=args.name,
        )


def _act_select_target(
    command: str,
    args: argparse.Namespace,
    *,
    allowed: Iterable[str],
    required: bool = True,
) -> str | None:
    _act_validate_unused_targets(command, args, allowed)
    modes = _act_target_modes(args, allowed)
    if len(modes) > 1:
        _act_argument_error(
            command,
            "Pass only one target mode for action act.",
            kind=args.kind,
            target_modes=modes,
        )
    if not modes:
        if required:
            _act_argument_error(
                command,
                f"--kind {args.kind} requires one of: "
                + ", ".join(f"--{mode}" for mode in allowed),
                kind=args.kind,
                allowed_targets=list(allowed),
            )
        return None
    return modes[0]


def _act_click_selection(command: str, args: argparse.Namespace) -> str:
    _act_validate_unused_targets(
        command,
        args,
        allowed=("role", "label", "text", "selector"),
    )
    primary_modes = [
        mode
        for mode in ("role", "label", "text")
        if _act_present(getattr(args, mode, None))
    ]
    selector_present = _act_present(args.selector)
    if len(primary_modes) > 1:
        _act_argument_error(
            command,
            "Pass only one semantic target mode for action act click.",
            kind=args.kind,
            target_modes=primary_modes,
        )
    if primary_modes:
        selection = primary_modes[0]
        if selector_present and selection != "text":
            _act_argument_error(
                command,
                "--selector can only be combined with --text for --kind click.",
                kind=args.kind,
                target_modes=[selection, "selector"],
            )
        return selection
    if selector_present:
        return "selector"
    _act_argument_error(
        command,
        "--kind click requires --role, --label, --text, or --selector.",
        kind=args.kind,
        allowed_targets=["role", "label", "text", "selector"],
    )


def _act_fill_text(command: str, args: argparse.Namespace) -> str:
    has_value = _act_present(args.value)
    has_text = _act_present(args.text)
    if has_value and has_text:
        _act_argument_error(
            command,
            "--kind fill accepts either --value or --text, not both.",
            kind=args.kind,
        )
    if has_value:
        return str(args.value)
    if has_text:
        return str(args.text)
    _act_argument_error(
        command,
        "--kind fill requires --value.",
        kind=args.kind,
        accepted_alias="--text",
    )


def _act_select_value(command: str, args: argparse.Namespace) -> tuple[str | None, str | None]:
    has_value = _act_present(args.value)
    has_option_label = _act_present(args.option_label)
    if has_value and has_option_label:
        _act_argument_error(
            command,
            "--kind select accepts either --value or --option-label, not both.",
            kind=args.kind,
        )
    if not has_value and not has_option_label:
        _act_argument_error(
            command,
            "--kind select requires --value or --option-label.",
            kind=args.kind,
        )
    return (
        str(args.value) if has_value else None,
        str(args.option_label) if has_option_label else None,
    )


def _act_target_payload(args: argparse.Namespace, selection: str | None) -> dict[str, Any]:
    payload: dict[str, Any] = {"selection": selection or "page"}
    if selection == "role":
        payload.update(
            role=args.role,
            name=args.name,
            exact=bool(args.exact),
            case_sensitive=bool(args.case_sensitive),
        )
    elif selection == "label":
        payload.update(
            label=args.label,
            exact=bool(args.exact),
            case_sensitive=bool(args.case_sensitive),
        )
    elif selection == "text":
        payload.update(
            text=args.text,
            selector=args.selector,
            exact=bool(args.exact),
            case_sensitive=bool(args.case_sensitive),
        )
    elif selection == "selector":
        payload.update(selector=args.selector)
    return payload


def _act_plan(
    command: str,
    args: argparse.Namespace,
) -> dict[str, Any]:
    kind = args.kind
    if kind == "click":
        selection = _act_click_selection(command, args)
        if selection == "role":
            underlying_command = "action.click-role"
            expression = _click_role_expression(
                role=args.role,
                name=args.name,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        elif selection == "label":
            underlying_command = "action.click-label"
            expression = _click_label_expression(
                label=args.label,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        elif selection == "text":
            underlying_command = "action.click-text"
            expression = _click_text_expression(
                text=args.text,
                selector=args.selector,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        else:
            underlying_command = "action.click-index"
            expression = _click_index_expression(
                selector=args.selector,
                index=args.index,
                include_hidden=args.include_hidden,
            )
    elif kind == "fill":
        selection = _act_select_target(
            command,
            args,
            allowed=("label", "role", "selector"),
        )
        text = _act_fill_text(command, args)
        if selection == "label":
            underlying_command = "action.fill-label"
            expression = _fill_label_expression(
                label=args.label,
                text=text,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        elif selection == "role":
            underlying_command = "action.fill-role"
            expression = _fill_role_expression(
                role=args.role,
                name=args.name,
                text=text,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        else:
            underlying_command = "action.fill"
            expression = _fill_expression(selector=args.selector, text=text)
    elif kind == "select":
        selection = _act_select_target(
            command,
            args,
            allowed=("label", "role", "selector"),
        )
        value, option_label = _act_select_value(command, args)
        if selection == "label":
            underlying_command = "action.select-label"
            expression = _select_label_expression(
                label=args.label,
                value=value,
                option_label=option_label,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        elif selection == "role":
            underlying_command = "action.select-role"
            expression = _select_role_expression(
                role=args.role,
                name=args.name,
                value=value,
                option_label=option_label,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        else:
            if option_label is not None:
                _act_argument_error(
                    command,
                    "--kind select with --selector requires --value; "
                    "--option-label is supported with --label or --role.",
                    kind=args.kind,
                    target="selector",
                )
            underlying_command = "action.select-option"
            expression = _select_option_expression(selector=args.selector, value=value or "")
    elif kind in {"check", "uncheck"}:
        selection = _act_select_target(
            command,
            args,
            allowed=("label", "role", "selector"),
        )
        checked = kind == "check"
        if selection == "label":
            underlying_command = "action.check-label" if checked else "action.uncheck-label"
            expression = _check_label_expression(
                label=args.label,
                checked=checked,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        elif selection == "role":
            underlying_command = "action.check-role" if checked else "action.uncheck-role"
            expression = _check_role_expression(
                role=args.role,
                name=args.name,
                checked=checked,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        else:
            underlying_command = "action.check" if checked else "action.uncheck"
            expression = _checkbox_action_expression(
                selector=args.selector,
                checked=checked,
            )
    elif kind == "hover":
        selection = _act_select_target(
            command,
            args,
            allowed=("role", "selector"),
        )
        if selection == "role":
            underlying_command = "action.hover-role"
            expression = _hover_role_expression(
                role=args.role,
                name=args.name,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        else:
            underlying_command = "action.hover"
            expression = _hover_expression(args.selector)
    elif kind == "press":
        selection = _act_select_target(
            command,
            args,
            allowed=("role", "selector"),
            required=False,
        )
        if not _act_present(args.key):
            _act_argument_error(command, "--kind press requires --key.", kind=args.kind)
        if selection == "role":
            underlying_command = "action.press-role"
            expression = _press_role_expression(
                role=args.role,
                name=args.name,
                key=args.key,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        elif selection == "selector":
            underlying_command = "action.press"
            expression = _press_expression(selector=args.selector, key=args.key)
        else:
            underlying_command = "action.press-key"
            expression = _press_key_expression(
                key=args.key,
                code=args.code,
                alt_key=args.alt_key,
                ctrl_key=args.ctrl_key,
                meta_key=args.meta_key,
                shift_key=args.shift_key,
            )
    elif kind == "scroll-into-view":
        selection = _act_select_target(
            command,
            args,
            allowed=("role", "selector"),
        )
        if selection == "role":
            underlying_command = "action.scroll-into-view-role"
            expression = _scroll_into_view_role_expression(
                role=args.role,
                name=args.name,
                block=args.block,
                inline=args.inline,
                behavior=args.behavior,
                exact=args.exact,
                case_sensitive=args.case_sensitive,
            )
        else:
            underlying_command = "action.scroll-into-view"
            expression = _scroll_into_view_expression(
                selector=args.selector,
                block=args.block,
                inline=args.inline,
                behavior=args.behavior,
            )
    elif kind == "scroll":
        selection = _act_select_target(
            command,
            args,
            allowed=("selector",),
            required=False,
        )
        underlying_command = "action.scroll"
        expression = _scroll_expression(
            selector=args.selector if selection == "selector" else None,
            x=args.x,
            y=args.y,
            behavior=args.behavior,
        )
    else:
        _act_argument_error(
            command,
            f"Unsupported action act kind: {kind}",
            kind=kind,
            available_kinds=list(ACT_KIND_CHOICES),
        )

    target = _act_target_payload(args, selection)
    if selection == "selector" and kind == "click":
        target["index"] = args.index
        target["include_hidden"] = bool(args.include_hidden)
    if kind in {"fill", "press", "select", "scroll", "scroll-into-view"}:
        target.update(
            {
                key: value
                for key, value in {
                    "value_present": kind == "fill" and (
                        _act_present(args.value) or _act_present(args.text)
                    ),
                    "key": args.key if kind == "press" else None,
                    "option_label": args.option_label if kind == "select" else None,
                    "x": args.x if kind == "scroll" else None,
                    "y": args.y if kind == "scroll" else None,
                    "block": args.block if kind == "scroll-into-view" else None,
                    "inline": args.inline if kind == "scroll-into-view" else None,
                    "behavior": args.behavior
                    if kind in {"scroll", "scroll-into-view"}
                    else None,
                }.items()
                if value is not None
            }
        )

    return {
        "underlying_command": underlying_command,
        "selection": selection or "page",
        "target": target,
        "expression_backed": True,
        "deterministic": True,
        "custom_javascript": False,
        "verify_after": [
            "browser-cli action observe --session-id <session_id> --surface interactive --surface text",
            "browser-cli action page-info --session-id <session_id>",
        ],
        "expression": expression,
    }


def cmd_action_act(args: argparse.Namespace) -> None:
    command = "action.act"
    try:
        plan = _act_plan(command, args)
        expression = str(plan.pop("expression"))
        target = _target_from_args(args)
        connect_url = resolve_browser_action_connect_url(target)
        action_result = _run_eval_expression_result(
            connect_url=connect_url,
            expression=expression,
        )
    except Exception as exc:
        _failure_from_exception(command, exc)

    result = {
        "kind": "act",
        "intent": args.kind,
        "target": plan["target"],
        "plan": plan,
        "action_result": action_result,
    }
    _success(
        command,
        session_id=getattr(args, "session_id", None),
        **_masked_connect_url_payload(
            connect_url,
            reveal_connect_url=bool(getattr(args, "reveal_connect_url", False)),
        ),
        result=result,
    )


def _page_info_expression() -> str:
    return """
() => {
  const bodyText = document.body ? (document.body.innerText || document.body.textContent || "") : "";
  const html = document.documentElement ? document.documentElement.outerHTML || "" : "";
  return {
    url: location.href,
    title: document.title,
    ready_state: document.readyState,
    visibility_state: document.visibilityState,
    language: document.documentElement ? document.documentElement.lang || null : null,
    referrer: document.referrer || null,
    body_text_length: bodyText.length,
    html_length: html.length,
    viewport: {
      width: window.innerWidth,
      height: window.innerHeight,
      device_pixel_ratio: window.devicePixelRatio
    },
    scroll: {
      x: window.scrollX,
      y: window.scrollY
    }
  };
}
""".strip()


def _selector_expression(selector: str, body: str) -> str:
    return f"""
() => {{
  const selector = {_js_literal(selector)};
  const element = document.querySelector(selector);
  if (!element) {{
    return {{ selector, found: false }};
  }}
{body}
}}
""".strip()


def _sensitive_value_helpers_expression() -> str:
    return """
  const sensitiveNamePattern =
    /api[-_]?key|apikey|authorization|bearer|credential|password|passwd|secret|token/i;
  const sensitiveText = (value) => sensitiveNamePattern.test(String(value ?? ""));
  const sensitiveElement = (element) => {
    const tag = element.tagName.toLowerCase();
    const type = String(element.getAttribute("type") || "").toLowerCase();
    if (tag === "input" && ["password", "hidden", "file"].includes(type)) {
      return true;
    }
    return [
      "name",
      "id",
      "autocomplete",
      "aria-label",
      "placeholder",
      "title",
      "data-testid",
      "data-test",
      "data-cy"
    ].some((attribute) => sensitiveNamePattern.test(element.getAttribute(attribute) || ""));
  };
  const shouldMaskValue = (element, value) =>
    sensitiveElement(element) && String(value ?? "") !== "";
  const maskValue = (element, value) => shouldMaskValue(element, value) ? "***" : value;
  const publicRequestedValue = (element, value) => {
    const masked = shouldMaskValue(element, value);
    return {
      value: masked ? "***" : value,
      value_masked: masked,
      value_length: masked ? String(value ?? "").length : null
    };
  };
  const publicSelectorRequestedValue = (selector, value) => {
    const masked = sensitiveText(selector) && String(value ?? "") !== "";
    return {
      value: masked ? "***" : value,
      value_masked: masked,
      value_length: masked ? String(value ?? "").length : null
    };
  };
""".rstrip()


def _event_expression(selector: str, body: str) -> str:
    return _selector_expression(
        selector,
        f"""
  const dispatch = (event) => element.dispatchEvent(event);
{body}
""".rstrip(),
    )


def _get_text_expression(selector: str) -> str:
    return _selector_expression(
        selector,
        """
  const text = element.innerText ?? element.textContent ?? "";
  return { selector, found: true, text };
""".rstrip(),
    )


def _exists_expression(selector: str) -> str:
    selector_source = _js_literal(selector)
    return f"""
() => {{
  const selector = {selector_source};
  return {{ selector, exists: Boolean(document.querySelector(selector)) }};
}}
""".strip()


def _count_expression(*, selector: str, include_hidden: bool) -> str:
    return f"""
() => {{
{_dom_helpers_expression(include_hidden=include_hidden)}
  const selector = {_js_literal(selector)};
  const all = [...document.querySelectorAll(selector)];
  const visibleNodes = all.filter(visible);
  const matched = includeHidden ? all : visibleNodes;
  return {{
    selector,
    include_hidden: includeHidden,
    count: matched.length,
    total_count: all.length,
    visible_count: visibleNodes.length
  }};
}}
""".strip()


def _scroll_expression(
    *,
    selector: str | None,
    x: float,
    y: float,
    behavior: str,
) -> str:
    x_source = _js_literal(x)
    y_source = _js_literal(y)
    behavior_source = _js_literal(behavior)
    if selector:
        return _selector_expression(
            selector,
            f"""
  element.scrollBy({{ left: {x_source}, top: {y_source}, behavior: {behavior_source} }});
  return {{ selector, found: true, scrolled: true, x: {x_source}, y: {y_source} }};
""".rstrip(),
        )
    return f"""
() => {{
  window.scrollBy({{ left: {x_source}, top: {y_source}, behavior: {behavior_source} }});
  return {{
    selector: null,
    found: true,
    scrolled: true,
    x: {x_source},
    y: {y_source},
    scroll_x: window.scrollX,
    scroll_y: window.scrollY
  }};
}}
""".strip()


def _select_option_expression(*, selector: str, value: str) -> str:
    value_source = _js_literal(value)
    return _event_expression(
        selector,
        f"""
  const requestedValue = {value_source};
  const previousValue = element.value;
  element.value = requestedValue;
  dispatch(new Event("input", {{ bubbles: true }}));
  dispatch(new Event("change", {{ bubbles: true }}));
  return {{
    selector,
    found: true,
    selected: element.value === requestedValue,
    value: element.value,
    requested_value: requestedValue,
    previous_value: previousValue
  }};
""".rstrip(),
    )


def _checkbox_action_expression(*, selector: str, checked: bool) -> str:
    checked_source = _js_literal(checked)
    return _event_expression(
        selector,
        f"""
  if (!("checked" in element)) {{
    return {{
      selector,
      found: true,
      checkable: false,
      checked: Boolean(element.checked)
    }};
  }}
  element.checked = {checked_source};
  dispatch(new Event("input", {{ bubbles: true }}));
  dispatch(new Event("change", {{ bubbles: true }}));
  return {{
    selector,
    found: true,
    checkable: true,
    checked: Boolean(element.checked)
  }};
""".rstrip(),
    )


def _hover_expression(selector: str) -> str:
    return _event_expression(
        selector,
        """
  const init = {
    view: window,
    bubbles: true,
    cancelable: true,
    clientX: element.getBoundingClientRect().left,
    clientY: element.getBoundingClientRect().top
  };
  for (const type of ["mouseover", "mouseenter", "mousemove"]) {
    dispatch(new MouseEvent(type, init));
  }
  return { selector, found: true, hovered: true };
""".rstrip(),
    )


def _hover_role_expression(
    *,
    role: str,
    name: str | None,
    exact: bool,
    case_sensitive: bool,
) -> str:
    name_source = "null" if name is None else _js_literal(name)
    return f"""
() => {{
{_dom_helpers_expression()}
  const requestedRole = {_js_literal(role)};
  const requestedName = {name_source};
  const exact = {_js_literal(exact)};
  const caseSensitive = {_js_literal(case_sensitive)};
{_role_target_helpers_expression("interactiveSelector")}
  const roleMatch = findRoleTargetElement();
  const element = roleMatch.element;
  if (!element) {{
    return {{
      role: requestedRole,
      name: requestedName,
      found: false,
      role_found: false,
      hovered: false,
      candidate_count: roleMatch.candidate_count,
      candidates: roleMatch.candidates
    }};
  }}
  const init = {{
    view: window,
    bubbles: true,
    cancelable: true,
    clientX: element.getBoundingClientRect().left,
    clientY: element.getBoundingClientRect().top
  }};
  for (const type of ["mouseover", "mouseenter", "mousemove"]) {{
    element.dispatchEvent(new MouseEvent(type, init));
  }}
  return {{
    role: requestedRole,
    name: requestedName,
    found: true,
    role_found: true,
    hovered: true,
    candidate_count: roleMatch.candidate_count,
    element: nodeInfo(element)
  }};
}}
""".strip()


def _press_expression(*, selector: str, key: str) -> str:
    key_source = _js_literal(key)
    return _event_expression(
        selector,
        f"""
  const key = {key_source};
  element.focus();
  const init = {{ key, code: key, bubbles: true, cancelable: true }};
  const keydownAccepted = dispatch(new KeyboardEvent("keydown", init));
  dispatch(new KeyboardEvent("keypress", init));
  dispatch(new KeyboardEvent("keyup", init));
  return {{
    selector,
    found: true,
    focused: document.activeElement === element,
    key,
    pressed: true,
    keydown_accepted: keydownAccepted
  }};
""".rstrip(),
    )


def _press_role_expression(
    *,
    role: str,
    name: str | None,
    key: str,
    exact: bool,
    case_sensitive: bool,
) -> str:
    key_source = _js_literal(key)
    name_source = "null" if name is None else _js_literal(name)
    return f"""
() => {{
{_dom_helpers_expression()}
  const requestedRole = {_js_literal(role)};
  const requestedName = {name_source};
  const exact = {_js_literal(exact)};
  const caseSensitive = {_js_literal(case_sensitive)};
{_role_target_helpers_expression("interactiveSelector")}
  const roleMatch = findRoleTargetElement();
  const element = roleMatch.element;
  if (!element) {{
    return {{
      role: requestedRole,
      name: requestedName,
      found: false,
      role_found: false,
      focused: false,
      key: {key_source},
      pressed: false,
      keydown_accepted: false,
      candidate_count: roleMatch.candidate_count,
      candidates: roleMatch.candidates
    }};
  }}
  const key = {key_source};
  element.focus();
  const init = {{ key, code: key, bubbles: true, cancelable: true }};
  const keydownAccepted = element.dispatchEvent(new KeyboardEvent("keydown", init));
  element.dispatchEvent(new KeyboardEvent("keypress", init));
  element.dispatchEvent(new KeyboardEvent("keyup", init));
  return {{
    role: requestedRole,
    name: requestedName,
    found: true,
    role_found: true,
    focused: document.activeElement === element,
    key,
    pressed: true,
    keydown_accepted: keydownAccepted,
    candidate_count: roleMatch.candidate_count,
    element: nodeInfo(element)
  }};
}}
""".strip()


def _dom_helpers_expression(
    *,
    include_hidden: bool = False,
    max_nodes: int | None = None,
) -> str:
    max_nodes_source = "null" if max_nodes is None else _js_literal(max_nodes)
    return f"""
  const includeHidden = {_js_literal(include_hidden)};
  const maxNodes = {max_nodes_source};
  const sensitiveNamePattern =
    /api[-_]?key|apikey|authorization|bearer|credential|password|passwd|secret|token/i;
  const interactiveSelector = [
    "a[href]",
    "button",
    "input:not([type=hidden])",
    "select",
    "textarea",
    "summary",
    "[role]",
    "[onclick]",
    "[tabindex]:not([tabindex='-1'])",
    "[contenteditable='true']"
  ].join(",");

  const normalize = (value) => String(value ?? "").replace(/\\s+/g, " ").trim();
  const sensitiveText = (value) => sensitiveNamePattern.test(String(value ?? ""));
  const sensitiveElement = (element) => {{
    const tag = element.tagName.toLowerCase();
    const type = String(element.getAttribute("type") || "").toLowerCase();
    if (tag === "input" && ["password", "hidden", "file"].includes(type)) {{
      return true;
    }}
    return [
      "name",
      "id",
      "autocomplete",
      "aria-label",
      "placeholder",
      "title",
      "data-testid",
      "data-test",
      "data-cy"
    ].some((attribute) => sensitiveNamePattern.test(element.getAttribute(attribute) || ""));
  }};
  const shouldMaskValue = (element, value) =>
    sensitiveElement(element) && String(value ?? "") !== "";
  const maskValue = (element, value) => shouldMaskValue(element, value) ? "***" : value;
  const visible = (element) => {{
    if (includeHidden) return true;
    const style = window.getComputedStyle(element);
    if (
      style.display === "none" ||
      style.visibility === "hidden" ||
      style.opacity === "0"
    ) {{
      return false;
    }}
    return Boolean(
      element.offsetWidth ||
      element.offsetHeight ||
      element.getClientRects().length
    );
  }};
  const rawTextOf = (element) => normalize(element.innerText ?? element.textContent ?? "");
  const textOf = (element) => maskValue(element, rawTextOf(element));
  const valueNameOf = (element) => {{
    if (!("value" in element)) return "";
    return normalize(maskValue(element, element.value));
  }};
  const nameFromLabelledBy = (element) => {{
    const labelledBy = element.getAttribute("aria-labelledby");
    if (!labelledBy) return "";
    return normalize(
      labelledBy
        .split(/\\s+/)
        .map((id) => document.getElementById(id)?.innerText ?? "")
        .join(" ")
    );
  }};
  const nameFromLabels = (element) => {{
    const explicitLabels = "labels" in element && element.labels
      ? [...element.labels]
      : [];
    if (explicitLabels.length) {{
      return normalize(explicitLabels.map((label) => rawTextOf(label)).join(" "));
    }}
    const id = element.id;
    if (!id) return "";
    return normalize(
      [...document.querySelectorAll(`label[for="${{CSS.escape(id)}}"]`)]
        .map((label) => rawTextOf(label))
        .join(" ")
    );
  }};
  const accessibleName = (element) => normalize(
    element.getAttribute("aria-label") ||
    nameFromLabelledBy(element) ||
    nameFromLabels(element) ||
    element.getAttribute("alt") ||
    element.getAttribute("title") ||
    element.getAttribute("placeholder") ||
    valueNameOf(element) ||
    textOf(element)
  );
  const roleOf = (element) => {{
    const explicitRole = normalize(element.getAttribute("role")).split(" ")[0];
    if (explicitRole) return explicitRole;
    const tag = element.tagName.toLowerCase();
    const type = String(element.getAttribute("type") || "").toLowerCase();
    if (tag === "a" && element.hasAttribute("href")) return "link";
    if (tag === "button") return "button";
    if (tag === "select") return "combobox";
    if (tag === "textarea") return "textbox";
    if (tag === "img") return "img";
    if (tag === "ul" || tag === "ol") return "list";
    if (tag === "li") return "listitem";
    if (tag === "summary") return "button";
    if (tag === "input") {{
      if (["button", "submit", "reset"].includes(type)) return "button";
      if (type === "checkbox") return "checkbox";
      if (type === "radio") return "radio";
      if (type === "range") return "slider";
      if (["email", "password", "search", "tel", "text", "url", ""].includes(type)) {{
        return "textbox";
      }}
      return type || "input";
    }}
    if (/^h[1-6]$/.test(tag)) return "heading";
    return "";
  }};
  const cssPath = (element) => {{
    if (element.id) return `#${{CSS.escape(element.id)}}`;
    const parts = [];
    let current = element;
    while (current && current.nodeType === Node.ELEMENT_NODE && parts.length < 4) {{
      let part = current.tagName.toLowerCase();
      if (current.classList.length) {{
        part += "." + [...current.classList].slice(0, 2).map(CSS.escape).join(".");
      }}
      const parent = current.parentElement;
      if (parent) {{
        const siblings = [...parent.children].filter((child) => child.tagName === current.tagName);
        if (siblings.length > 1) {{
          part += `:nth-of-type(${{siblings.indexOf(current) + 1}})`;
        }}
      }}
      parts.unshift(part);
      current = parent;
    }}
    return parts.join(" > ");
  }};
  const nodeInfo = (element) => ({{
    selector: cssPath(element),
    tag: element.tagName.toLowerCase(),
    role: roleOf(element) || null,
    name: accessibleName(element),
    text: textOf(element),
    visible: visible(element)
  }});
  const matchesText = (candidate, query, exact, caseSensitive) => {{
    let haystack = normalize(candidate);
    let needle = normalize(query);
    if (!caseSensitive) {{
      haystack = haystack.toLowerCase();
      needle = needle.toLowerCase();
    }}
    return exact ? haystack === needle : haystack.includes(needle);
  }};
  const limited = (nodes) => maxNodes === null ? nodes : nodes.slice(0, maxNodes);
""".rstrip()


def _label_control_helpers_expression() -> str:
    return """
  const findFieldByLabel = (requestedLabel, exact, caseSensitive, fieldSelector) => {
    const labelElements = [...document.querySelectorAll("label")].filter(visible);
    for (const labelElement of labelElements) {
      if (!matchesText(textOf(labelElement), requestedLabel, exact, caseSensitive)) {
        continue;
      }
      let element = null;
      if (labelElement.htmlFor) {
        element = document.getElementById(labelElement.htmlFor);
      }
      element ||= labelElement.querySelector(fieldSelector);
      if (element) {
        return { element, label_element: nodeInfo(labelElement) };
      }
    }
    const element = [...document.querySelectorAll(fieldSelector)]
      .filter(visible)
      .find((candidate) =>
        matchesText(accessibleName(candidate), requestedLabel, exact, caseSensitive)
      );
    return { element: element || null, label_element: null };
  };
""".rstrip()


def _click_text_expression(
    *,
    text: str,
    selector: str | None,
    exact: bool,
    case_sensitive: bool,
) -> str:
    selector_source = (
        "interactiveSelector" if selector is None else _js_literal(selector)
    )
    return f"""
() => {{
{_dom_helpers_expression()}
  const requestedText = {_js_literal(text)};
  const selector = {selector_source};
  const candidates = [...document.querySelectorAll(selector)].filter(visible);
  const element = candidates.find((candidate) =>
    matchesText(accessibleName(candidate), requestedText, {_js_literal(exact)}, {_js_literal(case_sensitive)})
  );
  if (!element) {{
    return {{
      found: false,
      clicked: false,
      text: requestedText,
      selector,
      candidate_count: candidates.length,
      candidates: candidates.slice(0, 20).map(nodeInfo)
    }};
  }}
  element.focus?.();
  element.click();
  return {{
    found: true,
    clicked: true,
    text: requestedText,
    selector,
    element: nodeInfo(element)
  }};
}}
""".strip()


